
import React, { Component } from "react";
import NotificationSystem from "react-notification-system";
import axios from 'axios';

import { style } from "../variables/Variables.jsx";
import Logo from '../assets/img/Black-Forest-Logo.png';
import '../assets/css/custom.css';
import {validateForm, validEmailRegex, logout} from '../configs/helpers';
import { apiUrls} from '../configs/configs';

class Login extends Component {
  
  constructor(props){
    super(props);
    logout();

    this.state = {
      _notificationSystem: null,
      email: null,
      password: null,
      errors: {
        email: 'Email is required',
        password: 'Password is required'
      }
    }
  }

  handleChange = (event) => {
    event.preventDefault();
    const { name, value } = event.target;
    let errors = this.state.errors;

    switch (name) {
      case 'email': 
        errors.email = 
          validEmailRegex.test(value)
            ? ''
            : 'Email is not valid!';
        break;
      case 'password': 
        errors.password = 
          value.length < 5
            ? 'Password must be 5 characters long!'
            : '';
        break;
      default:
        break;
    }

    this.setState({errors, [name]: value});
  }

  handleSubmit = (event) => {
    this.setState({ _notificationSystem: this.refs.notificationSystem, isFormSubmit: true });
    var _notificationSystem = this.refs.notificationSystem;
    event.preventDefault();

    if(validateForm(this.state.errors)) {
      axios({
        method: 'POST',
        url: apiUrls.login,
        data: {
          email: this.state.email,
          password: this.state.password
        },
        headers: {'Content-Type': 'application/json'}
      }).then(result => {
        if (result.status === 200) {
          var userData = result.data.data;
          localStorage.setItem('user', JSON.stringify(userData));
          this.props.history.push('/admin/user');
        }
      }).catch(e => {
        console.log(e)
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
            message: (
              <div>
               {(e.response) ? e.response.data.message : 'Something went wrong!'}
              </div>
            ),
            level: 'error',
            position: "tr",
            autoDismiss: 15
          });
      });
    }else{
      _notificationSystem.addNotification({
      title: <span data-notify="icon" className="pe-7s-close-circle" />,
        message: (
          <div>
            Sorry Required Valid Input
          </div>
        ),
        level: 'error',
        position: "tr",
        autoDismiss: 15
      });
    }
  }

  render() {
    const { errors, isFormSubmit } = this.state;
    return (
      <div className="container login-wrap">
        <NotificationSystem ref="notificationSystem" style={style} />
        <div className="form-wrap">
        <img src={Logo} className="logo-login img-responsive" alt="logo"/>

          <form onSubmit={this.handleSubmit} noValidate>
            <h3 className="text-center">Sign In</h3>

            <div className="form-group">
                <label>Email address</label>
                <input type="email" className="form-control" name="email" placeholder="Enter email" onChange={this.handleChange} noValidate />
                {
                  isFormSubmit && (
                    <p className="txt-error">{errors.email}</p> 
                  )
                }
                </div>

            <div className="form-group">
                <label>Password</label>
                <input type="password" className="form-control" name="password" placeholder="Enter password" onChange={this.handleChange} noValidate />
                {
                  isFormSubmit && (
                    <p className="txt-error">{errors.password}</p>
                  )
                }
            </div>
            <div className="text-center">
              <button type="submit" className="btn-login btn btn-primary">Login</button>

            </div>
          </form>
        </div>
      </div>
       
    );
  }
}

export default Login;