import React, { Component } from "react";
import {
  Grid,
  Row,
  Col
} from "react-bootstrap";
import NotificationSystem from "react-notification-system";
import axios from 'axios';

import { style } from "../variables/Variables.jsx";
import { Card } from "components/Card/Card.jsx";
import { UserCard } from "components/UserCard/UserCard.jsx";
import Button from "components/CustomButton/CustomButton.jsx";

import avatar from "assets/img/faces/face-0.jpg";
import bgAdmin from "assets/img/adminbg.jpg";
import {validateForm, authHeader } from '../configs/helpers';
import { apiUrls} from '../configs/configs';
class UserProfile extends Component {

  constructor(props){
    super(props);

    this.state = {
      _notificationSystem: null,
      newpassword: null,
      oldpassword: null,
      isFormSubmit: false,
      confirmpassword: null,
      errors: {
        newpassword: 'New password field is required',
        oldpassword: 'Old password field is required',
        confirmpassword: 'Confirm password is required',

      }
    }
  }


  handleChange = (event) => {
    event.preventDefault();
    const { name, value } = event.target;
    let errors = this.state.errors;

    switch (name) {
      case 'newpassword': 
        errors.newpassword = 
          value.length < 5
            ? 'New password must be 5 characters long!'
            : '';
        break;
        case 'oldpassword': 
          errors.oldpassword = 
            value.length < 5
              ? 'Old password must be 5 characters long!'
              : '';
          break;

          case 'confirmpassword': 
          errors.confirmpassword = 
            value.length < 5
              ? 'Confirm password must be 5 characters long!'
              : '';
            break;
      default:
        break;
    }

    this.setState({errors, [name]: value});
  }


  handleSubmit = (event) => {
    this.setState({ _notificationSystem: this.refs.notificationSystem, isFormSubmit: true });
    var _notificationSystem = this.refs.notificationSystem;
    event.preventDefault();

    if(validateForm(this.state.errors)) {

      if(this.state.newpassword === this.state.confirmpassword){
        axios({
          method: 'POST',
          url: apiUrls.changePassword,
          data: {
            oldpassword: this.state.oldpassword,
            newpassword: this.state.newpassword
          },
          headers: {
            'Content-Type': 'application/json',
            Authorization: authHeader()
          }
        }).then(result => {
          if (result.status === 200) {
            
          _notificationSystem.addNotification({
            title: <span data-notify="icon" className="pe-7s-check" />,
              message: (
                <div>
                  'Password changed.'
                </div>
              ),
              level: 'success',
              position: "tr",
              autoDismiss: 15
            });
          }
        }).catch(e => {
          console.log(e)
          _notificationSystem.addNotification({
            title: <span data-notify="icon" className="pe-7s-close-circle" />,
              message: (
                <div>
                {(e.response) ? e.response.data.message : 'Something went wrong!'}
                </div>
              ),
              level: 'error',
              position: "tr",
              autoDismiss: 15
            });
        });
      } else{
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
            message: (
              <div>
                New password and confirm password not matched. Please try again.
              </div>
            ),
            level: 'error',
            position: "tr",
            autoDismiss: 15
          });
      }
    }
  }
  render() {
    const { errors, isFormSubmit } = this.state;

    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />

        <Grid fluid>
          <Row>
          <Col md={4}>
              <UserCard
                bgImage={bgAdmin}
                avatar={avatar}
                name="Admin"
                description={
                  <span>Black Forest Cakes
                  </span>
                }
              />
            </Col>
            <Col md={8}>
              <Card
                title="Change Password"
                content={
                  <form onSubmit={this.handleSubmit} noValidate>
                    <div className="form-group">
                <label>Old Password</label>
                <input type="password" className="form-control" name="oldpassword" placeholder="Enter old password" onChange={this.handleChange} noValidate />
                {
                  isFormSubmit && (
                    <p className="txt-error">{errors.oldpassword}</p> 
                  )
                }
                </div>

            <div className="form-group">
                <label>New Password</label>
                <input type="password" className="form-control" name="newpassword" placeholder="Enter new password" onChange={this.handleChange} noValidate />
                {
                  isFormSubmit && (
                    <p className="txt-error">{errors.newpassword}</p>
                  )
                }
            </div>

            <div className="form-group">
                <label>Confirm New Password</label>
                <input type="password" className="form-control" name="confirmpassword" placeholder="Enter confirm password" onChange={this.handleChange} noValidate />
                {
                  isFormSubmit && (
                    <p className="txt-error">{errors.confirmpassword}</p>
                  )
                }
            </div>

                    <Button bsStyle="info" pullRight  type="submit">
                      Change
                    </Button>
                    <div className="clearfix" />
                  </form>
                }
              />
            </Col>
           
          </Row>
        </Grid>
      </div>
    );
  }
}

export default UserProfile;
