
import React, { Component } from "react";
import { Grid, Row, Col } from "react-bootstrap";
import axios from 'axios';
import NotificationSystem from "react-notification-system";
import ImageCompressor from 'image-compressor.js';

import { style } from "../../variables/Variables.jsx";
import Card from "components/Card/Card.jsx";
import Button from "components/CustomButton/CustomButton.jsx";
import '../../assets/css/custom.css';
import { ApiUrlHost, apiUrls} from '../../configs/configs';
import { validateForm,authHeader, fileMaxLimit } from '../../configs/helpers';

class ProductGallery extends Component {
  constructor(props){
    super(props);
    this.state = {
        pId: this.props.match.params.id,
        images: [],
        image:null,
        tempImg: '',
        errors:{
            image:''
        }
    };
   
  }

  componentWillMount(){
    this.getProductData();
  }


  fileChangedHandler = (event) => {
    let errors = this.state.errors;
    let curr = this;
    this.setState({
      tempImg: ''
    })

    if(event.target.files[0]){
      if(fileMaxLimit(event)){
        errors.image = '';
        this.setState({
          tempImg: URL.createObjectURL(event.target.files[0])
        })
        new ImageCompressor(event.target.files[0], {
          quality: 0.6,
          success(result) {
            var file = new File([result], result.name, {type: result.type});
            curr.setState({image: file, errors});
          },
          error(e) {
            console.log(e.message);
          },
        });
      } else{
        errors.image = 'File size should be maximum 5MB';
        this.setState({errors});
      }
    }else{
      errors.image = '';
      this.setState({image: '', errors});
    }
  };


  getProductData(){
    axios({
      method: 'GET',
      url: apiUrls.PRODUCT.create + '/' + this.state.pId,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        var pData = result.data.data;
        if(pData.image && pData.image.length > 0){
           this.setState({
            images: pData.image
           })
        }else{
            this.setState({
                images: []
            }) 
        }
      }
    }).catch(e => {
      console.log(e);
    });
  }

  
  handleSubmit = (event) => {
    this.setState({ _notificationSystem: this.refs.notificationSystem, isFormSubmit: true });
    var _notificationSystem = this.refs.notificationSystem;
    event.preventDefault();

    if(validateForm(this.state.errors)) {
      var bodyFormData = new FormData();
      bodyFormData.append('image', this.state.image)

      axios({
        method: 'POST',
        url: apiUrls.PRODUCT.updateImage + this.state.pId,
        data: bodyFormData,
        headers: {
          'Content-Type': 'multipart/form-data',
          Authorization: authHeader()
        }
      }).then(result => {
        if (result.status === 200) {
            this.getProductData();
            this.setState({
              tempImg: ''
            })

        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-check" />,
            message: (
              <div>
                'Image uploaded.'
              </div>
            ),
            level: 'success',
            position: "tr",
            autoDismiss: 15
          });

        }
      }).catch(e => {
        console.log(e)
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
            message: (
              <div>
              {(e.response) ? e.response.data.message : 'Something went wrong!'}
              </div>
            ),
            level: 'error',
            position: "tr",
            autoDismiss: 15
          });
      });
    }
  }

  deleteImageById(image){
      console.log(image);
      var _notificationSystem;

    this.setState({ _notificationSystem: this.refs.notificationSystem }, () => {
       _notificationSystem = this.refs.notificationSystem;
    });

    axios({
      method: 'DELETE',
      url: apiUrls.PRODUCT.updateImage  + this.state.pId,
      data: {
        name: image
      },
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        this.getProductData();

        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-check" />,
            message: (
              <div>
                Product image deleted!.
              </div>
            ),
            level: 'success',
            position: "tr",
            autoDismiss: 15
          });
      }
    }).catch(e => {
      _notificationSystem.addNotification({
        title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
            {(e.response) ? e.response.data.message : 'Something went wrong!'}
            </div>
          ),
          level: 'error',
          position: "tr",
          autoDismiss: 15
        });
    });
  }

  render() {
    const { errors, isFormSubmit } = this.state;

    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />
        <Grid fluid>
          <Row>
          <Col md={4}>
            <Card
                title="Add to gallery"
                content={
                  <form onSubmit={this.handleSubmit} noValidate>
                    
                    <div className="form-group">
                      {
                        this.state.tempImg && (
                          <img src={this.state.tempImg} height="200" width="200" className="mb-btm" alt = "temp"/>

                        )
                      }
                      <input type="file" className="form-control" name="name" noValidate onChange={this.fileChangedHandler} />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.name}</p>
                        )
                      }
                    </div>
                    <Button bsStyle="info"  type="submit">
                      Add to gallery
                    </Button>

                    <div className="clearfix" />
                  </form>
                }
              />
            </Col>
            {
                this.state.images.length > 0 && (
                    <Col md={8}>
                    <Card
                        title="Product Images"
                        content={
                            <Row className="gallery-scroll">
                                {
                                    this.state.images.map((item, key) => {
                                        return (
                                            
                                            <Col xs={6} md={4} className="mb-btm" key={key}>
                                                <div className="card card-user">
                                                    <img src={ApiUrlHost + '/' + item} height="200" width="100%" alt="product" />
                                                    <button className="btn btn-default del-btn" onClick={() => this.deleteImageById(item)}>         
                                                        <i className="pe-7s-trash" />
                                                    </button>
                                                </div>
                                            </Col>
                                        )
                                    })
                                }
                            </Row>
                        }
                    />
                    </Col>
                )
            }
            

          </Row>
        </Grid>
      </div>
    );
  }
}

export default ProductGallery;
