import React, { Component } from "react";
import { FormGroup, Row, Col } from "react-bootstrap";
import { Multiselect } from "multiselect-react-dropdown";
import axios from "axios";
import { apiUrls } from "../../../configs/configs";
import { authHeader } from "../../../configs/helpers";
import InfiniteScroll from "react-infinite-scroll-component";
import * as moment from "moment";
import "./style.css";
const now = 10;

class ChefOrderReport extends Component {
  constructor(props) {
    super(props);
    this.state = {
      products: [],
      categories: [],
      waiterMan: [],
      selectedCategories: [],
      selectedProducts: [],
      waiterId: "",
      fromDate: null,
      toDate: null,
      totalAmt: 0,
      totalQty: 0,
      reports: [],
      chefId: null,
      page: 0,
      chefOrders: [],
      chefName: "",
    };
  }

  componentWillMount() {
    this.getAllWaiters();
    this.getAllProductCategories();
    this.getReportData();
  }

  getAllProductCategories() {
    axios({
      method: "GET",
      url: apiUrls.PRODUCT.getAllCategory,
      headers: {
        Authorization: authHeader(),
      },
    })
      .then((result) => {
        if (result.status === 200) {
          this.setState({
            categories: result.data.data,
          });
        } else {
          this.setState({
            categories: [],
          });
        }
      })
      .catch((e) => {
        this.setState({
          categories: [],
        });
      });
  }

  getAllWaiters() {
    axios({
      method: "GET",
      url: apiUrls.ORDERS.getChefs,
      headers: {
        Authorization: authHeader(),
      },
    })
      .then((result) => {
        if (result.status === 200) {
          this.setState({
            waiterMan: result.data.data,
          });
        } else {
          this.setState({
            waiterMan: [],
          });
        }
      })
      .catch((e) => {
        this.setState({
          waiterMan: [],
        });
      });
  }

  getAllProductsByCategory(category) {
    if (category && category.length > 0) {
      this.setState({
        selectedCategories: category,
        currentPage: 0,
      });
      axios({
        method: "GET",
        url: apiUrls.PRODUCT.getAllProductByCategory,
        headers: {
          Authorization: authHeader(),
        },
        params: { categories: category },
      })
        .then((result) => {
          if (result.status === 200) {
            this.setState({
              products: result.data.data,
            });
          } else {
            this.setState({
              products: [],
            });
          }
        })
        .catch((e) => {
          this.setState({
            products: [],
          });
        });
    } else {
      this.setState({
        products: [],
        selectedCategories: [],
      });
    }
  }

  categorySelection(selectedList) {
    const tempSelected = [];
    selectedList.forEach((item) => {
      tempSelected.push(item._id);
    });
    this.getAllProductsByCategory(tempSelected);
  }

  productSelections(selectedList) {
    const tempSelected = [];
    selectedList.forEach((item) => {
      tempSelected.push(item._id);
    });

    this.setState({
      selectedProducts: tempSelected,
    });
  }

  getReportData() {
    this.setState({
      chefId: "",
      chefOrders: [],
      page: 0,
      chefName: "",
    });

    const body = {
      selectedCategories: this.state.selectedCategories,
      selectedProducts: this.state.selectedProducts,
      chefId: this.state.waiterId,
      fromDate: this.state.fromDate,
      toDate: this.state.toDate,
    };

    axios({
      method: "POST",
      url: apiUrls.ORDERS.getChefReportsData,
      data: body,
      headers: {
        Authorization: authHeader(),
      },
    })
      .then((result) => {
        const { data } = result;
        if (data.data && data.data.length > 0) {
          let totalOrder = 0;
          let totalAmt = 0;
          const temp = data.data.map((item) => {
            const amt = parseFloat(item.totalAmount.$numberDecimal);
            totalAmt += amt;
            totalOrder += item.count;
            item.totalAmount = amt.toFixed(2);
            return item;
          });

          this.setState({
            reports: temp,
            totalAmt: totalAmt.toFixed(2),
            totalQty: totalOrder,
          });
        } else {
          this.setState({
            reports: [],
            totalAmt: 0,
            totalQty: 0,
          });
        }
      })
      .catch((e) => {
        console.log(e);
      });
  }

  loadChefOrders(chef, name) {
    this.setState(
      {
        chefId: chef,
        chefOrders: [],
        page: 0,
        chefName: name,
      },
      () => {
        this.getChefOrders();
      }
    );
  }

  fetchMoreData = () => {
    this.setState(
      {
        page: this.state.page + 1,
      },
      () => {
        this.getChefOrders();
      }
    );
  };

  getChefOrders() {
    const params = {
      selectedCategories: this.state.selectedCategories,
      selectedProducts: this.state.selectedProducts,
      fromDate: this.state.fromDate,
      toDate: this.state.toDate,
      page: this.state.page,
    };

    axios({
      method: "GET",
      url: apiUrls.ORDERS.listChefOrders + this.state.chefId,
      params,
      headers: {
        Authorization: authHeader(),
      },
    })
      .then((result) => {
        let temp = this.state.chefOrders;
        temp = temp.concat(result.data.data[0].paginatedResults);

        this.setState({
          chefOrders: temp,
        });
      })
      .catch((e) => {
        console.log(e);
      });
  }

  render() {
    return (
      <div className="box report-box">
        <div className="header">
          <div className="container2" id="container2">
            <div className="row-container row-center-items">
              <div className="element-wraps">
                <label>Chef</label>
                <select
                  className="in-select width18"
                  onChange={(e) => this.setState({ waiterId: e.target.value })}
                >
                  <option value="">Choose</option>
                  {this.state.waiterMan.map((store) => {
                    return (
                      <option value={store._id} key={`waiter-${store._id}`}>
                        {store.firstname}
                      </option>
                    );
                  })}
                </select>
              </div>

              <div className="element-wraps">
                <label>From</label>
                <input
                  placeholder="from"
                  className="in-date width18"
                  type="date"
                  onChange={(e) => this.setState({ fromDate: e.target.value })}
                />
              </div>
              <div className="element-wraps">
                <label>To</label>
                <input
                  id="input-date"
                  className="in-date width18"
                  type="date"
                  onChange={(e) => this.setState({ toDate: e.target.value })}
                />
              </div>
            </div>

            <Row>
              <Col md={4}>
                <div className="element-wraps">
                  <label>Category </label>
                  <FormGroup>
                    <Multiselect
                      options={this.state.categories} // Options to display in the dropdown
                      onSelect={this.categorySelection.bind(this)} // Function will trigger on select event
                      onRemove={this.categorySelection.bind(this)} // Function will trigger on remove event
                      displayValue="name"
                    />
                  </FormGroup>
                </div>
              </Col>
              <Col md={6}>
                <div className="element-wraps">
                  <FormGroup>
                    <label>Products </label>
                    <Multiselect
                      options={this.state.products} // Options to display in the dropdown
                      onSelect={this.productSelections.bind(this)} // Function will trigger on select event
                      onRemove={this.productSelections.bind(this)} // Function will trigger on remove event
                      displayValue="name" // Property name to display in the dropdown options
                    />
                  </FormGroup>
                </div>
              </Col>
              <Col md={2}>
                <button
                  className="apply-filter-btn"
                  onClick={() => this.getReportData()}
                >
                  Apply Filter
                </button>
              </Col>
            </Row>
          </div>
        </div>
        <div>
          <div className="inv" id="print-form-2">
            <p className="centered">
              <span className="title-head">Chef Reports </span>

              <br />
            </p>

            <div className="scroll-wrap">
              <table
                className="print-table"
                style={{
                  borderCollapse: "collapse",
                  textAlign: "left",
                  width: "100%",
                }}
              >
                <thead>
                  <tr style={{ borderCollapse: "collapse", textAlign: "left" }}>
                    <th
                      style={{
                        borderTop: "1px dashed black",
                        borderBottom: "1px dashed black",
                        padding: "4px 0",
                        minWidth: 50,
                      }}
                      className="serial"
                    >
                      S.No
                    </th>
                    <th
                      className="description th-desc"
                      style={{ minWidth: 150 }}
                    >
                      Name
                    </th>
                    <th
                      className="quantity th-qty"
                      style={{ minWidth: "5rem", textAlign: "center" }}
                    >
                      Total Orders
                    </th>
                    <th
                      className="thprice"
                      style={{ minWidth: "10rem", textAlign: "center" }}
                    >
                      Amount
                    </th>
                  </tr>
                </thead>
                <tbody className="print-moda-row print-moda-row-report">
                  {this.state.reports.map((item, key) => {
                    return (
                      <tr key={`stk-rep-d-${key}`}>
                        <td style={{ minWidth: 50 }}>{key + 1}</td>
                        <td
                          style={{
                            minWidth: 150,
                            cursor: "pointer",
                            color: "blue",
                          }}
                          onClick={() =>
                            this.loadChefOrders(
                              item._id,
                              item.employeeDetails &&
                                item.employeeDetails.length > 0
                                ? item.employeeDetails[0].firstname
                                : "Anonymous"
                            )
                          }
                        >
                          {item.employeeDetails &&
                          item.employeeDetails.length > 0
                            ? item.employeeDetails[0].firstname
                            : "Anonymous"}{" "}
                          <i className="fa fa-eye"></i>
                        </td>
                        <td style={{ minWidth: "5rem", textAlign: "center" }}>
                          {item.count}
                        </td>
                        <td style={{ minWidth: "10rem", textAlign: "center" }}>
                          ₹ {item.totalAmount}
                        </td>
                      </tr>
                    );
                  })}

                  <tr style={{ borderTop: "none" }}>
                    <td>Total</td>
                    <td></td>
                    <td style={{ minWidth: "5rem", textAlign: "center" }}>
                      {this.state.totalQty}
                    </td>
                    <td style={{ minWidth: "10rem", textAlign: "center" }}>
                      ₹ {this.state.totalAmt}
                    </td>
                  </tr>
                </tbody>
              </table>
            </div>

            {this.state.chefOrders.length > 0 && (
              <div className="order-detail-wrapper">
                <h3>Order details of {this.state.chefName}</h3>
                <InfiniteScroll
                  dataLength={this.state.chefOrders.length}
                  hasMore={true}
                  // loader={<h4>Loading...</h4>}
                  next={this.fetchMoreData}
                >
                  {this.state.chefOrders.map((item, key) => {
                    return (
                      <div className="list-item" key={`chef-order-row-${key}`}>
                        <Row>
                          <Col md={6}>
                            <p>Order Id: #{item.form_no}</p>
                            <p>
                              {" "}
                              {item.productDetails && item.productDetails[0]
                                ? item.productDetails[0].name
                                : item.pastryDetails && item.pastryDetails[0]
                                ? item.pastryDetails[0].name
                                : "Whats app modal"}{" "}
                            </p>
                            <p>
                              Delivery:{" "}
                              {moment(item.delivery_date).format("DD/MM/YYYY")}{" "}
                              @ {moment(item.delivery_time).format("hh:mm:a")}
                            </p>
                          </Col>
                          <Col md={6}>
                            <p>
                              Order Date:{" "}
                              {moment(item.created_at).format("DD/MM/YYYY")} @{" "}
                              {moment(item.created_at).format("hh:mm:a")}
                            </p>
                            <p>Customer name: {item.customer_name}</p>
                            <p>Customer number: {item.customer_phone}</p>
                          </Col>
                        </Row>

                        <hr style={{ marginTop: 0 }} />

                        {item.timelines.length > 0 && (
                          <Row>
                            <Col md={12}>
                              <div class="timelines">
                                <h2>Order Timelines</h2>
                              </div>
                              <div class="all-timelines">
                                {item.timelines.map((d, k) => {
                                  return (
                                    <div class="single-timeline d-flex-2">
                                      <div class="timeline-blank"></div>
                                      <div class="timeline-text d-flex-2">
                                        <span>
                                          <h6>{d.statusText}</h6> — {`${moment(d.created_at).format("DD/MM/YYYY")} - ${moment(d.created_at).format("hh:mm:a")}`}
                                        </span>
                                        <div class="t-square"></div>
                                      </div>
                                    </div>
                                  );
                                })}
                              </div>
                            </Col>
                          </Row>
                        )}
                      </div>
                    );
                  })}
                </InfiniteScroll>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }
}

export default ChefOrderReport;
