import React, { Component } from "react";
import {
    FormGroup,
    FormControl,
    Button,
    Row,
    Col,
    Table,
} from "react-bootstrap";
import axios from "axios";
import { authHeader } from "../../../configs/helpers";
import { ApiUrlHost, apiUrls } from "../../../configs/configs";
import ReportProductsModal from "../../../components/PopUps/ReportProduct";

import "./style.css";

class ReportsByProducts extends Component {
    constructor(props) {
        super(props);
        this.state = {
            selectedCategory: '',
            orderto: '',
            orderfrom: '',
            categories: [],
            pastryCategories: [],
            branchEmps: [],
            branches: [],
            popupLoader: false,
            openPrintPopUp: false
        }
    }
    componentWillMount() {
        this.getPastryCategoryList();
        this.getAllBranchEmployees();
        this.getCategoryList();
        this.getAllBranch();
        // this.getAllProductsReport();
    }

    getAllProductsReport() {
        axios({
            method: "GET",
            url: apiUrls.REPORTS.products,
            headers: {
                Authorization: authHeader(),
            },
        })
            .then((result) => {
                if (result.status === 200 && result.data.data) {
                    console.log(result.data)


                } else {

                }
            })
            .catch((e) => {
                this.setState({
                    branches: [],
                });
            });
    }


    getAllBranch() {
        axios({
            method: "GET",
            url: apiUrls.ORDERS.branches,
            headers: {
                Authorization: authHeader(),
            },
        })
            .then((result) => {
                if (result.status === 200 && result.data.data) {
                    this.setState({
                        branches: result.data.data,
                    });
                } else {
                    this.setState({
                        branches: [],
                    });
                }
            })
            .catch((e) => {
                this.setState({
                    branches: [],
                });
            });
    }


    getCategoryList() {
        axios({
            method: 'GET',
            url: apiUrls.PRODUCT.getAllCategory,
            headers: {
                Authorization: authHeader()
            }
        }).then(result => {
            if (result.status === 200) {
                this.setState({
                    categories: result.data.data,
                });
            } else {
                this.setState({
                    categories: []
                });
            }
        }).catch(e => {
            this.setState({
                categories: []
            });
        });
    }

    getPastryCategoryList() {
        axios({
            method: "GET",
            url: apiUrls.PRODUCT.getAllCategoryPastry,
            headers: {
                Authorization: authHeader(),
            },
        })
            .then((result) => {
                if (result.status === 200) {
                    this.setState({
                        pastryCategories: result.data.data,
                    });
                } else {
                    this.setState({
                        pastryCategories: [],
                    });
                }
            })
            .catch((e) => {
                this.setState({
                    pastryCategories: [],
                });
            });
    }

    getAllBranchEmployees() {
        axios({
            method: "GET",
            url: apiUrls.BRANCH_EMPLOYEE_LIST,
            headers: {
                Authorization: authHeader(),
            },
        })
            .then((result) => {
                if (result.status === 200 && result.data.data) {
                    this.setState({
                        branchEmps: result.data.data,
                    });
                } else {
                    this.setState({
                        branchEmps: [],
                    });
                }
            })
            .catch((e) => {
                this.setState({
                    branchEmps: [],
                });
            });
    }

    openPrintPopUpModal() {
        this.setState({
            openPrintPopUp: true
        });
    }

    closePopup() {
        this.setState({
            openPrintPopUp: false,
        });
    }
    render() {
        return (
            <div className="report-product-container">
                <ReportProductsModal data={[]} loader={this.state.popupLoader} closePopup={() => this.closePopup()}
                    open={this.state.openPrintPopUp}
                />
                <div className="filter-section">
                    <Row>
                        <Col md={2}>
                            <FormGroup>
                                <label>Choose Category</label>

                                <FormControl
                                    type="text"
                                    componentClass="select"
                                    inputRef={(ref) => {
                                        this._category = ref;
                                    }}
                                    onChange={() =>
                                        this.setState({ selectedCategory: this._category.value })
                                    }
                                >
                                    <option value="">Category</option>

                                    <optgroup label="Regular">
                                        {this.state.categories.map((store) => {
                                            return (
                                                <option value={store._id} key={store._id}>
                                                    {store.name}
                                                </option>
                                            );
                                        })}
                                    </optgroup>
                                    <optgroup label="Pastries">
                                        {this.state.pastryCategories.map((store) => {
                                            return (
                                                <option value={store._id} key={store._id}>
                                                    {store.name}
                                                </option>
                                            );
                                        })}
                                    </optgroup>
                                </FormControl>
                            </FormGroup>
                        </Col>
                        <Col md={2}>
                            <FormGroup>
                                <label>Choose Branch</label>

                                <FormControl
                                    type="text"
                                    componentClass="select"
                                    inputRef={(ref) => {
                                        this._category = ref;
                                    }}
                                    onChange={() =>
                                        this.setState({ selectedCategory: this._category.value })
                                    }
                                >
                                    <option value="">Branch</option>

                                    <optgroup label="Branches">
                                        {this.state.branches.map((store) => {
                                            return (
                                                <option value={store._id} key={store._id}>
                                                    {store.branch}
                                                </option>
                                            );
                                        })}                                    </optgroup>
                                    <optgroup label="Branch Head">
                                        {this.state.branchEmps.map((store) => {
                                            return (
                                                <option value={store._id} key={store._id}>
                                                    {store.firstname}
                                                </option>
                                            );
                                        })}
                                    </optgroup>

                                </FormControl>
                            </FormGroup>
                        </Col>
                        <Col md={2}>
                            <FormGroup>
                                <label>
                                    From
                  {this.fromDate && this.fromDate.value && (
                                        <span
                                            style={{ color: "tomato", fontSize: 8 }}
                                            onClick={() => {
                                                this.fromDate.value = "";
                                                this.setState({ orderfrom: this.fromDate.value });
                                            }}
                                        >
                                            {" "}
                                            <i className="fa fa-times-circle fa-2x" />
                                        </span>
                                    )}
                                </label>
                                <FormControl
                                    type="date"
                                    inputRef={(ref) => {
                                        this.fromDate = ref;
                                    }}
                                    onChange={() =>
                                        this.setState({ orderfrom: this.fromDate.value })
                                    }
                                ></FormControl>
                            </FormGroup>
                        </Col>
                        <Col md={2}>
                            <FormGroup>
                                <label>
                                    to
                  {this.toDate && this.toDate.value && (
                                        <span
                                            style={{ color: "tomato", fontSize: 8 }}
                                            onClick={() => {
                                                this.toDate.value = "";
                                                this.setState({ orderto: this.toDate.value });
                                            }}
                                        >
                                            {" "}
                                            <i className="fa fa-times-circle fa-2x" />
                                        </span>
                                    )}
                                </label>
                                <FormControl
                                    type="date"
                                    inputRef={(ref) => {
                                        this.toDate = ref;
                                    }}
                                    onChange={() => this.setState({ orderto: this.toDate.value })}
                                ></FormControl>
                            </FormGroup>
                        </Col>
                        <Col md={2} className="mar-t-25px">
                            <button
                                className="btn btn-info btn-brown"
                            // onClick={() => this.openPrintPopUpModal()}
                            >
                                <i className="fa fa-search"></i> Search
                    </button>
                        </Col>
                    </Row>
                </div>
                <div className="table-container">
                    <Table responsive>
                        <thead>
                            <tr>
                                <th>S.No</th>
                                <th>Particulars</th>
                                <th>Total Order Received</th>
                                <th>Shop Orders</th>
                                <th>Stock Orders</th>
                                <th>Branch Orders</th>
                            </tr>
                        </thead>
                        <tbody>
                            <tr>
                                <td>1</td>
                                <td>Cake</td>
                                <td>10 nos</td>
                                <td>10 nos</td>
                                <td>10 nos</td>
                                <td>10 nos</td>
                            </tr>
                            <tr>
                                <td>2</td>
                                <td>Cake</td>
                                <td>10 nos</td>
                                <td>10 nos</td>
                                <td>10 nos</td>
                                <td>10 nos</td>
                            </tr>
                        </tbody>
                    </Table>
                    <button
                        className="btn btn-info btn-brown"
                        onClick={() => this.openPrintPopUpModal()}
                    >
                        <i className="fa fa-print"></i> Print Preview
                    </button>
                </div>


            </div>
        )
    }
}

export default ReportsByProducts;
