  getGroupesArr(grouped) {
    const branchItems = [];
    Object.keys(grouped).map((key) => {
      let productTotalQty = 0;
      let productTotalQtyPrice = 0;
      let branchName = "";
      let branchId = "";

      grouped[key].forEach((item) => {
        if (item.totalCost) {
          productTotalQtyPrice =
            productTotalQtyPrice + parseFloat(item.totalCost);
        }
        if (item.qty) {
          productTotalQty = productTotalQty + parseFloat(item.qty);
        }
        branchName = item.branchDetails.branch;
        branchId = item.branchDetails._id;
      });

      const oneData = {
        name: branchName.slice(0, 3),
        qty: productTotalQty,
        branch: branchId,
        cost: productTotalQtyPrice,
      };
      branchItems.push(oneData);
    });
    return branchItems;
  }

  reportBySalesMan() {
    const params = {};

    if (this.state.orderFromDate) {
      params.orderFromDate = this.state.orderFromDate;
    }

    if (this.state.orderToDate) {
      params.orderToDate = this.state.orderToDate;
    }

    if (this.state.branch) {
      params.branch = this.state.branch;
    }

    if (this.state.discount) {
      params.discount = this.state.discount;
    }

    if (this.state.selectedSalesMan) {
      params.salesMan = this.state.selectedSalesMan;
    }

    axios({
      method: "post",
      url: apiUrls.STORE.reportSalesMan,
      headers: {
        Authorization: authHeader(),
      },
      params: params,
    }).then((result) => {
      if (result.status === 200 && result.data.data) {
        const data = result.data.data;
        let branchName = "";
        let qty = 0;
        let price = 0;
        const temp = [];
        let discount = 0;

        data.forEach((i, k) => {
          if (i.emp) {
            qty = qty + i.qty;
            price = price + i.totalCost;
            discount = discount + i.discount;

            const grouped = _.groupBy(i.branchWise, function (order) {
              return order.branch;
            });

            const branchItems = this.getGroupesArr(grouped);

            temp.push({
              sno: k + 1,
              label: i.emp && i.emp.firstname ? i.emp.firstname : "",
              value: i.totalCost.toFixed(2),
              qty: i.qty.toFixed(2),
              branchItems: branchItems,
              discount: i.discount.toFixed(2),
            });
          }
        });

        if (this.state.branch) {
          this.state.branches.forEach((i) => {
            if (i._id == this.state.branch) {
              branchName = i.branch;
            }
          });
        }

        const tempAppliedFilter = [];
        if (this.state.orderFromDate && this.state.orderToDate) {
          tempAppliedFilter.push({
            label: "Date",
            value: `${this.state.orderFromDate} - ${this.state.orderToDate}`,
          });
        } else if (this.state.orderFromDate) {
          tempAppliedFilter.push({
            label: "Date",
            value: `${this.state.orderFromDate}`,
          });
        } else if (this.state.orderToDate) {
          tempAppliedFilter.push({
            label: "Date",
            value: `${this.state.orderToDate}`,
          });
        }
        if (this.state.selectedSalesMan) {
          let salesMan = "";
          this.state.salesMans.forEach((i) => {
            if (i._id == this.state.selectedSalesMan) {
              salesMan = i.firstname;
            }
          });
          tempAppliedFilter.push({ label: "Sales Man", value: `${salesMan}` });
        }

        const billItem = {
          selectedBranch: branchName,
          totalQty: qty.toFixed(2),
          totalPrice: price.toFixed(2),
          items: temp,
          totalDiscount: discount.toFixed(2),
          appliedFilters: tempAppliedFilter,
        };
        this.setState({
          billItem: billItem,
        });
      }
    });
  }

  reportByBill() {
    const params = {};
    if (this.state.orderFromDate) {
      params.orderFromDate = this.state.orderFromDate;
    }

    if (this.state.orderToDate) {
      params.orderToDate = this.state.orderToDate;
    }

    if (this.state.branch) {
      params.branch = this.state.branch;
    }

    if (this.state.discount) {
      // console.log('discountComes')
      params.discount = this.state.discount;
    }

    axios({
      method: "post",
      url: apiUrls.STORE.reportByBill,
      headers: {
        Authorization: authHeader(),
      },
      params: params,
    }).then((result) => {
      if (result.status === 200 && result.data.data) {
        const data = result.data.data;
        let branchName = "";
        let qty = 0;
        let price = 0;
        let discount = 0;
        const temp = [];

        data.forEach((i, k) => {
          if (i.branchName && i.branchName[0]) {
            qty = qty + i.qty;
            price = price + i.totalCost;
            discount = discount + i.discount;
            const grouped = _.groupBy(i.branchWise, function (order) {
              // console.log(i, 'i')
              // console.log(order, 'order')
              return order.branch;
            });
            const branchItems = this.getGroupesArr(grouped);

            temp.push({
              sno: k + 1,
              label:
                i.branchName && i.branchName[0]
                  ? i.branchName[0].firstname + " Bills"
                  : "",
              value: i.totalCost.toFixed(2),
              discount: i.discount.toFixed(2),
              qty: i.qty.toFixed(2),
              branchItems: branchItems,
            });
          }
        });

        if (this.state.branch) {
          this.state.branches.forEach((i) => {
            if (i._id == this.state.branch) {
              branchName = i.branch;
            }
          });
        }
        const tempAppliedFilter = [];
        if (this.state.orderFromDate && this.state.orderToDate) {
          tempAppliedFilter.push({
            label: "Date",
            value: `${this.state.orderFromDate} - ${this.state.orderToDate}`,
          });
        } else if (this.state.orderFromDate) {
          tempAppliedFilter.push({
            label: "Date",
            value: `${this.state.orderFromDate}`,
          });
        } else if (this.state.orderToDate) {
          tempAppliedFilter.push({
            label: "Date",
            value: `${this.state.orderToDate}`,
          });
        }

        const billItem = {
          selectedBranch: branchName,
          totalQty: qty.toFixed(2),
          totalDiscount: discount.toFixed(2),
          totalPrice: price.toFixed(2),
          items: temp,
          appliedFilters: tempAppliedFilter,
        };

        this.setState({
          billItem: billItem,
        });
      }
    });
  }

  shortName(branch) {
    return branch.slice(0, 3);
  }

  getBranch(branchId, data) {
    let val = "-";

    data.forEach((o) => {
      if (o.branch == branchId) {
        val = `₹ ${o.cost.toFixed(2)}`;
      }
    });
    return val;
  }

  fixOpacity(index) {
     return 1 / (index + 1);
  }

  getBackground(index) {
    var value = index * 10;
    if (index <= 10) {
      const red = 50 + value;
      const blue = 32 + value;
      // return `rgb(1, ${red}, ${blue})`;
      // return `rgb(${red}, 0, ${blue})`;
    }
    value = index * 15;
    const blueValue = index * 3;
    const green = 40 + value;
    const blue = 21 + blueValue;
    return `rgb(1, ${green}, ${blue})`;
    // return `rgb(255, ${green}, ${blue})`;
  }

  getColor(index) {
    if (index <= 10) {
      return "#fff";
    }
    return "#000";
  }

  getTotalValue(type, items){
    let val = 0;
    if(type === 'price'){
      items.forEach((item)=>{
        val = val + parseFloat(item.cost);
      })
    }else   if(type === 'qty'){
      items.forEach((item)=>{
        val = val + parseFloat(item.qty);
      })
    }
    
    return (val).toFixed(2);
  }

