import React, { Component } from "react";
import Modal from "react-modal";
import axios from "axios";
import { apiUrls } from "../../configs/configs";
import { authHeader } from "../../configs/helpers";
import "./stocks.css";

const customStyles = {
    content: {
        top: "50%",
        left: "50%",
        right: "auto",
        bottom: "auto",
        // marginRight: '-50%',
        transform: "translate(-50%, -50%)",
        height: "600px", // <-- This sets the height
        overlfow: "scroll", // <-- This tells the modal to scrol
        minWidth: "70%",
    },
};

class StockManagePrStk extends Component {
    constructor(props) {
        super(props);
        this.state = {
            openPopup: false,
            itemId: '',
            qty: '',
            branch: '',
            category: '',
            product: ''
        };
    }

    UNSAFE_componentWillReceiveProps(_nprops) {
        if (_nprops.open === true) {
            console.log(_nprops)
            this.setState({
                openPopup: true,
                itemId: _nprops.id,
                category: _nprops.category,
                branch: _nprops.branch,
                product: _nprops.product
            });
        }
    }

    closePopUp(refresh = false) {
        this.setState({
            openPopup: false,
            itemId: '',
            qty: '',
            category: '',
            branch: '',
            product: ''
        });

        this.props.closePopup(refresh);
    }

    save() {
        const sendBody = {
            qty: this.state.qty,
            id: this.state.itemId,
            branch: this.state.branch,
            category: this.state.category,
            product: this.state.product
        }
        axios({
            method: "POST",
            data: sendBody,
            url: `${apiUrls.STOCKS.stockUpdate}`,
            headers: {
                Authorization: authHeader(),
            }
        })
            .then((result) => {
                this.closePopUp(true)

            })
            .catch((e) => {
            });
    }

    render() {
        return (
            <Modal
                isOpen={this.state.openPopup}
                ariaHideApp={false}
                style={customStyles}
                contentLabel="Stock Modal"
            >
                <div className="modal-header">
                    <p>Update Stock</p>
                    <p className="close-modal" onClick={() => this.closePopUp()}>
                        <i className="fa fa-times"></i>
                    </p>
                </div>
                <div className="modal-body">

                    <p>Enter stock limit of product</p>
                    <input type="number" value={this.state.qty} onChange={(e) => this.setState({ qty: e.target.value })} className="form-control" />
                    <p className="note">* Empty Qty considered as Unlimited</p>



                </div>
                <div className="modal-footer">
                    <button className="btn" onClick={() => this.save()}>Save</button>
                </div>

            </Modal>
        );
    }
}

export default StockManagePrStk;
