import React, { Component } from "react";
import Modal from "react-modal";
import { Table } from "react-bootstrap";
import ReactToPrint from "react-to-print";
import { ToWords } from "to-words";

import "./bill-custom.css";

const toWords = new ToWords({
  localeCode: "en-IN",
  converterOptions: {
    currency: true,
    ignoreDecimal: false,
    ignoreZeroCurrency: false,
  },
});

const customStyles = {
  content: {
    top: "50%",
    left: "50%",
    right: "auto",
    bottom: "auto",
    // marginRight: '-50%',
    transform: "translate(-50%, -50%)",
    height: "600px", // <-- This sets the height
    overlfow: "scroll", // <-- This tells the modal to scrol
    minWidth: "70%",
  },
};

class ReportOrdersModal extends Component {
  constructor(props) {
    super(props);
    this.state = {
      openPopup: false,
      billItems: [],
      branch: "",
      loader: false,
      totalOrders: 0,
      totalAmt: 0,
      grouped: [],
      returns: [],
    };
  }

  UNSAFE_componentWillReceiveProps(_nprops) {
    if (_nprops.open === true) {
      this.setState({
        openPopup: true,
        loader: _nprops.loader,
      });
      if (_nprops.data) {
        if (_nprops.data.length > 0) {
          this.setState({
            billItems: _nprops.data,
            totalOrders: _nprops.totalOrder,
            totalAmt: _nprops.totalSales,
            branch: _nprops.branch,
            grouped: _nprops.groupedData,
            returns: _nprops.returnOrders,
          });
        }
      }
    }
  }

  closePopUp() {
    this.setState({
      openPopup: false,
      billItems: [],
      grouped: [],
      returns: [],
    });
    this.props.closePopup();
  }

  getTotalAmountOfReturn(items) {
    let tAmont = 0;
    items.forEach((element) => {
      tAmont = parseFloat(tAmont) + parseFloat(element.price);
    });
    return tAmont;
  }

  getTotalOrdersOfReturn(items) {
    let _tOrders = 0;
    items.forEach((element) => {
      _tOrders = parseFloat(_tOrders) + parseFloat(element.qty);
    });
    return _tOrders;
  }

  render() {
    return (
      <Modal
        isOpen={this.state.openPopup}
        ariaHideApp={false}
        style={customStyles}
        contentLabel="Bill Modal"
      >
        <p className="close-modal" onClick={() => this.closePopUp()}>
          <i className="fa fa-times"></i>
        </p>

        <div ref={(el) => (this.componentRef = el)}>
          <Table
            bordered
            size="sm"
            className="margin-btm-0 zero-bottom-border table-head-item"
          >
            <tbody>
              <tr>
                <td colSpan="3" className="text-center pad-opx">
                  <h4>Black Forest Cakes</h4>
                  {this.state.branch && <p>{this.state.branch}</p>}
                </td>
              </tr>
            </tbody>
          </Table>
          <Table className="bill-item-table" size="sm">
            <thead>
              <tr>
                <th>S.No</th>
                <th>Checked</th>
                <th>Particulars</th>
                <th>Category</th>
                <th>Type</th>
                <th>Ordered Qty</th>
                <th>Amount</th>
                <th>Date</th>
              </tr>
            </thead>
            <tbody>
              {this.state.loader === true && (
                <tr className="border-top-row">
                  <td className="pad-10px" colSpan="6">
                    Loading huge items please wait...
                  </td>
                </tr>
              )}
              {/* {this.state.billItems.length > 0 &&
                this.state.billItems.map((item, key) => {
                  return (
                    <tr key={key}>
                      <td>{key + 1}</td>
                      <td>{item.name}</td>
                      <td>{item.type}</td>
                      <td>{item.qty}</td>
                      <td>₹ {item.amount}</td>
                      <td>₹ {item.date}</td>
                    </tr>
                  );
                })} */}
              {Object.keys(this.state.grouped).map((key) => {
                return (
                  <>
                    <tr className="border-top-row" key={key}>
                      <td td colSpan="8" className="cat-title">
                        {key}
                        <p className="font-12px">
                          Description <br />
                          <span>
                            Delivery Every cake we offer is handcrafted and
                            since each chef has his/her own way of baking and
                            designing a cake, there might be slight variation in
                            the product in terms of design an
                          </span>
                        </p>
                      </td>
                    </tr>
                    {this.state.grouped[key].map((item, keyT) => {
                      return (
                        <tr key={keyT} className="border-top-row">
                          <td>{keyT + 1}</td>
                          <td>
                            <input type="checkbox" disabled />
                          </td>
                          <td>{item.name}</td>
                          <td>{item.categoryName}</td>
                          <td>{item.type}</td>
                          <td>{item.qty}</td>
                          <td>₹ {item.amount}</td>
                          <td>₹ {item.date}</td>
                        </tr>
                      );
                    })}
                  </>
                );
              })}
              {this.state.billItems.length > 0 && (
                <tr className="border-top-row">
                  <td className="pad-10px" colSpan="5">
                    Total
                  </td>
                  <td className="pad-10px">{this.state.totalOrders}</td>
                  <td className="pad-10px">
                    {" "}
                    ₹ {this.state.totalAmt.toFixed(2)}
                  </td>
                  <td></td>
                </tr>
              )}
              {this.state.returns.length > 0 && (
                <tr className="border-top-row">
                  <td className="pad-10px" colSpan="5">
                    Total Return Orders
                  </td>
                  <td className="pad-10px">
                    {this.getTotalOrdersOfReturn(this.state.returns)}
                  </td>
                  <td className="pad-10px">
                    {" "}
                    ₹{this.getTotalAmountOfReturn(this.state.returns)}
                  </td>
                  <td></td>
                </tr>
              )}
              {this.state.returns.length > 0 && (
                <tr className="border-top-row">
                  <td className="pad-10px" colSpan="6">
                    Net Total
                  </td>
                  <td className="pad-10px">
                    {" "}
                    ₹{" "}
                    {this.state.totalAmt.toFixed(2) -
                      this.getTotalAmountOfReturn(this.state.returns)}
                  </td>
                  <td></td>
                </tr>
              )}

              <tr>
                <td colSpan="8"></td>
              </tr>
            </tbody>
          </Table>
        </div>

        {this.state.billItems.length > 0 && (
          <ReactToPrint
            documentTitle={"Black-forest-order-report"}
            trigger={() => {
              return (
                <button id="printInvoice" className="btn btn-info">
                  <i className="fa fa-print"></i> Print
                </button>
              );
            }}
            content={() => this.componentRef}
          />
        )}

        <button
          className="btn btn-info mar-lft-10px"
          onClick={() => this.closePopUp()}
        >
          <i className="fa fa-times"></i> Close
        </button>
      </Modal>
    );
  }
}

export default ReportOrdersModal;
