
import React, { Component } from "react";
import { Grid, Row, Col } from "react-bootstrap";
import { Link } from "react-router-dom";
import NotificationSystem from "react-notification-system";
import axios from 'axios';
import ImageCompressor from 'image-compressor.js';

import { style } from "../../variables/Variables.jsx";
import { Card } from "components/Card/Card.jsx";
import Button from "components/CustomButton/CustomButton.jsx";
import '../../assets/css/custom.css';
import { validateForm, authHeader, fileMaxLimit } from '../../configs/helpers';
import { ApiUrlHost, apiUrls } from '../../configs/configs';
import BarcodeReader from 'react-barcode-reader'

class PastryUpdate extends Component {
  constructor(props) {
    super(props);
    this.state = {
      isActive: false,
      allowGST: false,
      cgst: 0,
      sgst: 0,
      cess: 0,
      code: '',
      pastryId: this.props.match.params.id,
      isFormSubmit: false,
      name: '',
      price: '',
      image: '',
      category: '',
      categoryCol: [],
      productUnits: [],
      _pUnit: '',
      errors: {
        name: '',
        price: '',
        image: '',
        code: ''
      }
    }
  }

  componentWillMount() {
    this.getProductUnitList();
    this.getPastryData();
    this.getCategoryList();
  }

  handleCheck = () => {
    this.setState({ allowGST: !this.state.allowGST });
  };

  handleCheckActive = () => {
    this.setState({ isActive: !this.state.isActive });
  };

  getProductUnitList() {
    axios({
      method: 'GET',
      url: apiUrls.PRODUCTUNITSLIST,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        this.setState({
          productUnits: result.data.data,
        });
      } else {
        this.setState({
          productUnits: []
        });
      }
    }).catch(e => {
      this.setState({
        productUnits: []
      });
    });
  }


  getCategoryList() {
    axios({
      method: 'GET',
      url: apiUrls.PRODUCT.getAllCategoryPastry,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        this.setState({
          categoryCol: result.data.data,
        });
      } else {
        this.setState({
          categoryCol: []
        });
      }
    }).catch(e => {
      this.setState({
        categoryCol: []
      });
    });
  }

  getPastryData() {
    axios({
      method: 'GET',
      url: apiUrls.PASTRY.one + '/' + this.state.pastryId,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        var data = result.data.data;
        this.setState({
          name: data.name,
          price: data.price,
          existImg: data.image,
          category: data.category,
          allowGST: data.allowGST ? data.allowGST : false,
          cgst: data.cgst ? data.cgst : 0,
          sgst: data.sgst ? data.sgst : 0,
          cess: data.cess ? data.cess : 0,
          code: data.code ? data.code : '',
          isActive: data.isActive
        })
        if (data.unit) {
          this.setState({
            _pUnit: data.unit
          })
        }
      }
    }).catch(e => {
      console.log(e);
    });
  }


  handleChange = (event) => {
    event.preventDefault();
    const { name, value } = event.target;
    let errors = this.state.errors;

    switch (name) {
      case 'name':
        errors.name =
          value.length <= 0
            ? 'Branch name is required'
            : '';
        break;
      case 'price':
        errors.price =
          value.length <= 0
            ? 'Price is required'
            : '';
        break;
      case 'category':
        errors.category =
          value.length <= 0
            ? 'Product category is required'
            : '';
        break;
      case 'code':
        errors.code =
          value.length <= 0
            ? 'Product code is required'
            : '';
        break;
      default:
        break;
    }

    this.setState({ errors, [name]: value });
  }

  handleSubmit = (event) => {
    this.setState({ _notificationSystem: this.refs.notificationSystem, isFormSubmit: true });
    var _notificationSystem = this.refs.notificationSystem;
    event.preventDefault();

    if (validateForm(this.state.errors)) {
      var bodyFormData = new FormData();
      bodyFormData.set('name', this.state.name);
      bodyFormData.set('price', this.state.price);
      bodyFormData.set('code', this.state.code);
      bodyFormData.set('cgst', this.state.cgst);
      bodyFormData.set('sgst', this.state.sgst);
      bodyFormData.set('cess', this.state.cess);
      bodyFormData.set('allowGST', this.state.allowGST);
      bodyFormData.set('isActive', this.state.isActive);

      bodyFormData.append('image', this.state.image)
      bodyFormData.set('category', this.state.category);
      if (this.state._pUnit) {
        bodyFormData.set('unit', this.state._pUnit);
      }
      axios({
        method: 'PUT',
        url: apiUrls.PASTRY.one + '/' + this.state.pastryId,
        data: bodyFormData,
        headers: {
          'Content-Type': 'multipart/form-data',
          Authorization: authHeader()
        }
      }).then(result => {
        if (result.status === 200) {
          this.getPastryData();

          _notificationSystem.addNotification({
            title: <span data-notify="icon" className="pe-7s-check" />,
            message: (
              <div>
                Pastry Updated.
              </div>
            ),
            level: 'success',
            position: "tr",
            autoDismiss: 15
          });

        }
      }).catch(e => {
        console.log(e)
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
              {(e.response) ? e.response.data.message : 'Something went wrong!'}
            </div>
          ),
          level: 'error',
          position: "tr",
          autoDismiss: 15
        });
      });
    }
  }

  fileChangedHandler = (event) => {
    let errors = this.state.errors;
    let curr = this;

    if (event.target.files[0]) {
      if (fileMaxLimit(event)) {
        errors.image = '';
        new ImageCompressor(event.target.files[0], {
          quality: 0.6,
          success(result) {
            var file = new File([result], result.name, { type: result.type });
            curr.setState({ image: file, errors });
          },
          error(e) {
            console.log(e.message);
          },
        });
      } else {
        errors.image = 'File size should be maximum 5MB';
        this.setState({ errors });
      }
    } else {
      errors.image = '';
      this.setState({ image: '', errors });
    }
  };


  handleScan(data) {
    console.info("Barcode Working...");
    this.setState({
      code: data,
    })
  }

  handleError(err) {
    console.error(err)
  }

  render() {
    const { errors, isFormSubmit } = this.state;

    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />
        <BarcodeReader
          onError={this.handleError.bind(this)}
          onScan={this.handleScan.bind(this)}
        />
        <Grid fluid>
          <Row>
            <Col md={8}>
              <Card
                title="Update pastry"
                content={
                  <form onSubmit={this.handleSubmit} noValidate>

                    <div className="form-group">
                      <label>Name</label>
                      <input type="text" className="form-control" name="name" value={this.state.name} placeholder="Enter name" onChange={this.handleChange} noValidate />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.name}</p>
                        )
                      }
                    </div>


                    <div className="row">
                      <div className="col-md-6">


                        <div className="form-group">
                          <label>Price</label>
                          <input type="text" min={0} className="form-control" value={this.state.price} name="price" placeholder="Enter price" onChange={this.handleChange} noValidate />
                          {
                            isFormSubmit && (
                              <p className="txt-error">{errors.price}</p>
                            )
                          }
                        </div>
                      </div>
                      <div className="col-md-6">
                        <div className="form-group">
                          <label>Code*</label>
                          <input type="text" className="form-control" value={this.state.code} name="code" placeholder="Enter code" onChange={this.handleChange} noValidate />
                          {
                            isFormSubmit && (
                              <p className="txt-error">{errors.code}</p>
                            )
                          }
                        </div>
                      </div>
                    </div>
                    <div className="row">

                      <div className="col-md-2">

                        <div className="form-group">
                          <label>Allow GST?</label>
                          <input type="checkbox" className="form-control" name="allowGST" onChange={this.handleCheck} checked={this.state.allowGST}
                            noValidate />
                        </div>
                      </div>


                      <div className="col-md-2">

                        <div className="form-group">
                          <label>Is Active?</label>
                          <input type="checkbox" className="form-control" name="isActive" onChange={this.handleCheckActive} checked={this.state.isActive}
                            noValidate />
                        </div>
                      </div>

                    </div>


                    <div className="row">
                      <div className="col-md-3">
                        <div className="form-group">
                          <label>CGST %</label>
                          <input type="number" value={this.state.cgst} className="form-control" name="cgst" placeholder="Enter CGST  %" onChange={this.handleChange} noValidate />
                          {
                            isFormSubmit && (
                              <p className="txt-error">{errors.cgst}</p>
                            )
                          }
                        </div>
                      </div>

                      <div className="col-md-3">

                        <div className="form-group">
                          <label>SGST %</label>
                          <input type="number" value={this.state.sgst} className="form-control" name="sgst" placeholder="Enter SGST  %" onChange={this.handleChange} noValidate />
                          {
                            isFormSubmit && (
                              <p className="txt-error">{errors.sgst}</p>
                            )
                          }
                        </div>
                      </div>

                      <div className="col-md-3">

                        <div className="form-group">
                          <label>CESS %</label>
                          <input type="number" value={this.state.cess} className="form-control" name="cess" placeholder="Enter CESS %" onChange={this.handleChange} noValidate />
                          {
                            isFormSubmit && (
                              <p className="txt-error">{errors.sgst}</p>
                            )
                          }
                        </div>
                      </div>
                    </div>

                    <div className="form-group">
                      <label>Category</label>
                      <select name="category" className="form-control" value={this.state.category} onChange={this.handleChange}>
                        <option value="">Select Category</option>
                        {this.state.categoryCol.length > 0 && (
                          this.state.categoryCol.map((e, key) => {
                            return (
                              <option value={e._id} key={key}>{e.name}</option>
                            )
                          })
                        )}
                      </select>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.category}</p>
                        )
                      }
                    </div>


                    <div className="form-group">
                      <label>Photo</label>
                      <input type="file" className="form-control" name="image" onChange={this.fileChangedHandler} />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.image}</p>
                        )
                      }
                    </div>
                    <div className="form-group">
                      <label>Unit</label>
                      <select name="unit" className="form-control" value={this.state._pUnit} onChange={(ele) => this.setState({ _pUnit: ele.target.value })}>
                        <option value="">Select</option>
                        {this.state.productUnits.length > 0 && (
                          this.state.productUnits.map((e, key) => {
                            return (
                              <option value={e._id} key={key}>{e.name}</option>
                            )
                          })
                        )}
                      </select>
                    </div>

                    <Link className="mgr-5 btn btn-default" to="/admin/pastries">Cancel</Link>

                    <Button bsStyle="info" type="submit">
                      Update
                    </Button>

                    <div className="clearfix" />
                  </form>
                }
              />
            </Col>

            {this.state.existImg && (
              <Col md={3}>
                <div className="card card-user">
                  <img src={ApiUrlHost + '/' + this.state.existImg} className="store-image" alt="store" />
                </div>
              </Col>
            )}
          </Row>
        </Grid>
      </div>
    );
  }
}

export default PastryUpdate;
