import React, { Component } from "react";
import StockManageAssignBill from "../../components/PopUps/StockManage-AssignPro";
import StockManagePrStk from "../../components/PopUps/StockManage-ProStk";
import axios from "axios";
import { apiUrls } from "../../configs/configs";
import { authHeader } from "../../configs/helpers";
import "../../assets/css/stocks.css";

export class StockOrdersStocks extends Component {
    constructor(props, context) {
        super(props, context);
        this.state = {
            openPrintModal: false,
            openProductEdit: false,
            storesCollection: [],
            productCategories: [],
            selectedCategories: [],
            products: [],
            selectedProducts: [],
            selectedBranch: '',
            selectedCategory: '',
            selectedItem: '',
            selectedProduct: ''
        };

        this.getAllBranches();
        this.getAllProductCategory();
    }


    getAllBranches() {
        axios({
            method: "GET",
            url: apiUrls.ORDERS.branches,
            headers: {
                Authorization: authHeader(),
            }
        })
            .then((result) => {
                if (result.status === 200) {
                    this.setState({
                        storesCollection: result.data.data
                    });
                }
            })
            .catch((e) => {
            });
    }

    getAllProductCategory() {
        axios({
            method: "GET",
            url: apiUrls.PRODUCT.getAllCategoryPastry,
            headers: {
                Authorization: authHeader(),
            }
        })
            .then((result) => {
                if (result.status === 200) {
                    this.setState({
                        productCategories: result.data.data
                    });
                }
            })
            .catch((e) => {
            });
    }

    closePopup(isRefresh = false) {
        this.setState({
            openPrintModal: false
        });
        if (isRefresh) {
            this.getBranchesByCategory(this.state.selectedBranch);
        }
    }

    closeProStkPopup(refresh = false) {
        this.setState({
            openProductEdit: false
        });
        if (refresh == true) {
            this.getPastriesByCategory(this.state.selectedCategory)
        }
    }

    openProStkPopup(id, p) {
        this.setState({
            openProductEdit: true,
            selectedItem: id,
            selectedProduct: p
        });
    }

    openPopup(category) {
        this.setState({
            openPrintModal: true,
            selectedCategory: category
        });
    }


    getBranchesByCategory(branch) {
        this.setState({
            selectedBranch: branch,
            selectedProducts: [],
            selectedCategory: ''
        })
        axios({
            method: "GET",
            url: `${apiUrls.STOCKS.getAllBranchCategory}?branch=${branch}`,
            headers: {
                Authorization: authHeader(),
            }
        })
            .then((result) => {
                if (result.status === 200) {
                    if (result.data && result.data.data && result.data.data.length > 0) {
                        const branchSelected = result.data.data;
                        const allItems = this.state.productCategories;
                        allItems.forEach(i => {
                            i.isSelected = false;

                            branchSelected.forEach((b) => {
                                if (b.category == i._id && b.isEnable == true) {
                                    i.isSelected = true;
                                }
                            })
                        });

                        this.setState({
                            selectedCategories: allItems
                        });

                    } else {
                        const allItems = this.state.productCategories;

                        allItems.forEach(i => {
                            i.isSelected = false;
                        });

                        this.setState({
                            selectedCategories: allItems
                        });
                    }

                } else {
                    this.setState({
                        selectedCategories: []
                    });
                }
            })
            .catch((e) => {
                this.setState({
                    selectedCategories: []
                });
            });
    }

    deactiveCategory(category) {
        const sendBody = {
            selectedCategory: category,
            selectedBranch: this.state.selectedBranch,
        };
        axios({
            method: "POST",
            data: sendBody,
            url: `${apiUrls.STOCKS.disableCategory}`,
            headers: {
                Authorization: authHeader(),
            }
        })
            .then((result) => {
                this.setState({
                    selectedProducts: []
                })
                this.getBranchesByCategory(this.state.selectedBranch)
            })
            .catch((e) => {
            });
    }

    getPastriesByCategory(category) {
        this.setState({
            selectedCategory: category
        })
        axios({
            method: "POST",
            url: `${apiUrls.STORE.productDropDown}?category=${category}`,
            headers: {
                Authorization: authHeader(),
            }
        })
            .then((result) => {
                if (result.status === 200) {
                    const products = result.data.data;
                    axios({
                        method: "GET",
                        url: `${apiUrls.STOCKS.getAllBranchProducts}?branch=${this.state.selectedBranch}&category=${category}`,
                        headers: {
                            Authorization: authHeader(),
                        }
                    })
                        .then((result) => {
                            let items = [];
                            if (result.status === 200) {
                                if (result.data && result.data.data && result.data.data.length > 0) {
                                    items = result.data.data;
                                }
                            }
                            products.forEach((i) => {
                                i.isSelected = false;
                                i.qty = '';
                                items.forEach((s) => {
                                    if (s.product == i._id) {
                                        i.isSelected = s.isEnable;
                                        i.isAddedAlready = true;
                                        i.qty = s.qty;
                                        i.itemId = s._id;
                                    }
                                })
                            });
                            this.setState({
                                selectedProducts: products
                            })
                        })
                        .catch((e) => {
                            this.setState({
                                selectedCategories: []
                            });
                        });
                }
            })
            .catch((e) => {
            });
    }


    handleCheck(item) {

        const sendBody = {
            state: !item.isSelected,
            qty: item.qty,
            id: item.itemId,
            branch: this.state.selectedBranch,
            category: this.state.selectedCategory,
            product: item._id
        };
        axios({
            method: "POST",
            data: sendBody,
            url: `${apiUrls.STOCKS.stockUpdate}`,
            headers: {
                Authorization: authHeader(),
            }
        })
            .then((result) => {
                const items = this.state.selectedProducts;
                items.forEach((i) => {
                    if (i._id == item._id) {
                        i.isSelected = !i.isSelected
                    }
                });
                this.setState({
                    selectedProducts: items
                });
            })
            .catch((e) => {
            });

    }

    render() {
        return (
            <div className="content">
                <div className="row">
                    <div className="col-sm-12">
                        <div className="card">
                            <div className="header">
                                <div className="row"><div className="col-md-12"><div className="mar0px row"></div></div></div>
                            </div>
                            <div className="content">
                                <div className="row stock-section">
                                    <div className="col-sm-4">
                                        <ul>
                                            <li><h5>Branches</h5></li>
                                            {this.state.storesCollection.map((branch, key) => {
                                                return <li key={`br-row-${key}`} onClick={() => this.getBranchesByCategory(branch._id)}><p className={branch._id == this.state.selectedBranch ? " hand-cursor active" : "hand-cursor"}>{branch.branch} <i className={branch._id == this.state.selectedBranch ? "ico pe-7s-angle-right hand-cursor active" : "ico pe-7s-angle-right hand-cursor"}></i></p></li>
                                            })}
                                        </ul>
                                    </div>

                                    {
                                        this.state.selectedCategories.length > 0 && (
                                            <div className="col-sm-4">
                                                <ul className="pro-category">
                                                    <li><h5>Product Category</h5></li>
                                                    {this.state.selectedCategories.map((i, k) => {
                                                        return (<li key={`pro-c-stk-${k}`}>
                                                            {i.products == 0 && <i className={i.isSelected == true ? "ico1 fa fa-check-circle hand-cursor color-grey" : "ico1 fa fa-check-circle-o hand-cursor color-grey"}></i>}
                                                            {i.products > 0 && <i className={i.isSelected == true ? "ico1 fa fa-check-circle hand-cursor" : "ico1 fa fa-check-circle-o hand-cursor"} onClick={i.isSelected == true ? () => this.deactiveCategory(i._id) : () => this.openPopup(i._id)}></i>}
                                                            <p className={i._id == this.state.selectedCategory ? " active" : ""}>{i.name} <span>Total {i.products} products available in this category</span></p>
                                                            {i.isSelected == true && <i className="ico pe-7s-angle-right hand-cursor" onClick={() => this.getPastriesByCategory(i._id)}></i>}

                                                        </li>)
                                                    })}
                                                </ul>
                                            </div>
                                        )
                                    }

                                    {this.state.selectedProducts.length > 0 && (
                                        <div className="col-sm-4">
                                            <ul className="product">
                                                <li>
                                                    <h5>Product &nbsp;
                                                        {/* <label><input type="checkbox" />&nbsp;Enable all</label> */}
                                                    </h5>
                                                </li>
                                                {this.state.selectedProducts.map((i, k) => {
                                                    return (<li key={`pro-stk-item-${k}`}>
                                                        <p>{i.name}
                                                            <span>Stock Limit: {i.qty} <i className="fa fa-pencil-square-o hand-cursor" aria-hidden="true" onClick={() => this.openProStkPopup(i.itemId, i._id)}></i></span>
                                                        </p>
                                                        <label className="switch custom">
                                                            <input type="checkbox" checked={i.isSelected} onChange={() => this.handleCheck(i)} />
                                                            <span className="slider custom round"></span>
                                                        </label>
                                                    </li>)
                                                })}
                                            </ul>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

                <StockManageAssignBill
                    branch={this.state.selectedBranch}
                    category={this.state.selectedCategory}
                    closePopup={(state) => this.closePopup(state)}
                    open={this.state.openPrintModal}
                />
                <StockManagePrStk
                    closePopup={(refresh) => this.closeProStkPopup(refresh)}
                    open={this.state.openProductEdit}
                    id={this.state.selectedItem}
                    branch={this.state.selectedBranch}
                    category={this.state.selectedCategory}
                    product={this.state.selectedProduct}

                />
            </div>
        );
    }
}
