
import React, { Component } from "react";
import { Grid, Row, Col } from "react-bootstrap";
import {  Link } from "react-router-dom";
import NotificationSystem from "react-notification-system";
import axios from 'axios';
import ImageCompressor from 'image-compressor.js';

import { style } from "../../variables/Variables.jsx";
import { Card } from "components/Card/Card.jsx";
import Button from "components/CustomButton/CustomButton.jsx";
import '../../assets/css/custom.css';
import { validateForm, authHeader, fileMaxLimit } from '../../configs/helpers';
import { apiUrls, EmployeeTypes} from '../../configs/configs';

class EmployeeCreate extends Component {
  constructor(props){
    super(props);
    this.state = {
      isFormSubmit: false,
      stores: [],
      firstname: null,
      lastname: null,
      phone: null,
      address: null,
      email: null,
      branch: null,
      username: null,
      password: null,
      type: null,
      image: null,
      isOtpAccess: false,
      errors: {
        firstname: 'Firstname is required',
        lastname: 'Lastname is required',
        phone: '',
        // address: 'Address is required',
        // email: 'Email is required',
        // branch: 'Branch name is required',
        username: 'Username is required',
        password: 'Password is required',
        type: 'Employee type is required',
        image: ''
      }
    }
  }

  componentWillMount(){

    axios({
        method: 'GET',
        url: apiUrls.STORE.allStore,
        headers: {
          Authorization: authHeader()
        }
      }).then(result => {
        if (result.status === 200) {
          this.setState({
            stores: result.data.data,
          });
        }else{
          this.setState({
            stores : []
          });
        }
      }).catch(e => {
        this.setState({
          stores : []
        });
      });
  }

  handleChange = (event) => {
    event.preventDefault();
    const { name, value } = event.target;
    let errors = this.state.errors;

    switch (name) {
      case 'firstname': 
        errors.firstname = 
        value.length <= 0
        ? 'Firstname is required'
        : '';
        break;

    case 'lastname': 
        errors.lastname = 
        value.length <= 0
        ? 'Lastname is required'
        : '';
        break;
    case 'phone': 
        errors.phone = 
        !value ? '' : value.length === 10
        ? ''
        : 'Phone number should be 10 digits';
        break;
    case 'username': 
        errors.username = 
        value.length <= 0
        ? 'Username is required'
        : '';
        break;
      // case 'email': 
      //   errors.email = 
      //     validEmailRegex.test(value)
      //       ? ''
      //       : 'Email is not valid!';
      //   break;
      case 'password': 
        errors.password = 
          value.length < 5
            ? 'Password must be 5 characters long!'
            : '';
        break;
      // case 'branch': 
      //   errors.branch = 
      //     value.length <= 0
      //       ? 'Branch name is required'
      //       : '';
      //   break;
    case 'type': 
        errors.type = 
          value.length <= 0
            ? 'Employee type is required'
            : '';
        break;
        // case 'address': 
        //   errors.address = 
        //     value.length <= 0
        //       ? 'Address is required'
        //       : '';
        //   break;
      default:
        break;
    }

    this.setState({errors, [name]: value});
  }

  handleSubmit = (event) => {
    this.setState({ _notificationSystem: this.refs.notificationSystem, isFormSubmit: true });
    var _notificationSystem = this.refs.notificationSystem;
    event.preventDefault();

    if(this.state.isOtpAccess && !this.state.phone){
      _notificationSystem.addNotification({
        title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
              Phone number required for OTP access
            </div>
          ),
          level: 'error',
          position: "tr",
          autoDismiss: 15
        });
    } else if(validateForm(this.state.errors)) {
      
      var bodyFormData = new FormData();
      bodyFormData.set('firstname', this.state.firstname);
      bodyFormData.set('lastname', this.state.lastname);
      if(this.state.branch){
        bodyFormData.set('branch', this.state.branch);
      }
      if(this.state.phone){
        bodyFormData.set('phone', this.state.phone);
      }
      if(this.state.address){
        bodyFormData.set('address', this.state.address);
      }
      if(this.state.email){
        bodyFormData.set('email', this.state.email);
      }
      bodyFormData.set('username', this.state.username);
      bodyFormData.set('password', this.state.password);
      bodyFormData.set('type', this.state.type);
      bodyFormData.set('isOTPLogin', this.state.isOtpAccess);

      bodyFormData.append('image', this.state.image)
      axios({
        method: 'POST',
        url: apiUrls.EMPLOYEE,
        data: bodyFormData,
        headers: {
          'Content-Type': 'multipart/form-data',
          Authorization: authHeader()
        }
      }).then(result => {
        if (result.status === 201) {

        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-check" />,
            message: (
              <div>
                'Employee created.'
              </div>
            ),
            level: 'success',
            position: "tr",
            autoDismiss: 15
          });

        }
      }).catch(e => {
        console.log(e)
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
            message: (
              <div>
              {(e.response) ? e.response.data.message : 'Something went wrong!'}
              </div>
            ),
            level: 'error',
            position: "tr",
            autoDismiss: 15
          });
      });
    }
  }

  fileChangedHandler = (event) => {
    let errors = this.state.errors;
    let curr = this;

    if(event.target.files[0]){
      if(fileMaxLimit(event)){
        errors.image = '';
        new ImageCompressor(event.target.files[0], {
          quality: 0.6,
          success(result) {
            var file = new File([result], result.name, {type: result.type});
            curr.setState({image: file, errors});
          },
          error(e) {
            console.log(e.message);
          },
        });
      } else{
        errors.image = 'File size should be maximum 5MB';
        this.setState({errors});
      }
    } else {
      errors.image = '';
      this.setState({image: '', errors});
    }
  };

  render() {
    const { errors, isFormSubmit } = this.state;

    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />
        <Grid fluid>
          <Row>
            <Col md={8}>
            <Card
                title="Create a employee"
                content={
                  <form onSubmit={this.handleSubmit} noValidate>
                    <div className="form-group">
                      <label>Firstname</label>
                      <input type="text" className="form-control" name="firstname" placeholder="Enter firstname"  onChange={this.handleChange} noValidate />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.firstname}</p>
                        )
                      }
                    </div>

                    <div className="form-group">
                      <label>Lastname</label>
                      <input type="text" className="form-control" name="lastname" placeholder="Enter lastname"  onChange={this.handleChange} noValidate />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.lastname}</p>
                        )
                      }
                    </div>

                    <div className="form-group">
                      <label>Phone</label>
                      <input type="text" maxLength="10" className="form-control" name="phone" placeholder="Enter phone"  onChange={this.handleChange} noValidate />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.phone}</p>
                        )
                      }
                    </div>

                    <div className="form-group">
                      <label>Address</label>
                      <textarea className="form-control" name="address" placeholder="Address of the employee" onChange={this.handleChange}></textarea>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.address}</p>
                        )
                      }
                    </div>

                    <div className="form-group">
                      <label>Email</label>
                      <input type="text" className="form-control" name="email" placeholder="Enter email"  onChange={this.handleChange} noValidate />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.email}</p>
                        )
                      }
                    </div>
                    
                    <div className="form-group">
                      <label>Branch</label>
                      <select name="branch" className="form-control" onChange={this.handleChange}>
                      <option value="">Select Branch</option>

                      {this.state.stores.length > 0 && this.state.stores.map((type) => {
                        return (
                            <option value={type._id} key={type._id}>{type.branch}</option>
                          )
                        })}
                      </select>                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.branch}</p>
                        )
                      }
                    </div>

                    <div className="form-group">
                      <label>Username</label>
                      <input type="text" className="form-control" name="username" placeholder="Enter username"  onChange={this.handleChange} noValidate />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.username}</p>
                        )
                      }
                    </div>
                    <div className="form-group">
                      <label>Password</label>
                      <input type="password" className="form-control" name="password" placeholder="Enter password"  onChange={this.handleChange} noValidate />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.password}</p>
                        )
                      }
                    </div>
                    
                    <div className="form-group">
                      <label>Employee Type</label>
                      <select name="type" className="form-control" onChange={this.handleChange}>
                      <option value="">Select Employee Type</option>
                      {EmployeeTypes.map((type) => {
                        return (
                            <option value={type.id} key={type.id}>{type.name}</option>
                          )
                        })}
                      </select>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.type}</p>
                        )
                      }
                    </div>

                    {/* <div className="form-group checkbox-access">  
                      <label>OTP Login Access</label>
                      <input type="checkbox" className="form-control"  name="isOTPLogin" onClick={() => {
                        this.setState({
                          isOtpAccess: !this.state.isOtpAccess
                        })
                      }}  noValidate />
                    </div> */}

                    <div className="form-group">
                      <label>Photo</label>
                      <input type="file" className="form-control" name="image"  onChange={this.fileChangedHandler}/>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.image}</p>
                        )
                      }
                    </div>


                    <Link className="mgr-5 btn btn-default" to="/admin/employees">Cancel</Link>

                    <Button bsStyle="info"  type="submit">
                      Create
                    </Button>

                    <div className="clearfix" />
                  </form>
                }
              />
            </Col>
          </Row>
        </Grid>
      </div>
    );
  }
}

export default EmployeeCreate;
