
import React, { Component } from "react";
import { FormGroup, FormControl, Button, Row, Col, Table } from "react-bootstrap";
import axios from 'axios';
import NotificationSystem from "react-notification-system";
import * as moment from 'moment';
import { ApiUrlHost, apiUrls } from '../../configs/configs';
import { authHeader } from '../../configs/helpers';
import { style } from "../../variables/Variables.jsx";
import Modal from 'react-modal';
import './custom.css';

const customStyles = {
  content: {
    top: '50%',
    left: '50%',
    right: 'auto',
    bottom: 'auto',
    // marginRight: '-50%',
    transform: 'translate(-50%, -50%)',
    height: '340px', // <-- This sets the height
    overlfow: 'scroll', // <-- This tells the modal to scrol
    minWidth: '30%'
  },
};

class LiveStockOrderPayment extends Component {
  constructor(props) {
    super(props);
    this.state = {
      months: [2020, 2021, 2022, 2023, 2024, 2025],
      monthsNames: moment.monthsShort(),
      paymentInfoByMonth: [],
      currentYear: new Date().getFullYear(),
      currentMonth: null,
      branch: '',
      branches: [],
      modalOpen: false,
      popupData: null,
      balanceAmt: ''
    }
  }

  componentWillMount() {
    this.getAllBranchEmployees();
  }

  getYearlyOrderDetailsByBranch() {
    let params = {};
    if (this.state.branch) {
      params.branch = this.state.branch;
    }
    if (this.state.currentYear) {
      params.year = this.state.currentYear;
    }
    if (this.state.currentMonth) {
      params.month = this.state.currentMonth;
    }

    axios({
      method: 'GET',
      url: apiUrls.PAYMENTS.list,
      headers: {
        Authorization: authHeader()
      },
      params: params
    }).then(result => {
      if (result.status === 200 && result.data.data) {
        this.setState({
          paymentInfoByMonth: result.data.data,
        });

      } else {
        this.setState({
          paymentInfoByMonth: [],
        });
      }
    }).catch(e => {
      this.setState({
        paymentInfoByMonth: []
      });
    });
  }

  getAllBranchEmployees() {
    axios({
      method: 'GET',
      url: apiUrls.BRANCH_EMPLOYEE_LIST,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200 && result.data.data) {
        this.setState({
          branches: result.data.data,
        });
      } else {
        this.setState({
          branches: [],
        });
      }
    }).catch(e => {
      this.setState({
        branches: []
      });
    });
  }

  setCurrentYear = (year) => {
    this.setState({
      currentYear: year
    }, () => {
      this.getYearlyOrderDetailsByBranch()
    })
  };

  setCurrentMonth = (month) => {
    this.setState({
      currentMonth: month
    }, () => {
      this.getYearlyOrderDetailsByBranch()
    })
  };

  setBranch = (branch) => {
    this.setState({
      branch: branch
    }, () => {
      this.getYearlyOrderDetailsByBranch()
    })
  }

  openPopup = (month, costL, costS, payInfo, branch) => {
    this.setState({
      modalOpen: true,
      popupData: {
        month: month,
        branch: branch,
        monthName: moment(month, 'M').format('MMMM'),
        liveCost: costL,
        stockCost: costS,
        toPay: payInfo ? payInfo.balanceAmount : costS + costL
      }
    })
  }

  closePopup = () => {
    this.setState({
      modalOpen: false,
      popupData: null
    })
  }

  getTotalLiveOrder(orders) {
    let total = 0;
    if (orders && orders.length > 0) {
      orders.forEach(order => {
        total = total + order.length;
      });
    }
    return total;
  }

  getTotalStockOrder(orders) {
    let total = 0;
    if (orders && orders.length > 0) {
      orders.forEach(order => {
        total = total + order.length;
      });
    }
    return total;
  }

  getTotalCostOfLiveOrder(orders) {
    let total = 0;

    if (orders && orders.length > 0) {
      orders.forEach(order => {
        order.forEach(orderItem => {
          total = parseFloat(total) + parseFloat(orderItem.sendTotal)
        })
      });
    }
    return total;
  }

  getTotalCostOfStockOrder(orders) {
    let total = 0;
    if (orders && orders.length > 0) {
      orders.forEach(order => {
        order.forEach(orderItem => {
          total = parseFloat(total) + parseFloat(orderItem.sendTotal)
        })
      });
    }
    return total;
  }

  payNow = () => {
    this.setState({ _notificationSystem: this.refs.notificationSystem });
    var _notificationSystem = this.refs.notificationSystem;
    if (this.state.balanceAmt && this.state.balanceAmt > 0) {

      const sendData = {
        year: this.state.currentYear,
        totalcost: this.state.popupData ? this.state.popupData.stockCost + this.state.popupData.liveCost : null,
        branch: this.state.popupData ? this.state.popupData.branch : null,
        month: this.state.popupData ? this.state.popupData.month : null,
        payment: this.state.balanceAmt
      }

      axios({
        method: 'POST',
        url: apiUrls.PAYMENTS.pay,
        data: sendData,
        headers: {
          'Content-Type': 'application/json',
          Authorization: authHeader()
        }
      }).then(result => {
        if (result.status === 200) {
          this.getYearlyOrderDetailsByBranch();
          this.closePopup();
        }
      }).catch(e => {
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
              {(e.response) ? e.response.data.message : 'Something went wrong!'}
            </div>
          ),
          level: 'error',
          position: "tr",
          autoDismiss: 15
        });
      });
    } else {
      _notificationSystem.addNotification({
        title: <span data-notify="icon" className="pe-7s-close-circle" />,
        message: (
          <div>
            {'Amount should required'}
          </div>
        ),
        level: 'error',
        position: "tr",
        autoDismiss: 15
      });
    }
  }

  getAllSalesTotal(data){
    let total = 0;
    data.forEach(item => {
      if(item.liveOrders){
        item.liveOrders.forEach(order => {
          order.forEach(orderItem => {
            total = parseFloat(total) + parseFloat(orderItem.sendTotal)
          })
        })
      }
      if(item.stockOrders){
        item.stockOrders.forEach(orderstock => {
          orderstock.forEach(orderItem => {
            total = parseFloat(total) + parseFloat(orderItem.sendTotal)
          })
        })
      }
    })
    return total;
  }

  getAllSalesIncome(data){
    let total = 0;
    data.forEach(item => {
      if(item.paymentDetails){
        const received = item.paymentDetails.totalcost - item.paymentDetails.balanceAmount;
        total = parseFloat(total) + parseFloat(received)
      }
    })
    return total;
  }

  render() {
    return (
      <div className="content bg-white">
        <NotificationSystem ref="notificationSystem" style={style} />

        <Modal
          isOpen={this.state.modalOpen}
          ariaHideApp={false}
          style={customStyles}
          contentLabel="Payment Modal"
        >
          <h3 className="pop-up-head">{this.state.popupData && this.state.popupData.monthName ? this.state.popupData.monthName : '...'} Payment</h3>
          <div className="pay-info">
            <p>Cost of Live orders: ₹ {this.state.popupData && this.state.popupData.liveCost ? this.state.popupData.liveCost : '0'}</p>
            <p>Cost of Stock orders: ₹ {this.state.popupData && this.state.popupData.stockCost ? this.state.popupData.stockCost : '0'}</p>
            <p>Total Sales: ₹ {this.state.popupData ? this.state.popupData.stockCost + this.state.popupData.liveCost : '0'}</p>
            <p>Amount to pay: ₹  {this.state.popupData ? this.state.popupData.toPay : '0'}</p>
            <input type="text" className="pay-amt" onChange={(e) => this.setState({ balanceAmt: e.target.value })} placeholder="Enter the amount" />
          </div>
          <div className="pop-foot">
            <button className="pay-o-close-btn" onClick={() => this.closePopup()}>Close</button>
            <button className="pay-o-ok-btn" onClick={() => this.payNow()}>Pay</button>
          </div>

        </Modal>

        <Row>
          <Col md={3}>
            <FormGroup>
              <FormControl type="text"
                componentClass="select"
                inputRef={(ref) => { this.branch = ref }}
                onChange={() => this.setBranch(this.branch.value)}
              >
                <option value="">Choose Branch</option>
                <option value="">All</option>

                {this.state.branches.map((store) => {
                  return (
                    <option value={store._id} key={store._id}>{store.firstname}</option>
                  )
                })}
              </FormControl>
            </FormGroup>
          </Col>
          <Col md={3}>
            <FormGroup>
              <FormControl type="text"
                componentClass="select"
                inputRef={(ref) => { this.yearRef = ref }}
                onChange={() => this.setCurrentYear(this.yearRef.value)}
              >
                <option value="">Choose Year</option>
                <option value="">All</option>

                {this.state.months.map((year) => {
                  return (
                    <option value={year} key={year}>{year}</option>
                  )
                })}
              </FormControl>
            </FormGroup>
          </Col>
        </Row>

        <Row>
          <Col md={12}>
            <div className="years-block">
              <p onClick={() => this.setCurrentMonth('')}>{'All'}</p>
              {this.state.monthsNames.map((month, key) => {
                return <p key={key} onClick={() => this.setCurrentMonth(key + 1)}>{month}</p>
              })}</div>
          </Col>
        </Row>
        {this.state.paymentInfoByMonth.length > 0 && (
          this.state.paymentInfoByMonth.map((monthData) => {
            return (<div className="month-item-coll" key={monthData.branch + monthData.month}>
              <Row>
                <Col md={12} className={'month-item'}>
                  <Row>
                    <Col md={2}>
                      <p className="branch-head">{monthData.branchDetail ? monthData.branchDetail.firstname : 'N/A'}</p>
                      <p className="text-center">{moment(monthData.month, 'M').format('MMMM')}</p>
                    </Col>
                  </Row>
                  <Row>
                    <Col md={2}>

                    </Col>
                    <Col md={8}>
                      <p>Total Live orders: {this.getTotalLiveOrder(monthData.liveOrders)} | Total Stock Orders : {this.getTotalStockOrder(monthData.stockOrders)} | Cost of Stock orders: ₹ {this.getTotalCostOfStockOrder(monthData.stockOrders)} | Cost of Live orders: ₹ {this.getTotalCostOfLiveOrder(monthData.liveOrders)}</p>
                      <p>Total Sales: ₹ {this.getTotalCostOfStockOrder(monthData.stockOrders) + this.getTotalCostOfLiveOrder(monthData.liveOrders)} </p>
                      <p>Received: ₹ {monthData.paymentDetails ? monthData.paymentDetails.totalcost - monthData.paymentDetails.balanceAmount : '0'}</p>
                      <p>Yet to receive: ₹ {monthData.paymentDetails ? monthData.paymentDetails.balanceAmount : this.getTotalCostOfStockOrder(monthData.stockOrders) + this.getTotalCostOfLiveOrder(monthData.liveOrders)}</p>
                    </Col>
                    {(!monthData.paymentDetails || (monthData.paymentDetails && monthData.paymentDetails.balanceAmount > 0)) && (
                      <Col md={2}>
                        <button className="btn-pay-o" onClick={() => this.openPopup(monthData.month, this.getTotalCostOfLiveOrder(monthData.liveOrders), this.getTotalCostOfStockOrder(monthData.stockOrders), monthData.paymentDetails, monthData.branch)}>Pay Now</button>
                      </Col>
                    )}

                  </Row>
                </Col>
              </Row>
            </div>)
          })
        )}
        {this.state.paymentInfoByMonth.length > 0 && (
          <div className={'total-stock-detail'}>
            <Row>
              <Col md={12} >
                <p>Total Sales: ₹ {this.getAllSalesTotal(this.state.paymentInfoByMonth)}</p>
                <p>Total Payment Received: ₹ {this.getAllSalesIncome(this.state.paymentInfoByMonth)}</p>
              </Col>
            </Row>
          </div>

        )}
      </div>
    );
  }
}

export default LiveStockOrderPayment;
