import React, { Component } from "react";
import { Link } from "react-router-dom";
import { FormGroup, FormControl, Row, Col, Button } from "react-bootstrap";
import { Multiselect } from "multiselect-react-dropdown";
import { Range, getTrackBackground } from "react-range";
const STEP = 10;
const MIN = 0;
const MAX = 50000;

const WEIGHT_STEP = 10;
const WEIGHT_MIN = 0;
const WEIGHT_MAX = 500;

export class Card extends Component {
  categorySelection(selectedList) {
    const tempSelected = [];
    selectedList.forEach((item) => {
      tempSelected.push(item._id);
    });
    this.props.getAllProductsByCategory(tempSelected);
  }
  state = {
    values: [MAX],
    weightValues: [WEIGHT_MAX],
  };
  productSelections(selectedList) {
    const tempSelected = [];
    selectedList.forEach((item) => {
      tempSelected.push(item._id);
    });
    this.props.getAllProductsOrders(tempSelected);
  }
  render() {
    return (
      <div className={"card" + (this.props.plain ? " card-plain" : "")}>
        <div className={"header" + (this.props.hCenter ? " text-center" : "")}>
          <Row>
            <Col
              md={
                this.props.empSearch ||
                this.props.productSearch ||
                this.props.orderSearch
                  ? 12
                  : 12
              }
            >
              {this.props.search && (
                <Row>
                  <Col
                    md={
                      this.props.empSearch || this.props.productSearch ? 2 : 8
                    }
                  >
                    <FormGroup>
                      <FormControl
                        type="text"
                        inputRef={(ref) => {
                          this.input = ref;
                        }}
                        placeholder={this.props.searchplaceholder}
                        onChange={() => this.props.searchCall(this.input.value)}
                      />
                    </FormGroup>
                  </Col>
                  {this.props.empSearch && (
                    <Col md={4}>
                      <FormGroup>
                        <FormControl
                          type="text"
                          componentClass="select"
                          inputRef={(ref) => {
                            this.branch = ref;
                          }}
                          onChange={() =>
                            this.props.searchCallByBrnach(this.branch.value)
                          }
                        >
                          <option value="">Branch</option>
                          {this.props.storesCol.map((store) => {
                            return (
                              <option value={store._id} key={store._id}>
                                {store.branch}
                              </option>
                            );
                          })}
                        </FormControl>
                      </FormGroup>
                    </Col>
                  )}

                  {this.props.empSearch && (
                    <Col md={2}>
                      <FormGroup>
                        <FormControl
                          type="text"
                          componentClass="select"
                          inputRef={(ref) => {
                            this.type = ref;
                          }}
                          onChange={() =>
                            this.props.searchCallByType(this.type.value)
                          }
                        >
                          <option value="">Type</option>
                          {this.props.typeOfemp.map((type) => {
                            return (
                              <option value={type.id} key={type.id}>
                                {type.name}
                              </option>
                            );
                          })}
                        </FormControl>
                      </FormGroup>
                    </Col>
                  )}

                  {this.props.productSearch && (
                    <Col md={4}>
                      <FormGroup>
                        <FormControl
                          type="text"
                          componentClass="select"
                          inputRef={(ref) => {
                            this.branch = ref;
                          }}
                          onChange={() =>
                            this.props.searchCallByCate(this.branch.value)
                          }
                        >
                          <option value="">Category</option>
                          {this.props.catCollection.map((store) => {
                            return (
                              <option value={store._id} key={store._id}>
                                {store.name}
                              </option>
                            );
                          })}
                        </FormControl>
                      </FormGroup>
                    </Col>
                  )}
                  {this.props.productSearch && (
                    <Col md={2}>
                      <FormGroup>
                        <FormControl
                          type="text"
                          componentClass="select"
                          inputRef={(ref) => {
                            this.type = ref;
                          }}
                          onChange={() =>
                            this.props.searchCallByAlbum(this.type.value)
                          }
                        >
                          <option value="">Album</option>
                          {this.props.albumCollection.map((type) => {
                            return (
                              <option value={type._id} key={type._id}>
                                {type.name}
                              </option>
                            );
                          })}
                        </FormControl>
                      </FormGroup>
                    </Col>
                  )}
                  {this.props.productUnits &&
                    this.props.productUnits.length > 0 && (
                      <Col md={2}>
                        <FormGroup>
                          <FormControl
                            type="text"
                            componentClass="select"
                            inputRef={(ref) => {
                              this.type = ref;
                            }}
                            onChange={() =>
                              this.props.searchCallByUnit(this.type.value)
                            }
                          >
                            <option value="">Unit</option>
                            {this.props.productUnits.map((type) => {
                              return (
                                <option value={type._id} key={type._id}>
                                  {type.name}
                                </option>
                              );
                            })}
                          </FormControl>
                        </FormGroup>
                      </Col>
                    )}
                  <Col md={2}>
                    <Link
                      className="btn btn-default"
                      to={this.props.createLink}
                    >
                      Add
                    </Link>
                  </Col>
                  {this.props.priceFilter && (
                    <Col
                      md={6}
                      style={{
                        background: "#f9f9f9",
                      }}
                    >
                      <div
                        style={{
                          display: "flex",
                          justifyContent: "center",
                          flexWrap: "wrap",
                          margin: "10px 30px",
                        }}
                      >
                        <label>Price Range</label>
                        <Range
                          values={this.state.values}
                          step={STEP}
                          min={MIN}
                          max={MAX}
                          onChange={(values) => {
                            this.setState({ values }, () => {
                              this.props.applyPrice(values);
                            });
                          }}
                          renderTrack={({ props, children }) => (
                            <div
                              onMouseDown={props.onMouseDown}
                              onTouchStart={props.onTouchStart}
                              style={{
                                ...props.style,
                                height: "36px",
                                display: "flex",
                                width: "100%",
                              }}
                            >
                              <div
                                ref={props.ref}
                                style={{
                                  height: "5px",
                                  width: "100%",
                                  borderRadius: "4px",
                                  background: getTrackBackground({
                                    values: this.state.values,
                                    colors: ["#548BF4", "#ccc"],
                                    min: MIN,
                                    max: MAX,
                                  }),
                                  alignSelf: "center",
                                }}
                              >
                                {children}
                              </div>
                            </div>
                          )}
                          renderThumb={({ props, isDragged }) => (
                            <div
                              {...props}
                              style={{
                                ...props.style,
                                height: "42px",
                                width: "42px",
                                borderRadius: "4px",
                                backgroundColor: "#FFF",
                                display: "flex",
                                justifyContent: "center",
                                alignItems: "center",
                                boxShadow: "0px 2px 6px #AAA",
                              }}
                            >
                              <div
                                style={{
                                  height: "16px",
                                  width: "5px",
                                  backgroundColor: isDragged
                                    ? "#548BF4"
                                    : "#CCC",
                                }}
                              />
                            </div>
                          )}
                        />
                        <output id="output">₹ {this.state.values[0]}</output>
                      </div>
                    </Col>
                  )}
                  {this.props.weightFilter && (
                    <Col
                      md={6}
                      style={{
                        background: "#f9f9f9",
                      }}
                    >
                      <div
                        style={{
                          display: "flex",
                          justifyContent: "center",
                          flexWrap: "wrap",
                          margin: "10px 30px",
                        }}
                      >
                        <label>Weight</label>
                        <Range
                          values={this.state.weightValues}
                          step={WEIGHT_STEP}
                          min={WEIGHT_MIN}
                          max={WEIGHT_MAX}
                          onChange={(weightValues) => {
                            this.setState({ weightValues }, () => {
                              this.props.applyWeightChange(weightValues);
                            });
                          }}
                          renderTrack={({ props, children }) => (
                            <div
                              onMouseDown={props.onMouseDown}
                              onTouchStart={props.onTouchStart}
                              style={{
                                ...props.style,
                                height: "36px",
                                display: "flex",
                                width: "100%",
                              }}
                            >
                              <div
                                ref={props.ref}
                                style={{
                                  height: "5px",
                                  width: "100%",
                                  borderRadius: "4px",
                                  background: getTrackBackground({
                                    values: this.state.values,
                                    colors: ["#548BF4", "#ccc"],
                                    min: MIN,
                                    max: MAX,
                                  }),
                                  alignSelf: "center",
                                }}
                              >
                                {children}
                              </div>
                            </div>
                          )}
                          renderThumb={({ props, isDragged }) => (
                            <div
                              {...props}
                              style={{
                                ...props.style,
                                height: "42px",
                                width: "42px",
                                borderRadius: "4px",
                                backgroundColor: "#FFF",
                                display: "flex",
                                justifyContent: "center",
                                alignItems: "center",
                                boxShadow: "0px 2px 6px #AAA",
                              }}
                            >
                              <div
                                style={{
                                  height: "16px",
                                  width: "5px",
                                  backgroundColor: isDragged
                                    ? "#548BF4"
                                    : "#CCC",
                                }}
                              />
                            </div>
                          )}
                        />
                        <output id="output">
                          {" "}
                          {this.state.weightValues[0]} Kg
                        </output>
                      </div>
                    </Col>
                  )}
                </Row>
              )}

              {this.props.orderSearch && !this.props.noStatusSearch && (
                <Col md={2}>
                  <FormGroup>
                    <label>Status</label>

                    <FormControl
                      type="text"
                      componentClass="select"
                      inputRef={(ref) => {
                        this.statusOrder = ref;
                      }}
                      onChange={() =>
                        this.props.searchCallStatus(this.statusOrder.value)
                      }
                    >
                      <option value="">All</option>
                      <option value="1">Ordered</option>
                      <option value="2">Cancelled</option>
                      <option value="4">Preparing</option>
                      <option value="5">Ready</option>
                      <option value="6">Picked</option>
                      <option value="7">Delivered</option>
                      <option value="8">Not Delivered</option>
                      <option value="3">Completed</option>
                    </FormControl>
                  </FormGroup>
                </Col>
              )}

              {this.props.branchHeadSearch && (
                <Col md={3}>
                  <FormGroup>
                    <FormControl
                      type="text"
                      componentClass="select"
                      inputRef={(ref) => {
                        this.branchHead = ref;
                      }}
                      onChange={() =>
                        this.props.searchByBranchEmp(this.branchHead.value)
                      }
                    >
                      <option value="">All Branch</option>
                      {this.props.empList.map((store) => {
                        return (
                          <option value={store._id} key={store._id}>
                            {store.firstname}
                          </option>
                        );
                      })}
                    </FormControl>
                  </FormGroup>
                </Col>
              )}
              {this.props.branchHeadSearch && (
                <Col md={3}>
                  <FormGroup>
                    <label>Category</label>

                    <FormControl
                      type="text"
                      componentClass="select"
                      inputRef={(ref) => {
                        this.branchHeadCategory = ref;
                      }}
                      onChange={() =>
                        this.props.searchCallByCategory(
                          this.branchHeadCategory.value
                        )
                      }
                    >
                      <option value="">All Category</option>
                      {this.props.categoryCol.map((store) => {
                        return (
                          <option value={store._id} key={store._id}>
                            {store.name}
                          </option>
                        );
                      })}
                    </FormControl>
                  </FormGroup>
                </Col>
              )}
              {this.props.orderSearch && !this.props.noStatusSearch && (
                <Col md={2}>
                  <FormGroup>
                    <label>Branch</label>

                    <FormControl
                      type="text"
                      componentClass="select"
                      inputRef={(ref) => {
                        this.branchOrder = ref;
                      }}
                      onChange={() =>
                        this.props.searchCallBranch(this.branchOrder.value)
                      }
                    >
                      <option value="">All</option>
                      {this.props.branchesList.map((store) => {
                        return (
                          <option value={store._id} key={store._id}>
                            {store.branch}
                          </option>
                        );
                      })}
                    </FormControl>
                  </FormGroup>
                </Col>
              )}

              {this.props.waiterSearch && !this.props.noStatusSearch && (
                <Col md={2}>
                  <FormGroup>
                    <label>Waiter</label>

                    <FormControl
                      type="text"
                      componentClass="select"
                      inputRef={(ref) => {
                        this.waiterOrder = ref;
                      }}
                      onChange={() =>
                        this.props.searchCallWaiter(this.waiterOrder.value)
                      }
                    >
                      <option value="">All</option>
                      {this.props.waiterList.map((store) => {
                        return (
                          <option value={store._id} key={`waiter-${store._id}`}>
                            {store.firstname}
                          </option>
                        );
                      })}
                    </FormControl>
                  </FormGroup>
                </Col>
              )}

              {this.props.orderSearch && (
                <Col md={3}>
                  <FormGroup>
                    <label>
                      Order Date From 
                      {this.branchDateOrder && this.branchDateOrder.value && (
                        <span
                          style={{ color: "tomato" }}
                          onClick={() => {
                            this.branchDateOrder.value = "";
                            this.props.searchByDate();
                          }}
                        >
                          {" "}
                          <i className="fa fa-times-circle fa-2x" />
                        </span>
                      )}
                    </label>

                    <FormControl
                      type="date"
                      defaultValue={this.props.fromDate}
                      inputRef={(ref) => {
                        this.branchDateOrder = ref;
                      }}
                      onChange={() =>
                        this.props.searchByDate(this.branchDateOrder.value)
                      }
                    ></FormControl>
                  </FormGroup>
                </Col>
              )}
              {this.props.orderSearch && (
                <Col md={3}>
                  <FormGroup>
                    <label>
                      Order Date To
                      {this.branchDateOrderTo && this.branchDateOrderTo.value && (
                        <span
                          style={{ color: "tomato" }}
                          onClick={() => {
                            this.branchDateOrderTo.value = "";
                            this.props.searchByDateUpTo();
                          }}
                        >
                          {" "}
                          <i className="fa fa-times-circle fa-2x" />
                        </span>
                      )}
                    </label>

                    <FormControl
                      type="date"
                      inputRef={(ref) => {
                        this.branchDateOrderTo = ref;
                      }}
                      onChange={() =>
                        this.props.searchByDateUpTo(
                          this.branchDateOrderTo.value
                        )
                      }
                    ></FormControl>
                  </FormGroup>
                </Col>
              )}

              {this.props.orderSearch && !this.props.noStatusSearch && (
                <Col md={3}>
                  <FormGroup>
                    <label>
                      Delivery From
                      {this.branchDelDateOrder &&
                        this.branchDelDateOrder.value && (
                          <span
                            style={{ color: "tomato" }}
                            onClick={() => {
                              this.branchDelDateOrder.value = "";
                              this.props.searchByDeliveryDate();
                            }}
                          >
                            {" "}
                            <i className="fa fa-times-circle fa-2x" />
                          </span>
                        )}
                    </label>

                    <FormControl
                      type="date"
                      inputRef={(ref) => {
                        this.branchDelDateOrder = ref;
                      }}
                      onChange={() =>
                        this.props.searchByDeliveryDate(
                          this.branchDelDateOrder.value
                        )
                      }
                    ></FormControl>
                  </FormGroup>
                </Col>
              )}
              {this.props.orderSearch && !this.props.noStatusSearch && (
                <Col md={3}>
                  <FormGroup>
                    <label>
                      Delivery Date To
                      {this.branchDelDateOrderTo &&
                        this.branchDelDateOrderTo.value && (
                          <span
                            style={{ color: "tomato" }}
                            onClick={() => {
                              this.branchDelDateOrderTo.value = "";
                              this.props.searchByDeliveryDateTo();
                            }}
                          >
                            {" "}
                            <i className="fa fa-times-circle fa-2x" />
                          </span>
                        )}
                    </label>

                    <FormControl
                      type="date"
                      inputRef={(ref) => {
                        this.branchDelDateOrderTo = ref;
                      }}
                      onChange={() =>
                        this.props.searchByDeliveryDateTo(
                          this.branchDelDateOrderTo.value
                        )
                      }
                    ></FormControl>
                  </FormGroup>
                </Col>
              )}

              <Row className="mar0px">
                {this.props.orderSearch && (
                  <Col md={12}>
                    <FormGroup>
                      <label>Category </label>
                      <Multiselect
                        options={this.props.allProductCategories} // Options to display in the dropdown
                        // selectedValues={this.state.selectedValue} // Preselected value to persist in dropdown
                        onSelect={this.categorySelection.bind(this)} // Function will trigger on select event
                        onRemove={this.categorySelection.bind(this)} // Function will trigger on remove event
                        displayValue="name" // Property name to display in the dropdown options
                      />
                    </FormGroup>
                  </Col>
                )}

                {this.props.orderSearch && (
                  <Col md={12}>
                    <FormGroup>
                      <label>Products </label>
                      <Multiselect
                        options={this.props.allProducts} // Options to display in the dropdown
                        // selectedValues={this.props.selectedProducts} // Preselected value to persist in dropdown
                        onSelect={this.productSelections.bind(this)} // Function will trigger on select event
                        onRemove={this.productSelections.bind(this)} // Function will trigger on remove event
                        displayValue="name" // Property name to display in the dropdown options
                      />
                    </FormGroup>
                  </Col>
                )}
              </Row>

              {/* {this.props.orderSearch && <Col md={2}>
                <Button onClick={this.props.downloadReport} className="mar-t-25px">Download</Button>
              </Col>} */}
            </Col>
          </Row>
        </div>
        <div
          className={
            "content" +
            (this.props.ctAllIcons ? " all-icons" : "") +
            (this.props.ctTableFullWidth ? " table-full-width" : "") +
            (this.props.ctTableResponsive ? " table-responsive" : "") +
            (this.props.ctTableUpgrade ? " table-upgrade" : "")
          }
        >
          {this.props.content}

          <div className="footer text-center">
            {this.props.legend}
            {this.props.stats != null ? <hr /> : ""}
            <div className="stats">
              <i className={this.props.statsIcon} /> {this.props.stats}
            </div>

            {/* {
              (!this.props.paginateContent && this.props.pagination && this.props.totalPages > 0) && (

                // <div className="page-btn-wrap">
                //   <button className="btn-navg" onClick={()=>this.props.prev()}>Prev</button>

                //   {
                //     [...Array(this.props.totalPages)].map((e,index) => {
                //       return (
                //         <button key={index + '-' + Math.random()} className={this.props.currentPage == (index) ? "page-btns active" : "page-btns"} onClick={()=>this.props.processPagination(index)}>{index + 1}</button>
                //       )
                //     })
                //   }
                //   <button className="btn-navg" onClick={()=>this.props.next()}>Next</button>
                // </div>
                <ReactPaginate
                  previousLabel={'previous'}
                  initialPage={this.props.currentPage}
                  nextLabel={'next'}
                  breakLabel={'...'}
                  breakClassName={'break-me'}
                  pageCount={this.props.totalPages}
                  marginPagesDisplayed={2}
                  pageRangeDisplayed={5}
                  onPageChange={(index) => this.props.processPagination(index.selected)}
                  containerClassName={'pagination'}
                  subContainerClassName={'pages pagination'}
                  activeClassName={'active'}
                />


              )
            } */}
          </div>
        </div>
      </div>
    );
  }
}

export default Card;
