
import React, { Component } from "react";
import { Grid, Row, Col } from "react-bootstrap";
import { Link } from "react-router-dom";
import NotificationSystem from "react-notification-system";
import axios from 'axios';

import { style } from "../../variables/Variables.jsx";
import { Card } from "components/Card/Card.jsx";
import Button from "components/CustomButton/CustomButton.jsx";
import '../../assets/css/custom.css';
import { validateForm, authHeader } from '../../configs/helpers';
import { apiUrls } from '../../configs/configs';

class AlbumUpdate extends Component {
  constructor(props) {
    super(props);
    this.state = {
      cateId: this.props.match.params.id,
      isFormSubmit: false,
      name: '',
      isActive: true,
      errors: {
        name: '',
      }
    }
  }

  componentWillMount() {
    this.getData();
  }

  getData() {
    axios({
      method: 'GET',
      url: apiUrls.ALBUM + '/' + this.state.cateId,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        var storeData = result.data.data;
        this.setState({
          name: storeData.name,
          isActive: storeData.isActive
        })
      }
    }).catch(e => {
      console.log(e);
    });
  }

  handleChange = (event) => {
    event.preventDefault();
    const { name, value } = event.target;
    let errors = this.state.errors;

    switch (name) {
      case 'name':
        errors.name =
          value.length <= 0
            ? 'Album name is required'
            : '';
        break;
      default:
        break;
    }

    this.setState({ errors, [name]: value });
  }

  handleSubmit = (event) => {
    this.setState({ _notificationSystem: this.refs.notificationSystem, isFormSubmit: true });
    var _notificationSystem = this.refs.notificationSystem;
    event.preventDefault();

    if (validateForm(this.state.errors)) {
      var bodyFormData = { 'name': this.state.name, 'isActive': this.state.isActive };

      axios({
        method: 'PUT',
        url: apiUrls.ALBUM + '/' + this.state.cateId,
        data: bodyFormData,
        headers: {
          'Content-Type': 'application/json',
          Authorization: authHeader()
        }
      }).then(result => {
        if (result.status === 200) {

          _notificationSystem.addNotification({
            title: <span data-notify="icon" className="pe-7s-check" />,
            message: (
              <div>
                'Album updated.'
              </div>
            ),
            level: 'success',
            position: "tr",
            autoDismiss: 15
          });

        }
      }).catch(e => {
        console.log(e)
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
              {(e.response) ? e.response.data.message : 'Something went wrong!'}
            </div>
          ),
          level: 'error',
          position: "tr",
          autoDismiss: 15
        });
      });
    }
  }

  render() {
    const { errors, isFormSubmit } = this.state;

    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />
        <Grid fluid>
          <Row>
            <Col md={8}>
              <Card
                title="Update album"
                content={
                  <form onSubmit={this.handleSubmit} noValidate>

                    <div className="form-group">
                      <label>Name</label>
                      <input type="text" className="form-control" value={this.state.name} name="name" placeholder="Enter name" onChange={this.handleChange} noValidate />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.name}</p>
                        )
                      }
                    </div>

                    <div className="form-group checkbox-access">
                      <label>Enable Album</label>
                      <input type="checkbox" className="form-control" checked={this.state.isActive} name="isOTPLogin" onChange={() => {
                        this.setState({
                          isActive: !this.state.isActive
                        })
                      }} noValidate />
                    </div>

                    <Link className="mgr-5 btn btn-default" to="/admin/albums">Cancel</Link>

                    <Button bsStyle="info" type="submit">
                      Update
                    </Button>

                    <div className="clearfix" />
                  </form>
                }
              />
            </Col>
          </Row>
        </Grid>
      </div>
    );
  }
}

export default AlbumUpdate;
