
import React, { Component } from "react";
import { Grid, Row, Col, Table } from "react-bootstrap";
import { Link } from "react-router-dom";
import axios from 'axios';
import NotificationSystem from "react-notification-system";

import { style } from "../../variables/Variables.jsx";
import Card from "components/Card/Card.jsx";
import Button from "components/CustomButton/CustomButton.jsx";
import '../../assets/css/custom.css';
import { authHeader } from '../../configs/helpers';
import { apiUrls } from '../../configs/configs';
import InfiniteScroll from "react-infinite-scroll-component";

const mgr2 = {
  marginRight: 2
};

class ProductUnitList extends Component {
  constructor(props) {
    super(props);
    this.state = {
      collections: [],
      currentPage: 0,
      loading: true,
      totalRec: 0,
      searchStr: ''
    };
    this.paginationCall = this.paginationCall.bind(this);
    this.prevRecords = this.prevRecords.bind(this);
    this.nextRecords = this.nextRecords.bind(this);
    this.searchCall = this.searchCall.bind(this);
  }

  componentWillMount() {
    this.getAllUnits(null);
  }

  getAllUnits(search) {
    var _notificationSystem;

    var params = {
      page: this.state.currentPage
    };

    if (this.state.searchStr) {
      params.name = this.state.searchStr;
    }

    this.setState({ _notificationSystem: this.refs.notificationSystem }, () => {
      _notificationSystem = this.refs.notificationSystem;
    });
    this.setState({
      loading: true
    });

    axios({
      method: 'GET',
      url: apiUrls.PRODUCTUNITS,
      headers: {
        Authorization: authHeader()
      },
      params: params
    }).then(result => {
      if (result.status === 200 && result.data.data[0]) {
        var temp = this.state.collections;
        temp = temp.concat(result.data.data[0].paginatedResults);

        this.setState({
          collections: temp,
          totalRec: result.data.data[0].totalCount[0] ? result.data.data[0].totalCount[0].count : 0,
          loading: false
        });
      } else {
        this.setState({
          loading: false
        });
      }
    }).catch(e => {
      this.setState({
        loading: false
      });

      _notificationSystem.addNotification({
        title: <span data-notify="icon" className="pe-7s-close-circle" />,
        message: (
          <div>
            {(e.response) ? e.response.data.message : 'Something went wrong!'}
          </div>
        ),
        level: 'error',
        position: "tr",
        autoDismiss: 15
      });
    });
  }

  paginationCall(index) {
    this.setState({
      currentPage: index
    }, () => {
      this.getAllUnits(null);
    })
  }

  prevRecords() {
    if (this.state.currentPage > 0) {
      var c = this.state.currentPage;
      this.setState({
        currentPage: c - 1
      }, () => {
        this.getAllUnits(null);
      })
    }
  }

  nextRecords() {
    var c = this.state.currentPage;
    var totalPage = Math.ceil(this.state.totalRec / 5);
    if (c < totalPage - 1) {
      this.setState({
        currentPage: c + 1
      }, () => {
        this.getAllUnits(null);
      })
    }
  }

  searchCall(val) {
    this.setState({
      currentPage: 0,
      collections: [],
      searchStr: val
    }, () => {
      this.getAllUnits(null);
    })
  }

  deleteById(storeId) {
    if (window.confirm("Are sure to delete this unit!")) {

      var _notificationSystem;

      this.setState({ _notificationSystem: this.refs.notificationSystem }, () => {
        _notificationSystem = this.refs.notificationSystem;
      });

      axios({
        method: 'DELETE',
        url: apiUrls.PRODUCTUNITS + '/' + storeId,
        headers: {
          Authorization: authHeader()
        }
      }).then(result => {
        if (result.status === 200) {
          const temp = this.state.collections.filter(i => {
            return i._id != storeId
          });
          this.setState({
            collections: temp
          })
          // if (this.state.currentPage !== 0 && this.state.collections.length === 1) {
          //   this.setState({
          //     currentPage: this.state.currentPage - 1
          //   })
          // }
          // this.getAllUnits(null);

          _notificationSystem.addNotification({
            title: <span data-notify="icon" className="pe-7s-check" />,
            message: (
              <div>
                Product category deleted!.
              </div>
            ),
            level: 'success',
            position: "tr",
            autoDismiss: 15
          });
        }
      }).catch(e => {
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
              {(e.response) ? e.response.data.message : 'Something went wrong!'}
            </div>
          ),
          level: 'error',
          position: "tr",
          autoDismiss: 15
        });
      });
    }
  }

  render() {
    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />
        <Grid fluid>
          <Row>
            <Col md={12}>

              <Card
                title="Product Units"
                search={true}
                searchplaceholder="Search by name"
                ctTableFullWidth
                ctTableResponsive
                pagination={this.state.collections.length > 0 ? true : false}
                processPagination={this.paginationCall}
                prev={this.prevRecords}
                next={this.nextRecords}
                searchCall={this.searchCall}
                currentPage={this.state.currentPage}
                totalPages={Math.ceil(this.state.totalRec / 5)}
                createLink="/admin/product-unit/create"
                content={
                  <InfiniteScroll
                    dataLength={this.state.collections.length}
                    hasMore={true}
                    // loader={<h4>Loading...</h4>}
                    next={this.fetchMoreData}
                  >
                    {

                      <Table striped hover>
                        <thead>
                          <tr>
                            <th>Id</th>
                            <th>Name</th>
                            <th>Actions</th>
                          </tr>
                        </thead>
                        <tbody>
                          {(this.state.collections.length > 0) && (
                            this.state.collections.map((element, index) => {
                              return (
                                <tr key={index}>
                                  <td>{index + 1}</td>
                                  <td>{element.name}</td>
                                  <td>

                                    <Link className="mgr-5 btn btn-default" to={"/admin/product-unit/" + element._id + "/update"} type="button" >
                                      Edit
                                    </Link>

                                    <Button bsStyle="danger" onClick={() => this.deleteById(element._id)} type="button" style={mgr2}>
                                      Delete
                                    </Button>
                                  </td>
                                </tr>
                              );
                            })

                          )}

                          {(this.state.loading == false && this.state.collections.length == 0) && (
                            <tr>
                              <td colSpan={4} className="text-center">No Records Found</td>
                            </tr>
                          )}

                        </tbody>

                      </Table>
                    }
                  </InfiniteScroll>


                }

              />
            </Col>

          </Row>
        </Grid>
      </div>
    );
  }
}

export default ProductUnitList;
