import { EmployeeTypes } from './configs';

export const validateForm = (errors) => {
  let valid = true;
  Object.values(errors).forEach(
    (val) => val.length > 0 && (valid = false)
  );
  return valid;
}

export const validEmailRegex = RegExp(/^(([^<>()\[\]\.,;:\s@\"]+(\.[^<>()\[\]\.,;:\s@\"]+)*)|(\".+\"))@(([^<>()[\]\.,;:\s@\"]+\.)+[^<>()[\]\.,;:\s@\"]{2,})$/i);

export function authHeader() {
  // return authorization header with basic auth credentials
  let user = JSON.parse(localStorage.getItem('user'));
  if (user && user.token) {
    return 'Bearer ' + user.token;
  } else {
    return '';
  }
}

export function fileMaxLimit(file) {
  let file_size = file.target.files[0].size;
  if (file_size / 1024 > 5000) {
    return false;
  } else {
    return true;
  }
}


export function MultifileMaxLimit(file) {
  let file_size = file.size;
  if (file_size / 1024 > 5000) {
    return false;
  } else {
    return true;
  }
}
export function logout() {
  // remove user from local storage to log user out
  localStorage.removeItem('user');
}

export function getTypeName(type) {
  var name = '';
  EmployeeTypes.map((t) => {
    if (t.id == type) {
      name = t.name;
    }
  });
  return name;
}

export function getOrderStatusText(status) {
  let res = '-';
  if (status == 1) {
    res = 'Ordered'
  } else if (status == 2) {
    res = 'Cancel'
  } else if (status == 3) {
    res = 'Completed'
  } else if (status == 4) {
    res = 'Prepared'
  } else if (status == 5) {
    res = 'Ready'
  } else if (status == 6) {
    res = 'Picked'
  } else if (status == 7) {
    res = 'Delivered'
  } else if (status == 8) {
    res = 'Not delivered'
  }
  return res;
}


