    categorySelection(selectedList) {
        const tempSelected = [];
        selectedList.forEach(item => {
            tempSelected.push(item._id)
        })
        this.setState({
            selectedCategories: tempSelected
        })

        // if (tempSelected.indexOf(val) > -1) {
        //     const newChoice = tempSelected.filter(item => {
        //         return item != val;
        //     });
        //     this.setState({
        //         selectedCategories: newChoice
        //     })
        // } else {
        //     tempSelected.push(val);
        //     this.setState({
        //         selectedCategories: tempSelected
        //     })
        // }

    }

    getTotalAmountOfReturn(items) {
        let tAmont = 0;
        items.forEach((element) => {
            tAmont = parseFloat(tAmont) + parseFloat(element.price);
        });
        return tAmont;
    }

