
import React, { Component } from "react";
import { Grid, Row, Col, Table } from "react-bootstrap";
import { Link } from "react-router-dom";
import axios from 'axios';
import NotificationSystem from "react-notification-system";
import Button from "components/CustomButton/CustomButton.jsx";

import { style } from "../../variables/Variables.jsx";
import Card from "components/Card/Card.jsx";
import '../../assets/css/custom.css';
import { authHeader } from '../../configs/helpers';
import { apiUrls } from '../../configs/configs';
import InfiniteScroll from "react-infinite-scroll-component";
const _ = require("lodash");

const mgr2 = {
  marginRight: 2
};

class ProductList extends Component {
  constructor(props) {
    super(props);
    this.state = {
      products: [],
      currentPage: 0,
      loading: true,
      totalRec: 0,
      cateSearch: null,
      nameSearch: null,
      albumSearch: null,
      albumCol: [],
      categoryCol: [],
      maxPrice: null,
      weightChange: null,
      productUnits: [],
      unitSearch: null

    };
    this.paginationCall = this.paginationCall.bind(this);
    this.prevRecords = this.prevRecords.bind(this);
    this.nextRecords = this.nextRecords.bind(this);
    this.searchCall = this.searchCall.bind(this);
    this.searchCallByCate = this.searchCallByCate.bind(this);
    this.searchCallByAlbum = this.searchCallByAlbum.bind(this);
    this.applyPrice = this.applyPrice.bind(this);
    this.applyWeightChange = this.applyWeightChange.bind(this);
    this.searchCallByUnit = this.searchCallByUnit.bind(this);

  }

  componentWillMount() {
    if (localStorage.getItem('_prod_page_last')) {
      this.setState({
        currentPage: parseInt(localStorage.getItem('_prod_page_last')),
        nameSearch: localStorage.getItem('_prod_name_search') ? localStorage.getItem('_prod_name_search') : null,
        albumSearch: localStorage.getItem('_prod_album_search') ? localStorage.getItem('_prod_album_search') : null,
        cateSearch: localStorage.getItem('_prod_cat_search') ? localStorage.getItem('_prod_cat_search') : null
      }, () => {
        this.getAllProduct(null);
        localStorage.removeItem('_prod_page_last');
        localStorage.removeItem('_prod_album_search');
        localStorage.removeItem('_prod_cat_search');
        localStorage.removeItem('_prod_name_search');

      })
    } else {
      this.getAllProduct(null);
    }
    this.getAlbumList();
    this.getCategoryList();
    this.getProductUnitList();
  }


  getProductUnitList(){
    axios({
      method: 'GET',
      url: apiUrls.PRODUCTUNITS,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        this.setState({
          productUnits: result.data.data[0].paginatedResults,
        });
      }else{
        this.setState({
          productUnits : []
        });
      }
    }).catch(e => {
      this.setState({
        productUnits : []
      });
    });
  }
  
  getAlbumList() {
    axios({
      method: 'GET',
      url: apiUrls.PRODUCT.getAllAlbum,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        this.setState({
          albumCol: result.data.data,
        });
      } else {
        this.setState({
          albumCol: []
        });
      }
    }).catch(e => {
      this.setState({
        albumCol: []
      });
    });
  }

  getCategoryList() {
    axios({
      method: 'GET',
      url: apiUrls.PRODUCT.getAllCategory,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        this.setState({
          categoryCol: result.data.data,
        });
      } else {
        this.setState({
          categoryCol: []
        });
      }
    }).catch(e => {
      this.setState({
        categoryCol: []
      });
    });
  }

  fetchMoreData = () => {
    this.setState({
      currentPage: this.state.currentPage + 1
    }, () => {
      this.getAllProduct(null);
    }
    );
  };

  applyPrice(price){
    this.setState({
      currentPage: 0,
      maxPrice: price[0]
    });
    const handleChangeDebounce = _.debounce(() => {
      if(this.state.loading === false){
        this.getAllProduct(null);
      }
    }, 500);
    handleChangeDebounce();

  }

  applyWeightChange(weigh){
    this.setState({
      currentPage: 0,
      weightChange: weigh[0]
    });
    const handleChangeDebounce = _.debounce(() => {
      if(this.state.loading === false){
        this.getAllProduct(null);
      }
    }, 500);
    handleChangeDebounce();

  }

  getAllProduct(search) {
    var _notificationSystem;

    var params = {
      page: this.state.currentPage
    };

    if (this.state.nameSearch) {
      params.name = this.state.nameSearch;
    }

    if (this.state.cateSearch) {
      params.category = this.state.cateSearch;
    }

    if (this.state.albumSearch) {
      params.album = this.state.albumSearch;
    }

    if(this.state.maxPrice){
      params.maxPrice = this.state.maxPrice;
    }

    if(this.state.weightChange || this.state.weightChange === 0){
      params.weightChange = this.state.weightChange;
    }

    if(this.state.unitSearch){
      params.unitSearch = this.state.unitSearch;
    }
 
    
    this.setState({ _notificationSystem: this.refs.notificationSystem }, () => {
      _notificationSystem = this.refs.notificationSystem;
    });
    this.setState({
      loading: true
    });


    axios({
      method: 'GET',
      url: apiUrls.PRODUCT.getAllProduct,
      headers: {
        Authorization: authHeader()
      },
      params: params
    }).then(result => {
      if (result.status === 200 && result.data.data[0]) {
        var temp = [];
        if(this.state.currentPage > 0){
          temp = this.state.products;
          temp = temp.concat(result.data.data[0].paginatedResults);
        } else {
          var temp = result.data.data[0].paginatedResults;
        }
        
        if(this.state.currentPage === 0 && result.data.data[0].paginatedResults.length === 0){
          this.setState({
            products: [],
            totalRec: 0,
            loading: false
          })
        } else {
          this.setState({
            products: temp,
            totalRec: result.data.data[0].totalCount[0] ? result.data.data[0].totalCount[0].count : 0,
            loading: false
          });
        }
      } else {
        if(this.state.currentPage === 0){
          this.setState({
            products: [],
            totalRec: 0
          })
        }
        this.setState({
          loading: false
        });
      }
    }).catch(e => {
      this.setState({
        loading: false
      });

      _notificationSystem.addNotification({
        title: <span data-notify="icon" className="pe-7s-close-circle" />,
        message: (
          <div>
            {(e.response) ? e.response.data.message : 'Something went wrong!'}
          </div>
        ),
        level: 'error',
        position: "tr",
        autoDismiss: 15
      });
    });
  }


  paginationCall(index) {
    this.setState({
      currentPage: index
    }, () => {
      this.getAllProduct(true);
    })
  }

  prevRecords() {
    if (this.state.currentPage > 0) {
      var c = this.state.currentPage;
      this.setState({
        currentPage: c - 1
      }, () => {
        this.getAllProduct(true);
      })
    }
  }

  nextRecords() {
    var c = this.state.currentPage;
    var totalPage = Math.ceil(this.state.totalRec / 5);
    if (c < totalPage - 1) {
      this.setState({
        currentPage: c + 1
      }, () => {
        this.getAllProduct(true);
      })
    }
  }

  searchCall(val) {
    this.setState({
      nameSearch: val,
      currentPage: 0,
      products: []
    }, () => {
      this.getAllProduct(true);
    })
  }

  searchCallByCate(val) {
    this.setState({
      cateSearch: val,
      currentPage: 0,
      products: []
    }, () => {
      this.getAllProduct(true);
    })
  }

  searchCallByAlbum(val) {
    this.setState({
      albumSearch: val,

      currentPage: 0,
      products: []
    }, () => {
      this.getAllProduct(true);
    })
  }

  searchCallByUnit(val) {
    this.setState({
      unitSearch: val,

      currentPage: 0,
      products: []
    }, () => {
      this.getAllProduct(true);
    })
  }


  deletePro(orderId) {
    if (window.confirm("Are sure to delete this product!")) {
      var _notificationSystem;
      this.setState({ _notificationSystem: this.refs.notificationSystem }, () => {
        _notificationSystem = this.refs.notificationSystem;
      });

      axios({
        method: 'DELETE',
        url: apiUrls.PRODUCT.getAllProduct + '/' + orderId,
        headers: {
          Authorization: authHeader()
        }
      }).then(result => {
        if (result.status === 200) {
          // if (this.state.currentPage != 0 && this.state.employees && this.state.employees.length == 1) {
          //   this.setState({
          //     currentPage: this.state.currentPage - 1
          //   })
          // }
          // this.getAllProduct(this.state.nameSearch);

          const temp = [];
          this.state.products.forEach(i => {
            if (i._id == orderId) {
              i.isActive = false;
            }
            temp.push(i)
          });
          this.setState({
            products: temp
          })
          _notificationSystem.addNotification({
            title: <span data-notify="icon" className="pe-7s-check" />,
            message: (
              <div>
                Product removed!.
              </div>
            ),
            level: 'success',
            position: "tr",
            autoDismiss: 15
          });
        }
      }).catch(e => {
        console.log(e)
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
              {(e.response) ? e.response.data.message : 'Something went wrong!'}
            </div>
          ),
          level: 'error',
          position: "tr",
          autoDismiss: 15
        });
      });
    }
  }


  activatePro(orderId) {
    if (window.confirm("Are sure to activate this product!")) {
      var _notificationSystem;
      this.setState({ _notificationSystem: this.refs.notificationSystem }, () => {
        _notificationSystem = this.refs.notificationSystem;
      });

      axios({
        method: 'DELETE',
        url: apiUrls.PRODUCT.activatePro + orderId,
        headers: {
          Authorization: authHeader()
        }
      }).then(result => {
        if (result.status === 200) {
          // if (this.state.currentPage != 0 && this.state.employees && this.state.employees.length == 1) {
          //   this.setState({
          //     currentPage: this.state.currentPage - 1
          //   })
          // }
          // this.getAllProduct(this.state.nameSearch);
          const temp = [];
          this.state.products.forEach(i => {
            if (i._id == orderId) {
              i.isActive = true;
            }
            temp.push(i)
          });
          this.setState({
            products: temp
          })
          _notificationSystem.addNotification({
            title: <span data-notify="icon" className="pe-7s-check" />,
            message: (
              <div>
                Product added!.
              </div>
            ),
            level: 'success',
            position: "tr",
            autoDismiss: 15
          });
        }
      }).catch(e => {
        console.log(e)
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
              {(e.response) ? e.response.data.message : 'Something went wrong!'}
            </div>
          ),
          level: 'error',
          position: "tr",
          autoDismiss: 15
        });
      });
    }
  }

  setLocalData() {
    if (this.state.nameSearch) {
      localStorage.setItem('_prod_name_search', this.state.nameSearch)
    }
    if (this.state.cateSearch) {
      localStorage.setItem('_prod_cat_search', this.state.cateSearch)
    }
    if (this.state.albumSearch) {
      localStorage.setItem('_prod_album_search', this.state.albumSearch)
    }

    localStorage.setItem('_prod_page_last', this.state.currentPage)
  }


  render() {
    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />
        <Grid fluid>
          <Row>
            <Col md={12}>

              <Card
                title="Product List"
                search={true}
                searchplaceholder="Search by name"
                ctTableFullWidth
                ctTableResponsive
                pagination={this.state.products.length > 0 ? true : false}
                processPagination={this.paginationCall}
                prev={this.prevRecords}
                next={this.nextRecords}
                productSearch={true}
                priceFilter={true}
                weightFilter={true}
                albumCollection={this.state.albumCol}
                catCollection={this.state.categoryCol}
                productUnits={this.state.productUnits}
                searchCall={this.searchCall}
                applyPrice={this.applyPrice}
                applyWeightChange={this.applyWeightChange}
                searchCallByCate={this.searchCallByCate}
                searchCallByAlbum={this.searchCallByAlbum}
                searchCallByUnit={this.searchCallByUnit}
                currentPage={this.state.currentPage}
                totalPages={Math.ceil(this.state.totalRec / 5)}
                createLink="/admin/product/create"
                content={
                  <InfiniteScroll
                    dataLength={this.state.products.length}
                    hasMore={true}
                    // loader={<h4>Loading...</h4>}
                    next={this.fetchMoreData}
                  >
                    <Table striped hover>
                      <thead>
                        <tr>
                          <th>Id</th>
                          <th>Name</th>
                          <th>Category</th>
                          <th>Album</th>
                          <th>Status</th>
                          <th>Actions</th>
                        </tr>
                      </thead>
                      <tbody>
                        {(this.state.products.length > 0) && (
                          this.state.products.map((element, index) => {
                            return (
                              <tr key={index}>
                                <td>{index + 1}</td>
                                <td>{element.name}</td>
                                <td>{element.productCategory[0].name}</td>
                                <td>{element.album[0].name}</td>
                                <td>{element.isActive === false ? "Disabled" : "Enabled"}</td>

                                <td>

                                  <Link className="mgr-5 btn btn-default" to={"/admin/product/" + element._id + "/update"} type="button" onClick={() => this.setLocalData()}>
                                    Edit
                                  </Link>
                                  <Link className="mgr-5 btn btn-default" to={"/admin/product-gallery/" + element._id} type="button" >
                                    Gallery
                                  </Link>
                                  {/* {element.isActive === true && (<Button bsStyle="danger" onClick={() => this.deletePro(element._id)} type="button" style={mgr2}>
                                    Delete
                                  </Button>)} */}
                                  {element.isActive === false && (<Button bsStyle="danger" onClick={() => this.activatePro(element._id)} type="button" style={mgr2}>
                                    Activate
                                  </Button>)}
                                  {element.isActive === true && (<Button bsStyle="danger" onClick={() => this.deletePro(element._id)} type="button" style={mgr2}>
                                    De-Activate
                                  </Button>)}


                                </td>
                              </tr>
                            );
                          })

                        )}

                        {(this.state.loading == false && this.state.products.length == 0) && (
                          <tr>
                            <td colSpan={6} className="text-center">No Records Found</td>
                          </tr>
                        )}

                      </tbody>

                    </Table>
                  </ InfiniteScroll>
                }
              />
            </Col>

          </Row>
        </Grid>
      </div>
    );
  }
}

export default ProductList;
