
import React, { Component } from "react";
import { Grid, Row, Col, Table } from "react-bootstrap";
import { Link } from "react-router-dom";
import axios from 'axios';
import NotificationSystem from "react-notification-system";
import { style } from "../../variables/Variables.jsx";
import Card from "components/Card/Card.jsx";
import '../../assets/css/custom.css';
import { authHeader } from '../../configs/helpers';
import { apiUrls } from '../../configs/configs';
import InfiniteScroll from "react-infinite-scroll-component";
const _ = require("lodash");

const mgr2 = {
  marginRight: 2
};

class PastryList extends Component {
  constructor(props) {
    super(props);
    this.state = {
      collections: [],
      currentPage: 0,
      loading: true,
      totalRec: 0,
      searchData: null,
      maxPrice: null,
      weightChange: null,
      productUnits: [],
      unitSearch: null

    };
    this.paginationCall = this.paginationCall.bind(this);
    this.prevRecords = this.prevRecords.bind(this);
    this.nextRecords = this.nextRecords.bind(this);
    this.searchCall = this.searchCall.bind(this);
    this.applyPrice = this.applyPrice.bind(this);
    this.searchCallByUnit = this.searchCallByUnit.bind(this);

  }

  componentWillMount() {
    if (localStorage.getItem('_pastry_page_last')) {
      this.setState({
        currentPage: parseInt(localStorage.getItem('_pastry_page_last')),
        searchData: localStorage.getItem('_pastry_name_search') ? localStorage.getItem('_pastry_name_search') : null,
      }, () => {
        this.getAllPastry(null);
        localStorage.removeItem('_pastry_page_last');
        localStorage.removeItem('_pastry_name_search');
      })
    } else {
      this.getAllPastry(null);
    }
    this.getProductUnitList();

  }


  getProductUnitList(){
    axios({
      method: 'GET',
      url: apiUrls.PRODUCTUNITS,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        this.setState({
          productUnits: result.data.data[0].paginatedResults,
        });
      }else{
        this.setState({
          productUnits : []
        });
      }
    }).catch(e => {
      this.setState({
        productUnits : []
      });
    });
  }

 

  searchCallByUnit(val) {
    this.setState({
      unitSearch: val,
      currentPage: 0,
      collections: []
    }, () => {
      this.getAllPastry(true);
    })
  }

  applyPrice(price){
    this.setState({
      currentPage: 0,
      maxPrice: price[0],
      collections: []
    });
    const handleChangeDebounce = _.debounce(() => {
      if(this.state.loading === false){
        this.getAllPastry(null);
      }
    }, 500);
    handleChangeDebounce();

  }

  getAllPastry(search) {
    var _notificationSystem;

    var params = {
      page: this.state.currentPage
    };

    if (this.state.searchData) {
      params.name = this.state.searchData;
    }

    if(this.state.maxPrice){
      params.maxPrice = this.state.maxPrice;
    }

    if(this.state.unitSearch){
      params.unitSearch = this.state.unitSearch;
    }

    this.setState({ _notificationSystem: this.refs.notificationSystem }, () => {
      _notificationSystem = this.refs.notificationSystem;
    });
    this.setState({
      loading: true
    });
    axios({
      method: 'GET',
      url: apiUrls.PASTRY.list,
      headers: {
        Authorization: authHeader()
      },
      params: params
    }).then(result => {
      if (result.status === 200 && result.data.data[0]) {
        var temp = this.state.collections;
        temp = temp.concat(result.data.data[0].paginatedResults);

        this.setState({
          collections: temp,
          totalRec: result.data.data[0].totalCount[0] ? result.data.data[0].totalCount[0].count : 0,
          loading: false
        });
      } else {
        this.setState({
          loading: false
        });
      }
    }).catch(e => {
      this.setState({
        loading: false
      });

      _notificationSystem.addNotification({
        title: <span data-notify="icon" className="pe-7s-close-circle" />,
        message: (
          <div>
            {(e.response) ? e.response.data.message : 'Something went wrong!'}
          </div>
        ),
        level: 'error',
        position: "tr",
        autoDismiss: 15
      });
    });
  }

  paginationCall(index) {
    this.setState({
      currentPage: index
    }, () => {
      this.getAllPastry(null);
    })
  }

  prevRecords() {
    if (this.state.currentPage > 0) {
      var c = this.state.currentPage;
      this.setState({
        currentPage: c - 1
      }, () => {
        this.getAllPastry(null);
      })
    }
  }

  nextRecords() {
    var c = this.state.currentPage;
    var totalPage = Math.ceil(this.state.totalRec / 5);
    if (c < totalPage - 1) {
      this.setState({
        currentPage: c + 1
      }, () => {
        this.getAllPastry(null);
      })
    }
  }

  searchCall(val) {
    this.setState({
      searchData: val,
      collections: [],
      currentPage: 0,
    }, () => {
      this.getAllPastry();
    })
  }

  deleteById(id) {
    if (window.confirm("Are sure to delete this pastry!")) {

      var _notificationSystem;

      this.setState({ _notificationSystem: this.refs.notificationSystem }, () => {
        _notificationSystem = this.refs.notificationSystem;
      });

      axios({
        method: 'DELETE',
        url: apiUrls.PASTRY.one + '/' + id,
        headers: {
          Authorization: authHeader()
        }
      }).then(result => {
        if (result.status === 200) {
          if (this.state.currentPage !== 0 && this.state.collections.length === 1) {
            this.setState({
              currentPage: this.state.currentPage - 1
            })
          }
          this.getAllPastry(null);

          _notificationSystem.addNotification({
            title: <span data-notify="icon" className="pe-7s-check" />,
            message: (
              <div>
                Pastry category deleted!.
              </div>
            ),
            level: 'success',
            position: "tr",
            autoDismiss: 15
          });
        }
      }).catch(e => {
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
              {(e.response) ? e.response.data.message : 'Something went wrong!'}
            </div>
          ),
          level: 'error',
          position: "tr",
          autoDismiss: 15
        });
      });
    }
  }

  fetchMoreData = () => {
    this.setState({
      currentPage: this.state.currentPage + 1
    }, () => {
      this.getAllPastry(null);
    }
    );
  };


  setLocalData() {
    if (this.state.nameSearch) {
      localStorage.setItem('_pastry_name_search', this.state.searchData)
    }

    localStorage.setItem('_pastry_page_last', this.state.currentPage)
  }


  render() {
    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />
        <Grid fluid>
          <Row>
            <Col md={12}>

              <Card
                title="Pastries"
                search={true}
                searchplaceholder="Search by name"
                ctTableFullWidth
                ctTableResponsive
                pagination={this.state.collections.length > 0 ? true : false}
                processPagination={this.paginationCall}
                prev={this.prevRecords}
                next={this.nextRecords}
                searchCall={this.searchCall}
                applyPrice={this.applyPrice}
                searchCallByUnit={this.searchCallByUnit}
                productUnits={this.state.productUnits}
                priceFilter={true}
                currentPage={this.state.currentPage}
                totalPages={Math.ceil(this.state.totalRec / 5)}
                createLink="/admin/pastry/create"
                content={

                  <InfiniteScroll
                    dataLength={this.state.collections.length}
                    hasMore={true}
                    // loader={<h4>Loading...</h4>}
                    next={this.fetchMoreData}
                  >

                    <Table striped hover>
                      <thead>
                        <tr>
                          <th>Id</th>
                          <th>Name</th>
                          <th>Price</th>
                          <th>Status</th>
                          <th>Actions</th>
                        </tr>
                      </thead>
                      <tbody>
                        {(this.state.collections.length > 0) && (
                          this.state.collections.map((element, index) => {
                            return (
                              <tr key={index}>
                                <td>{index + 1}</td>
                                <td>{element.name}</td>
                                <td>{element.price}</td>
                                <td>{element.isActive === true ? "Enabled" : "Disabled"}</td>

                                <td>

                                  <Link className="mgr-5 btn btn-default" to={"/admin/pastry/" + element._id + "/update"} type="button" onClick={() => this.setLocalData()} >
                                    Edit
                                  </Link>
                                  {/* 
                                <Button bsStyle="danger" onClick={() => this.deleteById(element._id)} type="button" style={mgr2}>
                                  Delete
                                </Button> */}
                                </td>
                              </tr>
                            );
                          })

                        )}

                        {(this.state.loading == false && this.state.collections.length == 0) && (
                          <tr>
                            <td colSpan={4} className="text-center">No Records Found</td>
                          </tr>
                        )}

                      </tbody>

                    </Table>
                  </ InfiniteScroll>
                }

              />
            </Col>

          </Row>
        </Grid>
      </div>
    );
  }
}

export default PastryList;
