
import React, { Component } from "react";
import { Grid, Row, Col } from "react-bootstrap";
import { Link } from "react-router-dom";
import NotificationSystem from "react-notification-system";
import axios from 'axios';
import ImageCompressor from 'image-compressor.js';

import { style } from "../../variables/Variables.jsx";
import { Card } from "components/Card/Card.jsx";
import Button from "components/CustomButton/CustomButton.jsx";
import '../../assets/css/custom.css';
import { validateForm, authHeader, fileMaxLimit } from '../../configs/helpers';
import { apiUrls } from '../../configs/configs';
import BarcodeReader from 'react-barcode-reader'

class PastryCreate extends Component {
  constructor(props) {
    super(props);
    this.state = {
      allowGST: false,
      isActive: true,
      cgst: 0,
      sgst: 0,
      cess: 0,
      code: '',
      isFormSubmit: false,
      name: null,
      price: null,
      image: null,
      tempImg: '',
      category: '',
      categoryCol: [],
      productUnits: [],
      _pUnit: '',
      barResult: 'No result',
      errors: {
        name: 'Name is required',
        price: 'Price is required',
        category: 'Product category is required',
        image: '',
        code: 'Product code is required'
      }
    }
    this.handleScan = this.handleScan.bind(this);
  }

  handleScan(data) {
    console.info("Barcode Working...");
    this.setState({
      code: data,
    })
  }

  handleError(err) {
    console.error(err)
  }

  componentWillMount() {
    this.getCategoryList();
    this.getProductUnitList();
  }


  getProductUnitList() {
    axios({
      method: 'GET',
      url: apiUrls.PRODUCTUNITSLIST,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        this.setState({
          productUnits: result.data.data,
        });
      } else {
        this.setState({
          productUnits: []
        });
      }
    }).catch(e => {
      this.setState({
        productUnits: []
      });
    });
  }

  getCategoryList() {
    axios({
      method: 'GET',
      url: apiUrls.PRODUCT.getAllCategoryPastry,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        this.setState({
          categoryCol: result.data.data,
        });
      } else {
        this.setState({
          categoryCol: []
        });
      }
    }).catch(e => {
      this.setState({
        categoryCol: []
      });
    });
  }


  handleChange = (event) => {
    event.preventDefault();
    const { name, value } = event.target;
    let errors = this.state.errors;

    switch (name) {
      case 'name':
        errors.name =
          value.length <= 0
            ? 'Branch name is required'
            : '';
        break;
      case 'price':
        errors.price =
          value.length <= 0
            ? 'Price is required'
            : '';
        break;
      case 'category':
        errors.category =
          value.length <= 0
            ? 'Product category is required'
            : '';
        break;
      case 'code':
        errors.code =
          value.length <= 0
            ? 'Product code is required'
            : '';
        break;
      default:
        break;
    }

    this.setState({ errors, [name]: value });
  }

  handleSubmit = (event) => {
    this.setState({ _notificationSystem: this.refs.notificationSystem, isFormSubmit: true });
    var _notificationSystem = this.refs.notificationSystem;
    event.preventDefault();


    if (validateForm(this.state.errors)) {
      var bodyFormData = new FormData();
      bodyFormData.set('name', this.state.name);
      bodyFormData.set('price', this.state.price);
      bodyFormData.set('code', this.state.code);
      bodyFormData.set('cgst', this.state.cgst);
      bodyFormData.set('sgst', this.state.sgst);
      bodyFormData.set('cess', this.state.cess);
      bodyFormData.set('allowGST', this.state.allowGST);
      bodyFormData.set('isActive', this.state.isActive);

      bodyFormData.append('image', this.state.image);
      bodyFormData.set('category', this.state.category);
      if (this.state._pUnit) {
        bodyFormData.set('unit', this.state._pUnit);
      }

      axios({
        method: 'POST',
        url: apiUrls.PASTRY.one,
        data: bodyFormData,
        headers: {
          'Content-Type': 'multipart/form-data',
          Authorization: authHeader()
        }
      }).then(result => {
        if (result.status === 201) {

          _notificationSystem.addNotification({
            title: <span data-notify="icon" className="pe-7s-check" />,
            message: (
              <div>
                Pastry created.
              </div>
            ),
            level: 'success',
            position: "tr",
            autoDismiss: 15
          });

        }
      }).catch(e => {
        console.log(e)
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
              {(e.response) ? e.response.data.message : 'Something went wrong!'}
            </div>
          ),
          level: 'error',
          position: "tr",
          autoDismiss: 15
        });
      });
    }
  }

  fileChangedHandler = (event) => {
    let errors = this.state.errors;
    let curr = this;
    this.setState({
      tempImg: ''
    })
    if (event.target.files[0]) {
      if (fileMaxLimit(event)) {
        errors.image = '';
        this.setState({
          tempImg: URL.createObjectURL(event.target.files[0])
        })
        new ImageCompressor(event.target.files[0], {
          quality: 0.6,
          success(result) {
            var file = new File([result], result.name, { type: result.type });
            curr.setState({ image: file, errors });
          },
          error(e) {
            console.log(e.message);
          },
        });
      } else {
        errors.image = 'File size should be maximum 5MB';
        this.setState({ errors });
      }
    } else {
      errors.image = '';
      this.setState({ image: '', errors });
    }
  };

  render() {
    const { errors, isFormSubmit } = this.state;

    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />
        <BarcodeReader
          onError={this.handleError}
          onScan={this.handleScan}
        />
        <Grid fluid>
          <Row>
            <Col md={8}>
              <Card
                title="Create a new pastry"
                content={
                  <form onSubmit={this.handleSubmit} noValidate>

                    <div className="form-group">
                      <label>Name</label>
                      <input type="text" className="form-control" name="name" placeholder="Enter name" onChange={this.handleChange} noValidate />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.name}</p>
                        )
                      }
                    </div>
                    <div className="row">
                      <div className="col-md-6">

                        <div className="form-group">
                          <label>Price</label>
                          <input type="number" min={0} className="form-control" name="price" placeholder="Enter price" onChange={this.handleChange} noValidate />
                          {
                            isFormSubmit && (
                              <p className="txt-error">{errors.price}</p>
                            )
                          }
                        </div>
                      </div>
                      <div className="col-md-6">


                        <div className="form-group">
                          <label>Code*</label>
                          <input type="text" className="form-control" value={this.state.code} name="code" placeholder="Enter code" onChange={this.handleChange} noValidate />
                          {
                            isFormSubmit && (
                              <p className="txt-error">{errors.code}</p>
                            )
                          }
                        </div>
                      </div>
                    </div>
                    <div className="row">

                      <div className="col-md-2">

                        <div className="form-group">
                          <label>Allow GST?</label>
                          <input type="checkbox" className="form-control" name="allowGST"
                            onClick={() => {
                              this.setState({
                                allowGST: !this.state.allowGST
                              })
                            }}
                            noValidate />
                        </div>
                      </div>

                      <div className="col-md-2">

                        <div className="form-group">
                          <label>Is Active?</label>
                          <input type="checkbox" className="form-control" name="isActive"
                            onClick={() => {
                              this.setState({
                                isActive: !this.state.isActive
                              })
                            }}
                            checked={this.state.isActive}
                            noValidate />
                        </div>
                      </div>

                    </div>

                    <div className="row">
                      <div className="col-md-3">
                        <div className="form-group">
                          <label>CGST %</label>
                          <input type="number" className="form-control" name="cgst" placeholder="Enter CGST  %" onChange={this.handleChange} noValidate />
                          {
                            isFormSubmit && (
                              <p className="txt-error">{errors.cgst}</p>
                            )
                          }
                        </div>
                      </div>

                      <div className="col-md-3">

                        <div className="form-group">
                          <label>SGST %</label>
                          <input type="number" className="form-control" name="sgst" placeholder="Enter SGST  %" onChange={this.handleChange} noValidate />
                          {
                            isFormSubmit && (
                              <p className="txt-error">{errors.sgst}</p>
                            )
                          }
                        </div>
                      </div>

                      <div className="col-md-3">

                        <div className="form-group">
                          <label>CESS %</label>
                          <input type="number" className="form-control" name="cess" placeholder="Enter CESS %" onChange={this.handleChange} noValidate />
                          {
                            isFormSubmit && (
                              <p className="txt-error">{errors.sgst}</p>
                            )
                          }
                        </div>
                      </div>
                    </div>


                    <div className="form-group">
                      <label>Category</label>
                      <select name="category" className="form-control" onChange={this.handleChange}>
                        <option value="">Select Category</option>
                        {this.state.categoryCol.length > 0 && (
                          this.state.categoryCol.map((e, key) => {
                            return (
                              <option value={e._id} key={key}>{e.name}</option>
                            )
                          })
                        )}
                      </select>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.category}</p>
                        )
                      }
                    </div>

                    <div className="form-group">
                      <label>Unit</label>
                      <select name="unit" className="form-control" onChange={(ele) => this.setState({ _pUnit: ele.target.value })}>
                        <option value="">Select</option>
                        {this.state.productUnits.length > 0 && (
                          this.state.productUnits.map((e, key) => {
                            return (
                              <option value={e._id} key={key}>{e.name}</option>
                            )
                          })
                        )}
                      </select>
                    </div>

                    <div className="form-group">
                      <label>Photo</label>
                      <input type="file" className="form-control" name="image" onChange={this.fileChangedHandler} />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.image}</p>
                        )
                      }
                    </div>

                    <Link className="mgr-5 btn btn-default" to="/admin/pastries">Cancel</Link>

                    <Button bsStyle="info" type="submit">
                      Create
                    </Button>

                    <div className="clearfix" />
                  </form>
                }
              />
            </Col>
            {
              this.state.tempImg && (
                <Col md={4}>
                  <Card
                    title="Pastry Image"
                    content={
                      <Row className="gallery-scroll">
                        <Col xs={12} md={12} className="mb-btm">
                          <img src={this.state.tempImg} height="200" width="100%" className="mb-btm" alt="temp" />
                        </Col>
                      </Row>
                    }
                  />
                </Col>
              )
            }

          </Row>
        </Grid>
      </div>
    );
  }
}

export default PastryCreate;
