import React, { Component } from "react";
import { Grid, Row, Col, Table } from "react-bootstrap";
import { Link } from "react-router-dom";
import axios from "axios";
import NotificationSystem from "react-notification-system";

import { style } from "../../variables/Variables.jsx";
import Card from "components/Card/Card.jsx";
import Button from "components/CustomButton/CustomButton.jsx";
import "../../assets/css/custom.css";
import { authHeader, getTypeName } from "../../configs/helpers";
import { apiUrls, EmployeeTypes } from "../../configs/configs";
import InfiniteScroll from "react-infinite-scroll-component";

const mgr2 = {
  marginRight: 2,
};

class EmployeeList extends Component {
  constructor(props) {
    super(props);
    this.state = {
      employees: [],
      currentPage: 0,
      loading: true,
      totalRec: 0,
      branchSearch: null,
      typeSearch: null,
      nameSearch: null,
      storesCollection: [],
      isLoadingContent: false
    };
    this.paginationCall = this.paginationCall.bind(this);
    this.prevRecords = this.prevRecords.bind(this);
    this.nextRecords = this.nextRecords.bind(this);
    this.searchCall = this.searchCall.bind(this);
    this.searchCallByType = this.searchCallByType.bind(this);
    this.searchCallByBrnach = this.searchCallByBrnach.bind(this);
  }

  componentWillMount() {
    this.getAllEmployees(null);
  }

  getAllEmployees(search) {
    var _notificationSystem;
    this.setState({
      loading: true
    })

    var params = {
      page: this.state.currentPage,
    };

    if (this.state.branchSearch) {
      params.branch = this.state.branchSearch;
    }

    if (this.state.nameSearch) {
      params.emp = this.state.nameSearch;
    }

    if (this.state.typeSearch) {
      params.type = this.state.typeSearch;
    }

    this.setState({ _notificationSystem: this.refs.notificationSystem }, () => {
      _notificationSystem = this.refs.notificationSystem;
    });

    axios({
      method: "GET",
      url: apiUrls.EMPLOYEE,
      headers: {
        Authorization: authHeader(),
      },
      params: params,
    })
      .then((result) => {
        if (result.status === 200 && result.data.data[0]) {
          var temp = this.state.employees;
          temp = temp.concat(result.data.data[0].paginatedResults)

          this.setState({
            employees: temp,
            isLoadingContent: false,
            storesCollection: result.data.store,
            totalRec: result.data.data[0].totalCount[0]
              ? result.data.data[0].totalCount[0].count
              : 0,
            loading: false,
          });
        } else {
          this.setState({
            loading: false,
          });
        }
      })
      .catch((e) => {
        this.setState({
          loading: false,
        });

        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
              {e.response ? e.response.data.message : "Something went wrong!"}
            </div>
          ),
          level: "error",
          position: "tr",
          autoDismiss: 15,
        });
      });
  }

  paginationCall(index) {
    this.setState(
      {
        currentPage: index,
      },
      () => {
        this.getAllEmployees(null);
      }
    );
  }

  prevRecords() {
    if (this.state.currentPage > 0) {
      var c = this.state.currentPage;
      this.setState(
        {
          currentPage: c - 1,
        },
        () => {
          this.getAllEmployees(null);
        }
      );
    }
  }

  nextRecords() {
    var c = this.state.currentPage;
    var totalPage = Math.ceil(this.state.totalRec / 5);
    if (c < totalPage - 1) {
      this.setState(
        {
          currentPage: c + 1,
        },
        () => {
          this.getAllEmployees(null);
        }
      );
    }
  }

  fetchMoreData = () => {
    this.setState({
      currentPage: this.state.currentPage + 1
    }, () => {
      this.getAllEmployees(null);
    }
    );
  };


  searchCall(val) {
    this.setState(
      {
        nameSearch: val,
        employees: [],
        currentPage: 0,
      },
      () => {
        this.getAllEmployees(true);
      }
    );
  }

  searchCallByBrnach(val) {
    this.setState(
      {

        employees: [],
        branchSearch: val,
        currentPage: 0,
      },
      () => {
        this.getAllEmployees(true);
      }
    );
  }

  searchCallByType(val) {
    this.setState(
      {
        typeSearch: val,
        currentPage: 0,
        employees: []
      },
      () => {
        this.getAllEmployees(true);
      }
    );
  }

  deleteEmployeeById(empId) {
    if (window.confirm("Are sure to delete this employee!")) {
      var _notificationSystem;
      this.setState(
        { _notificationSystem: this.refs.notificationSystem },
        () => {
          _notificationSystem = this.refs.notificationSystem;
        }
      );

      axios({
        method: "DELETE",
        url: apiUrls.EMPLOYEE + "/" + empId,
        headers: {
          Authorization: authHeader(),
        },
      })
        .then((result) => {
          if (result.status === 200) {
            if (
              this.state.currentPage != 0 &&
              this.state.employees.length == 1
            ) {
              this.setState({
                currentPage: this.state.currentPage - 1,
              });
            }
            this.getAllEmployees(null);

            _notificationSystem.addNotification({
              title: <span data-notify="icon" className="pe-7s-check" />,
              message: <div>Employee deleted!.</div>,
              level: "success",
              position: "tr",
              autoDismiss: 15,
            });
          }
        })
        .catch((e) => {
          _notificationSystem.addNotification({
            title: <span data-notify="icon" className="pe-7s-close-circle" />,
            message: (
              <div>
                {e.response ? e.response.data.message : "Something went wrong!"}
              </div>
            ),
            level: "error",
            position: "tr",
            autoDismiss: 15,
          });
        });
    }
  }

  forceLogoutUser(empId) {
    if (window.confirm("Are sure for this change!")) {
      axios({
        method: "POST",
        url: apiUrls.FORCE_LOGOUT + empId,
        headers: {
          "Content-Type": "multipart/form-data",
          Authorization: authHeader(),
        },
      })
        .then((result) => {
          if (result.status === 200) {
            this.getAllEmployees(null);
          }
        })
        .catch((e) => {
          console.log(e);
        });
    }
  }

  render() {
    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />
        <Grid fluid>
          <Row>
            <Col md={12}>
              <Card
                title="Employees"
                search={true}
                searchplaceholder="Search employee"
                ctTableFullWidth
                ctTableResponsive
                pagination={this.state.employees.length > 0 ? true : false}
                processPagination={this.paginationCall}
                prev={this.prevRecords}
                next={this.nextRecords}
                searchCall={this.searchCall}
                searchCallByBrnach={this.searchCallByBrnach}
                searchCallByType={this.searchCallByType}
                currentPage={this.state.currentPage}
                typeOfemp={EmployeeTypes}
                storesCol={this.state.storesCollection}
                totalPages={Math.ceil(this.state.totalRec / 5)}
                empSearch={true}
                createLink="/admin/employee/create"
                paginateContent={true}
                content={
                  <InfiniteScroll
                    dataLength={this.state.employees.length}
                    hasMore={true}
                    // loader={<h4>Loading...</h4>}
                    next={this.fetchMoreData}
                  >
                    <Table striped hover>
                      <thead>
                        <tr>
                          <th>Id</th>
                          <th>Firstname</th>
                          <th>Lastname</th>
                          <th>Employee Code</th>
                          <th>Type</th>
                          <th>Actions</th>
                        </tr>
                      </thead>
                      <tbody>
                        {
                          this.state.employees.length > 0 &&
                          this.state.employees.map((element, index) => {
                            return (
                              <tr key={index}>
                                <td>{index + 1}</td>
                                <td>{element.firstname}</td>
                                <td>{element.lastname}</td>
                                <td style={{ textAlign: "center" }}>
                                  {element.empcode ? element.empcode : "-"}
                                </td>
                                <td>{getTypeName(element.emptype)}</td>
                                <td>
                                  <Link
                                    className="mgr-5 btn btn-default"
                                    to={
                                      "/admin/employee/" +
                                      element._id +
                                      "/update"
                                    }
                                    type="button"
                                  >
                                    Edit
                                  </Link>

                                  {/* <Button bsStyle="danger" onClick={() => this.deleteEmployeeById(element._id)} type="button" style={mgr2}>
                                  Delete
                                </Button> */}
                                  <Button
                                    bsStyle="warning"
                                    onClick={() =>
                                      this.forceLogoutUser(element._id)
                                    }
                                    type="button"
                                    style={mgr2}
                                  >
                                    {element.isEnable === true
                                      ? "Force Logout"
                                      : "Give Access"}
                                  </Button>
                                </td>
                              </tr>
                            );
                          })}

                        {this.state.loading == false &&
                          this.state.employees.length == 0 && (
                            <tr>
                              <td colSpan={6} className="text-center">
                                No Employee Records Found
                              </td>
                            </tr>
                          )}
                      </tbody>
                    </Table>
                  </InfiniteScroll>
                }
              />
            </Col>
          </Row>
        </Grid>
      </div>
    );
  }
}

export default EmployeeList;
