
import React, { Component } from "react";
import { Grid, Row, Col } from "react-bootstrap";
import {  Link } from "react-router-dom";
import NotificationSystem from "react-notification-system";
import axios from 'axios';
import ImageCompressor from 'image-compressor.js';

import { style } from "../../variables/Variables.jsx";
import { Card } from "components/Card/Card.jsx";
import Button from "components/CustomButton/CustomButton.jsx";
import '../../assets/css/custom.css';
import {validateForm, authHeader, MultifileMaxLimit } from '../../configs/helpers';
import { apiUrls} from '../../configs/configs';


class ProductCreate extends Component {
  constructor(props){
    super(props);
    this.state = {
      isFormSubmit: false,
      name: null,
      category: null,
      album: null,
      description: null,
      directuse: null,
      footnote: null,
      ingredients: null,
      images: [],
      pricesData: [],
      albumCol: [],
      categoryCol: [],
      tempImgs: [],
      productUnits: [],
      errors: {
        name: 'Product name is required',
        category: 'Product category is required',
        album: 'Product album is required',
        // description: 'Description is required',
        // directuse: 'Direction to use',
        // footnote: 'Footnote is required',
        // ingredients: 'Ingredients is required',
        images: []
      }
    }
  }

  componentWillMount(){
    this.getAlbumList();
    this.getCategoryList();
    this.getProductUnitList();
  }

  getProductUnitList(){
    axios({
      method: 'GET',
      url: apiUrls.PRODUCTUNITS,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        this.setState({
          productUnits: result.data.data[0].paginatedResults,
        });
      }else{
        this.setState({
          productUnits : []
        });
      }
    }).catch(e => {
      this.setState({
        productUnits : []
      });
    });
  }

  getAlbumList(){
    axios({
      method: 'GET',
      url: apiUrls.PRODUCT.getAllAlbum,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        this.setState({
          albumCol: result.data.data,
        });
      }else{
        this.setState({
          albumCol : []
        });
      }
    }).catch(e => {
      this.setState({
        albumCol : []
      });
    });
  }

  getCategoryList(){
    axios({
      method: 'GET',
      url: apiUrls.PRODUCT.getAllCategory,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        this.setState({
          categoryCol: result.data.data,
        });
      }else{
        this.setState({
          categoryCol : []
        });
      }
    }).catch(e => {
      this.setState({
        categoryCol : []
      });
    });
  }

  handleChange = (event) => {
    event.preventDefault();
    const { name, value } = event.target;
    let errors = this.state.errors;

    switch (name) {
      case 'name': 
        errors.name = 
          value.length <= 0
            ? 'Product name is required'
            : '';
        break;

      case 'category': 
        errors.category = 
          value.length <= 0
            ? 'Product category is required'
            : '';
        break;  

      case 'album': 
        errors.album = 
          value.length <= 0
            ? 'Product album is required'
            : '';
          break;  
      
      // case 'description': 
      // errors.description = 
      //   value.length <= 0
      //     ? 'Description is required'
      //     : '';
      //     break;  

      // case 'footnote': 
      //     errors.footnote = 
      //       value.length <= 0
      //         ? 'Footnote is required'
      //         : '';
      //       break;  
      
      // case 'ingredients': 
      //         errors.ingredients = 
      //           value.length <= 0
      //             ? 'Ingredients is required'
      //             : '';              
      //     break;  
      // case 'directuse': 
      //     errors.directuse = 
      //       value.length <= 0
      //         ? 'Direction to use is required'
      //         : '';              
      // break;  
      default:
        break;
    }

    this.setState({errors, [name]: value});
  }


  fileChangedHandler = (event) => {
    this.setState({tempImgs: []})

    let errors = this.state.errors;

    if(event.target.files.length > 0){
      let files = event.target.files;

      let errorImsg = [];
      for(var i =0; i < files.length; i++){
        if(!MultifileMaxLimit(files[i])){
          errorImsg.push('Image ' + (i + 1) + ' file size greater than 5MB')
        }
      }
      
      if(errorImsg.length > 0){
        errors.images = errorImsg;
        this.setState({errors});
      } else{
        
        errors.images = [];
        let newComImg = [];
        let tempI = [];
        for(var i =0; i < files.length; i++){
          tempI.push(URL.createObjectURL(files[i]));
          new ImageCompressor(files[i], {
            quality: 0.6,
            success(result) {
              var file = new File([result], result.name, {type: result.type});
              newComImg.push(file);
            },
            error(e) {
              console.log(e.message);
            },
          });
        }
          this.setState({
            images: newComImg, errors,
            tempImgs: tempI
          })
      }
    }else{
      errors.images = [];
      this.setState({images: '', errors});
    }
  };

  handleSubmit = (event) => {
    this.setState({ _notificationSystem: this.refs.notificationSystem, isFormSubmit: true });
    var _notificationSystem = this.refs.notificationSystem;
    var havePrice = true;

    event.preventDefault();

    if(this.state.pricesData.length > 0){
      this.state.pricesData.map((price) => {
        if(price.qty && price.price){

        }else{
          havePrice = false;
        }
      });
    }
    
    if(validateForm(this.state.errors) && havePrice) {
      var bodyFormData = new FormData();
      bodyFormData.set('name', this.state.name);
      bodyFormData.set('category', this.state.category);
      bodyFormData.set('album', this.state.album);

      if(this.state.description){
        bodyFormData.set('description', this.state.description);
      }

      if(this.state.directuse){
        bodyFormData.set('directuse', this.state.directuse);
      }

      if(this.state.footnote){
        bodyFormData.set('footnote', this.state.footnote);
      }
      
      if(this.state.ingredients){
        bodyFormData.set('ingredients', this.state.ingredients);
      }

      for(var i=0; i < this.state.images.length; i++){
        bodyFormData.append('image', this.state.images[i]);
      }

      for(var i=0; i < this.state.pricesData.length; i++){
        for (var k in this.state.pricesData[i]){
          if (this.state.pricesData[i].hasOwnProperty(k)) {
              bodyFormData.set('price[' + i + '][' + k + ']', this.state.pricesData[i][k]);
          }
        }
      }

      axios({
        method: 'POST',
        url: apiUrls.PRODUCT.create,
        data: bodyFormData,
        headers: {
          'Content-Type': 'multipart/form-data',
          Authorization: authHeader()
        }
      }).then(result => {
        if (result.status === 201) {

        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-check" />,
            message: (
              <div>
                'Product created.'
              </div>
            ),
            level: 'success',
            position: "tr",
            autoDismiss: 15
          });

        }
        let redirectUrl = '/admin/product/'+ result.data.productId +'/update';
        this.props.history.push(redirectUrl);

      }).catch(e => {
        console.log(e)
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
            message: (
              <div>
              {(e.response) ? e.response.data.message : 'Something went wrong!'}
              </div>
            ),
            level: 'error',
            position: "tr",
            autoDismiss: 15
          });
      });
    }
  }

  addPriceDetails() {
    let newPrice = {id: (this.state.pricesData.length + 1), price: '', qty: '', offerPercent: ''};
    this.setState({
      pricesData: [...this.state.pricesData, newPrice]
    })
  }

  removePriceDetails(id) {
    let clearedPrice = this.state.pricesData.filter((price) => price.id != id);
    this.setState({
      pricesData: clearedPrice
    }) 
   }

   updatePriceDate(id, key, val) {
      let priceCol = this.state.pricesData;
      priceCol.map((price) => {
        if(price.id === id){
          price[key] = val
        }
      })
      console.log(priceCol)

   }

  render() {
    const { errors, isFormSubmit } = this.state;
    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />
        <Grid fluid>
          <Row>
            <Col md={8}>
            <Card
                title="Create Product"
                content={
                  <form onSubmit={this.handleSubmit} noValidate>
                    
                    <div className="form-group">
                      <label>Name</label>
                      <input type="text" className="form-control" name="name" placeholder="Enter name"  onChange={this.handleChange} noValidate />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.name}</p>
                        )
                      }
                    </div>
                    <Col md={6}>
                    <div className="form-group">
                      <label>Category</label>
                      <select name="category" className="form-control" onChange={this.handleChange}>
                      <option value="">Select Category</option>
                      {this.state.categoryCol.length > 0 && (
                        this.state.categoryCol.map((e, key) => {
                          return (
                            <option value={e._id} key={key}>{e.name}</option>
                          )
                        })
                      )}
                      </select>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.category}</p>
                        )
                      }
                    </div>
                    </Col>
                    <Col md={6}>

                    <div className="form-group">
                      <label>Album</label>
                      <select name="album" className="form-control" onChange={this.handleChange}>
                      <option value="">Select Album</option>
                      {this.state.albumCol.length > 0 && (
                        this.state.albumCol.map((e, key) => {
                          return (
                            <option value={e._id} key={key}>{e.name}</option>
                          )
                        })
                      )}
                      </select>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.album}</p>
                        )
                      }
                    </div>
                    </Col>

                    <div className="form-group">
                      <label>Description</label>
                      <textarea className="form-control" name="description" placeholder="Description of product" onChange={this.handleChange}></textarea>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.description}</p>
                        )
                      }
                    </div>

                    {/* <Col md={6}>

                    <div className="form-group">
                      <label>Direction to use</label>
                      <textarea className="form-control" name="directuse" placeholder="Direction to use" onChange={this.handleChange}></textarea>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.directuse}</p>
                        )
                      }   
                    </div>
                    </Col> */}

                    <div className="form-group">
                      <label>Footnote</label>
                      <textarea className="form-control" name="footnote" placeholder="Footnote of product" onChange={this.handleChange}></textarea>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.footnote}</p>
                        )
                      }   
                    </div>

                    <div className="form-group">
                      <label>Ingredients</label>
                      <input type="text" className="form-control" name="ingredients" placeholder="Enter ingredients"  onChange={this.handleChange} noValidate />
                      <small className="text-danger">(Every ingredient should seperated by comma.)</small>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.ingredients}</p>
                        )
                      }   
                    </div>                    

                    <div className="form-group">
                      <label>Images</label>
                      <input type="file" className="form-control" multiple noValidate onChange={this.fileChangedHandler}/>
                      <small className="text-danger">(Choose multiple images.)</small>
                      {
                       ( isFormSubmit && errors.images.length > 0)&& (
                          errors.images.map((err, key) => {
                           return (
                              <p key={key} className="txt-error">{err}</p>
                           ) 

                          })
                        )
                      }
                    </div>

                    <div className="form-group">
                      <Button bsStyle="link" onClick={()=>this.addPriceDetails()}>Add price details</Button>
                    </div>

                    {
                      this.state.pricesData.length > 0 && (
                        this.state.pricesData.map((e, k) => {
                          return (
                            <Row className="bg-light-grey" key={k}>
                              <Col md={2}>
                                <div className="form-group">
                                  <label>Price</label>
                                  <input type="number" min={0} className="form-control"  onChange={(ele) => this.updatePriceDate(e.id, 'price', ele.target.value)} noValidate />
                                </div>
                              </Col>
                              
                              <Col md={2}>
                                <div className="form-group">
                                  <label>offer Percent</label>
                                  <input type="number" min={0} max={100}  className="form-control" onChange={(ele) => this.updatePriceDate(e.id, 'offerPercent', ele.target.value)}  noValidate />
                                </div>
                              </Col>
                              <Col md={2}>
                                <div className="form-group">
                                  <label>quantity</label>
                                  <input type="number" min={0} className="form-control" onChange={(ele) => this.updatePriceDate(e.id, 'qty', ele.target.value)} noValidate />
                                </div>
                              </Col>
                              <Col md={2}>
                                <div className="form-group">
                                  <label>Unit</label>
                                  <select name="unit" className="form-control" onChange={(ele) => this.updatePriceDate(e.id, 'unit', ele.target.value)}>
                                    <option value="">Select</option>
                                    {this.state.productUnits.length > 0 && (
                                      this.state.productUnits.map((e, key) => {
                                        return (
                                          <option value={e._id} key={key}>{e.name}</option>
                                        )
                                      })
                                    )}
                                  </select>
                                </div>
                              </Col>

                              <Col md={2}>
                                <div className="form-group" onChange={(ele) => this.updatePriceDate(e.id, 'type', ele.target.value)}>
                                  <label>Cake Type</label>
                                  <select name="type" className="form-control">
                                    <option value="">Select</option>
                                    <option value="1">Fresh Cream</option>
                                    <option value="2">Butter Cream</option>
                                  </select>
                                </div>
                              </Col>

                              <Col md={2}>
                                <Button bsStyle="link" className="mr-t25px" onClick={() => this.removePriceDetails(e.id)}> 
                                  Remove
                                </Button>
                              </Col>
                            </Row>
                          )
                        })
                      )
                    }

                    <Link className="mgr-5 btn btn-default" to="/admin/products">Cancel</Link>

                    <Button bsStyle="info"  type="submit">
                      Create
                    </Button>

                    <div className="clearfix" />
                  </form>
                }
              />
            </Col>
            {
              this.state.tempImgs.length > 0 && (
                  <Col md={4}>
                    <Card
                        title="Product Images"
                        content={
                            <Row className="gallery-scroll">
                                {
                                    this.state.tempImgs.map((item, key) => {
                                        return (
                                            <Col xs={6} md={12} className="mb-btm" key={key}>
                                              <div className="image-card" key={key}>
                                                 <img src={item} alt="product" />     
                                               </div>
                                            </Col>
                                        )
                                    })
                                }
                            </Row>
                        }
                    />
                    </Col>
              )
            }
            
          </Row>
        </Grid>
      </div>
    );
  }
}

export default ProductCreate;
