import React, { Component } from "react";
import { FormGroup, FormControl, Button, Row, Col, Table } from "react-bootstrap";
import { Link } from "react-router-dom";
import axios from 'axios';
import NotificationSystem from "react-notification-system";
import * as moment from 'moment';
import '../billstyle.css';
import { style } from "../../../variables/Variables.jsx";
import { authHeader } from '../../../configs/helpers';
import { ApiUrlHost, apiUrls } from '../../../configs/configs';
import ReactPaginate from 'react-paginate';
import PrintPriviewModal from '../../../components/PopUps/PrintBill';
import Modal from "react-modal";
import { Multiselect } from 'multiselect-react-dropdown';

const _ = require('lodash');
const customStyles = {
    content: {
        top: "50%",
        left: "50%",
        right: "auto",
        bottom: "auto",
        // marginRight: '-50%',
        transform: "translate(-50%, -50%)",
        height: "500px", // <-- This sets the height
        overlfow: "scroll", // <-- This tells the modal to scrol
        minWidth: "50%",
    },
};
class StockOrdersList extends Component {
    constructor(props) {
        super(props);
        this.state = {
            branches: [],
            categories: [],
            searchLoad: false,
            currentPage: 0,
            searchbranch: '',
            searchbill: '',
            status: '',
            category: '',
            deliveryDate: '',
            deliveryDateTo: '',
            createdDate: '',
            createdDateTo: '',
            searchRecords: [],
            totalSearchRec: 0,
            oneBillOrder: [],
            oneBillid: '',
            balanceAmt: '',
            stockOrderPayment: null,
            payment_status: false,
            showOrderView: false,
            openPrintPopUp: false,
            billPreviewData: [],
            currBillStatus: '',
            groupedData: [],
            openCategoryPopup: false,
            selectedCategories: []

        }
    }
    componentWillMount() {
        this.getCategoryList();
        this.getAllBranchEmployees();
        this.getAllRecords();
    }

    openPrintPopUpModalForOneOrder() {
        const billPreview = [];
        if (this.state.oneBillOrder && this.state.oneBillOrder[0] && this.state.oneBillOrder[0].pastries) {
            this.state.oneBillOrder[0].pastries.forEach((pastry) => {

                billPreview.push({
                    particulars: this.getProductName(pastry.data, this.state.oneBillOrder[0].pastryDetails),
                    rate: pastry.data.price,
                    categoryName: this.getProductCategoryName(pastry.data, this.state.oneBillOrder[0].pastryDetails),
                    qty: pastry.data.sendQty,
                    amt: pastry.data.price * pastry.data.sendQty,
                    branch: this.state.oneBillOrder[0].employees ? this.state.oneBillOrder[0].employees.firstname : '',
                    bill: this.state.oneBillOrder[0]._id,
                    billDate: this.state.oneBillOrder[0].created_at
                })
            })
        }
        const grouped = _.groupBy(billPreview, function (order) {
            return order.categoryName;
        });

        this.setState({
            openPrintPopUp: true,
            groupedData: grouped,
            billPreviewData: billPreview
        })
    }

    closePopup() {
        this.setState({
            openPrintPopUp: false
        })
    }

    getAllBranchEmployees() {
        axios({
            method: 'GET',
            url: apiUrls.BRANCH_EMPLOYEE_LIST,
            headers: {
                Authorization: authHeader()
            }
        }).then(result => {
            if (result.status === 200 && result.data.data) {
                this.setState({
                    branches: result.data.data
                });
            } else {
                this.setState({
                    branches: [],
                });
            }
        }).catch(e => {
            this.setState({
                branches: []
            });

        });
    }

    getPaginateRec(index) {
        this.setState({
            currentPage: index
        }, () => {
            this.getAllRecords();
        })
    }

    getProductName(selected, items) {
        let name = '-';
        items.forEach(element => {
            if (element.info._id === selected._id) {
                name = element.info.name
            }
        });
        return name;
    }

    getProductCategoryName(selected, items) {
        let name = 'NA';
        items.forEach(element => {
            if (element.info._id === selected._id) {
                name = (element.info.categoryData && element.info.categoryData[0]) ? element.info.categoryData[0].name : 'NA'
            }
        });
        return name;
    }

    getUnitName(selected, items) {
        let unit = '';
        items.forEach(element => {
            if (element.info._id === selected._id) {
                unit = element.info.unitDetails ? element.info.unitDetails.name : ''
            }
        });
        return unit;
    }

    getCategoryList() {
        axios({
            method: 'GET',
            url: apiUrls.PRODUCT.getAllCategoryPastry,
            headers: {
                Authorization: authHeader()
            }
        }).then(result => {
            if (result.status === 200) {
                this.setState({
                    categories: result.data.data,
                });
            } else {
                this.setState({
                    categories: []
                });
            }
        }).catch(e => {
            this.setState({
                categories: []
            });
        });
    }

    getTotalSendItemorders(items) {
        let total = 0;
        items.forEach(element => {
            if (element.sendQty) {
                total = total + parseFloat(element.sendQty);
            }
        });
        return total;
    }

    setData(e) {
        this.setState({
            deliveryDate: e.target.value
        }, () => {
            this.getAllRecords()
        })
    }

    setDataTo(e) {
        this.setState({
            deliveryDateTo: e.target.value
        }, () => {
            this.getAllRecords()
        })
    }

    setCreateData(e) {
        this.setState({
            createdDate: e.target.value
        }, () => {
            this.getAllRecords()
        })
    }

    setCreateDataTo(e) {
        this.setState({
            createdDateTo: e.target.value
        }, () => {
            this.getAllRecords()
        })
    }

    getAllRecords() {
        this.setState({
            searchLoad: true
        })

        var params = {
            page: this.state.currentPage
        };

        if (this.state.searchbranch) {
            params.branch = this.state.searchbranch
        }

        if (this.state.searchbill) {
            params.bill = this.state.searchbill
        }

        if (this.state.status) {
            params.status = this.state.status
        }

        if (this.state.createdDate) {
            params.createdDate = this.state.createdDate
        }

        if (this.state.createdDateTo) {
            params.createdDateEnd = this.state.createdDateTo
        }

        if (this.state.deliveryDate) {
            params.deliveryDate = this.state.deliveryDate
        }

        if (this.state.deliveryDateTo) {
            params.deliveryDateTo = this.state.deliveryDateTo
        }

        axios({
            method: 'GET',
            url: apiUrls.ORDERS.stockBillOrder,
            headers: {
                Authorization: authHeader()
            },
            params: params
        }).then(result => {
            if (result.status === 200 && result.data.data && result.data.data[0]) {
                this.setState({
                    searchRecords: result.data.data[0].paginatedResults,
                    searchLoad: false,
                    totalSearchRec: result.data.data[0].totalCount[0].count
                });
            } else {
                this.setState({
                    searchRecords: [],
                    searchLoad: false
                });
            }
        }).catch(e => {
            this.setState({
                searchRecords: [], searchLoad: false
            });

        });
    }


    getExcelRecords() {
        var params = {};
        if (this.state.searchbranch) {
            params.branch = this.state.searchbranch
        }

        if (this.state.searchbill) {
            params.bill = this.state.searchbill
        }

        if (this.state.status) {
            params.status = this.state.status
        }

        if (this.state.category) {
            params.category = this.state.category
        }

        if (this.state.deliveryDate) {
            params.deliveryDate = this.state.deliveryDate
        }

        if (this.state.createdDate) {
            params.createdDate = this.state.createdDate
        }

        axios({
            method: 'GET',
            url: apiUrls.ORDERS.downloadStocks,
            headers: {
                Authorization: authHeader()
            },
            params: params
        }).then(result => {
            if (result.data.filename) {
                window.open(ApiUrlHost + '/' + result.data.filename);
            }
        }).catch(e => {

        });
    }

    getTotalOrderedItemorders(items) {
        let total = 0;
        items.forEach(element => {
            if (element.qty) {
                total = total + parseFloat(element.qty);
            }
        });
        return total;
    }

    getTotalorders(items) {
        let total = 0;
        items.forEach(element => {
            total = total + 1;
        });
        return total;
    }

    getTotalCompletedorders(items) {
        let total = 0;
        items.forEach(element => {
            if (element.status == '2')
                total = total + 1;
        });
        return total;
    }

    getTotalPendingorders(items) {
        let total = 0;
        items.forEach(element => {
            if (element.status == '1')
                total = total + 1;
        });
        return total;
    }

    getTotalAmountOrdered(items) {
        let totalPrice = 0;
        items.forEach(element => {
            const onePrice = element.price * element.qty;
            totalPrice = totalPrice + parseFloat(onePrice)
        });
        return totalPrice;
    }

    getTotalAmount(items) {
        let totalPrice = 0;
        items.forEach(element => {
            const onePrice = element.price * element.sendQty;
            totalPrice = totalPrice + parseFloat(onePrice)
        });
        return totalPrice;
    }
    getStatusText(status) {
        let text = '-';
        if (status == '1') {
            text = 'Pending';
        } else if (status == '2') {
            text = 'Completed';
        }

        return text;
    }

    getOneBillRecord(id) {
        this.setState({
            oneBillid: id
        }, () => {
            this.getOneData();
        });
    }

    getOneData() {
        if (this.state.oneBillid) {
            this.setState({
                showOrderView: true
            })
            var params = {};
            // if (this.state.category) {
            //     params.category = this.state.category
            // }
            if (this.state.selectedCategories.length > 0) {
                params.category = this.state.selectedCategories;
            }

            if (this.state.currBillStatus) {
                params.currBillStatus = this.state.currBillStatus
            }

            axios({
                method: 'GET',
                url: apiUrls.ORDERS.oneStockBill + '/' + this.state.oneBillid,
                headers: {
                    Authorization: authHeader()
                },
                params: params
            }).then(result => {

                if (result.status === 200 && result.data.data) {
                    result.data.data[0].pastry.sort(function (o1, o2) {
                        return new Date(o1.delivery_date) - new Date(o2.delivery_date);
                    });

                    this.setState({
                        oneBillOrder: result.data.data,
                        stockOrderPayment: result.data.payment ? result.data.payment : null
                    });
                } else {
                    this.setState({
                        oneBillOrder: [],
                        stockOrderPayment: null
                    });
                }
            }).catch(e => {
                this.setState({
                    oneBillOrder: [],
                    stockOrderPayment: null
                });
            });
        }
    }
    changePastryQty(pastry, qty, items, order) {

        const tmpLiveData = items[0];

        tmpLiveData.pastries.forEach(_p => {
            if ((_p.data._id === pastry) && order === _p.orderId.id) {
                _p.data.sendQty = qty
            }
        })

        this.setState({
            oneBillOrder: [tmpLiveData]
        })

    }

    updateSendQty(pastry, order, qty) {
        this.setState({ _notificationSystem: this.refs.notificationSystem });
        var _notificationSystem = this.refs.notificationSystem;

        const sendData = {
            pastry: pastry,
            orderId: order,
            sendQty: qty
        }

        axios({
            method: 'POST',
            url: apiUrls.ORDERS.updateStockQty,
            data: sendData,
            headers: {
                'Content-Type': 'application/json',
                Authorization: authHeader()
            }
        }).then(result => {
            if (result.status === 200) {
                const _tempOneData = this.state.oneBillOrder[0];
                if (_tempOneData && _tempOneData.pastries && _tempOneData.pastries.length > 0) {
                    _tempOneData.pastries.map(pastryItem => {
                        if (pastryItem.data && pastry == pastryItem.data._id) {
                            pastryItem.data.status = 2
                        }
                    })
                }
                const _tempOne = [_tempOneData];
                this.setState({
                    oneBillOrder: _tempOne
                })
            }
        }).catch(e => {
            _notificationSystem.addNotification({
                title: <span data-notify="icon" className="pe-7s-close-circle" />,
                message: (
                    <div>
                        {(e.response) ? e.response.data.message : 'Something went wrong!'}
                    </div>
                ),
                level: 'error',
                position: "tr",
                autoDismiss: 15
            });
        });
    }
    updateBalance = (billno) => {
        if (this.state.balanceAmt) {

            this.setState({ _notificationSystem: this.refs.notificationSystem, isFormSubmit: true });
            var _notificationSystem = this.refs.notificationSystem;

            var bodyFormData = { 'amount': this.state.balanceAmt, status: (this.state.payment_status === true) ? '2' : '1' };

            axios({
                method: 'POST',
                url: apiUrls.ORDERS.stockPayment + billno,
                data: bodyFormData,
                headers: {
                    'Content-Type': 'application/json',
                    Authorization: authHeader()
                }
            }).then(result => {
                if (result.status === 200) {
                    this.getOneData();
                    _notificationSystem.addNotification({
                        title: <span data-notify="icon" className="pe-7s-check" />,
                        message: (
                            <div>
                                Balance updated.
                            </div>
                        ),
                        level: 'success',
                        position: "tr",
                        autoDismiss: 15
                    });

                }
            }).catch(e => {
                console.log(e)
                _notificationSystem.addNotification({
                    title: <span data-notify="icon" className="pe-7s-close-circle" />,
                    message: (
                        <div>
                            {(e.response) ? e.response.data.message : 'Something went wrong!'}
                        </div>
                    ),
                    level: 'error',
                    position: "tr",
                    autoDismiss: 15
                });
            });
        }
    }


    categorySelection(selectedList) {
        const tempSelected = [];
        selectedList.forEach(item => {
            tempSelected.push(item._id)
        })
        this.setState({
            selectedCategories: tempSelected
        }, () => {
            this.getOneData()
        });
    }

    render() {
        return (
            <div className="bill-container">
                <NotificationSystem ref="notificationSystem" style={style} />
                <PrintPriviewModal subTitle={'(Stock Order)'} groupedData={this.state.groupedData}
                    closePopup={() => this.closePopup()} open={this.state.openPrintPopUp} data={this.state.billPreviewData} />

                <div className="filter-section">
                    <Row>
                        <Col md={2}>
                            <FormGroup>
                                <label>Bill No</label>

                                <FormControl type="text"
                                    inputRef={(ref) => { this.sbill = ref }}

                                    onChange={() => this.setState({ searchbill: this.sbill.value }, () => { this.getAllRecords() })}

                                >
                                </FormControl>
                            </FormGroup>
                        </Col>
                        <Col md={2}>
                            <FormGroup>
                                <label>Choose Branch</label>

                                <FormControl type="text"
                                    componentClass="select"
                                    inputRef={(ref) => { this._sbranch = ref }}
                                    onChange={() => this.setState({ searchbranch: this._sbranch.value }, () => { this.getAllRecords() })}
                                >
                                    <option value="">Branch</option>
                                    {this.state.branches.map((store) => {
                                        return (
                                            <option value={store._id} key={store._id}>{store.firstname}</option>
                                        )
                                    })}
                                </FormControl>
                            </FormGroup>
                        </Col>

                        <Col md={2}>
                            <FormGroup>
                                <label>Choose Status</label>

                                <FormControl type="text"
                                    componentClass="select"
                                    inputRef={(ref) => { this._status = ref }}
                                    onChange={() => this.setState({ status: this._status.value }, () => { this.getAllRecords() })}

                                >
                                    <option value="">Status</option>
                                    <option value="1">Pending</option>
                                    <option value="2">Completed</option>
                                </FormControl>
                            </FormGroup>
                        </Col>



                        <Col md={2}>
                            <FormGroup>
                                <label>
                                    Created Date From
                                    {this.createDate && this.createDate.value && (
                                        <span
                                            style={{ color: "tomato", fontSize: 8 }}
                                            onClick={() => {
                                                this.createDate.value = "";
                                                this.setState({ createdDate: this.createDate.value }, () => {
                                                    this.getAllRecords()
                                                });
                                            }}
                                        >
                                            {" "}
                                            <i className="fa fa-times-circle fa-2x" />
                                        </span>
                                    )}
                                </label>
                                <FormControl type="date"
                                    inputRef={(ref) => {
                                        this.createDate = ref;
                                    }}
                                    onChange={(e) => this.setCreateData(e)}
                                >
                                </FormControl>
                            </FormGroup>
                        </Col>
                        <Col md={2}>
                            <FormGroup>
                                <label>
                                    Created Date To
                                    {this.createDateTo && this.createDateTo.value && (
                                        <span
                                            style={{ color: "tomato", fontSize: 8 }}
                                            onClick={() => {
                                                this.createDateTo.value = "";
                                                this.setState({ createdDateTo: this.createDateTo.value }, () => {
                                                    this.getAllRecords()
                                                });
                                            }}
                                        >
                                            {" "}
                                            <i className="fa fa-times-circle fa-2x" />
                                        </span>
                                    )}
                                </label>
                                <FormControl type="date"
                                    inputRef={(ref) => {
                                        this.createDateTo = ref;
                                    }}
                                    onChange={(e) => this.setCreateDataTo(e)}
                                >
                                </FormControl>
                            </FormGroup>
                        </Col>
                        <Col md={3}>
                            <FormGroup>
                                <label>
                                    Delivery Date
                                    {this.toDate && this.toDate.value && (
                                        <span
                                            style={{ color: "tomato", fontSize: 8 }}
                                            onClick={() => {
                                                this.toDate.value = "";
                                                this.setState({ deliveryDate: this.toDate.value }, () => {
                                                    this.getAllRecords()
                                                });
                                            }}
                                        >
                                            {" "}
                                            <i className="fa fa-times-circle fa-2x" />
                                        </span>
                                    )}
                                </label>
                                <FormControl type="date"
                                    inputRef={(ref) => {
                                        this.toDate = ref;
                                    }}
                                    onChange={(e) => this.setData(e)}
                                >
                                </FormControl>
                            </FormGroup>
                        </Col>
                        <Col md={3}>
                            <FormGroup>
                                <label>
                                    Delivery Date To
                                    {this.toDateDel && this.toDateDel.value && (
                                        <span
                                            style={{ color: "tomato", fontSize: 8 }}
                                            onClick={() => {
                                                this.toDateDel.value = "";
                                                this.setState({ deliveryDateTo: this.toDateDel.value }, () => {
                                                    this.getAllRecords()
                                                });
                                            }}
                                        >
                                            {" "}
                                            <i className="fa fa-times-circle fa-2x" />
                                        </span>
                                    )}
                                </label>
                                <FormControl type="date"
                                    inputRef={(ref) => {
                                        this.toDateDel = ref;
                                    }}
                                    onChange={(e) => this.setDataTo(e)}
                                >
                                </FormControl>
                            </FormGroup>
                        </Col>
                        <Col md={2} className="mar-t-25px">
                            <Button variant="dark" className="export-btn" onClick={() => this.getExcelRecords()}>Export</Button>
                        </Col>
                    </Row>
                </div>
                <div className="search-results">
                    <Table responsive >
                        <thead>
                            <tr>
                                <th>#</th>
                                <th>Bill no</th>
                                <th>Total items</th>
                                <th>Total completed items</th>
                                <th>Total Pending items</th>
                                <th>Ordered Bill Value</th>
                                <th>Send Items Bill Value</th>
                                <th>Status</th>
                                <th>View</th>
                            </tr>
                        </thead>
                        <tbody>
                            {(this.state.searchLoad === true) && (
                                <tr>
                                    <td colSpan={7}>Loading...</td>
                                </tr>
                            )}

                            {(this.state.searchRecords.length > 0 && this.state.searchLoad === false) && (
                                this.state.searchRecords.map((pastryitems, key) => {
                                    return (<tr key={(key + 1) * 123}>
                                        <td>{key + 1}</td>
                                        <td>{pastryitems._id}</td>
                                        <td> {this.getTotalorders(pastryitems.pastry)}</td>
                                        <td>{this.getTotalCompletedorders(pastryitems.pastry)}</td>
                                        <td>{this.getTotalPendingorders(pastryitems.pastry)}</td>
                                        <td>{this.getTotalAmountOrdered(pastryitems.pastry)}</td>
                                        <td>{this.getTotalAmount(pastryitems.pastry)}</td>
                                        <td>{this.getStatusText(pastryitems.status)}</td>
                                        <td><p className="text-blue" onClick={() => this.getOneBillRecord(pastryitems._id)}>Click</p></td>
                                    </tr>)
                                })
                            )}


                            {(this.state.searchRecords.length === 0 && this.state.searchLoad === false) && (
                                <tr>
                                    <td colSpan={7}>No bills found</td>
                                </tr>
                            )}
                        </tbody>
                    </Table>
                    <div className="footer text-center">
                        <ReactPaginate
                            previousLabel={'previous'}
                            nextLabel={'next'}
                            breakLabel={'...'}
                            breakClassName={'break-me'}
                            pageCount={Math.ceil(this.state.totalSearchRec / 5)}
                            marginPagesDisplayed={2}
                            pageRangeDisplayed={5}
                            onPageChange={(index) => this.getPaginateRec(index.selected)}
                            containerClassName={'pagination'}
                            subContainerClassName={'pages pagination'}
                            activeClassName={'active'}
                        />
                    </div>
                </div>

                {this.state.showOrderView === true && (
                    <div className="live-order-section" >
                        <Row>
                            <Col md={2}>
                                <h3>Stock Bill Detials</h3>
                            </Col>
                            <Col md={2}>
                                <FormGroup>
                                    <label>Choose Category</label>
                                    <Multiselect
                                        options={this.state.categories} // Options to display in the dropdown
                                        // selectedValues={this.state.selectedValue} // Preselected value to persist in dropdown
                                        onSelect={this.categorySelection.bind(this)} // Function will trigger on select event
                                        onRemove={this.categorySelection.bind(this)} // Function will trigger on remove event
                                        displayValue="name" // Property name to display in the dropdown options
                                    />
                                    {/* <p className="filter-clear-txt" onClick={() => { this.setState({ openCategoryPopup: true }) }}> <i className="fa fa-check" />Apply filers</p>
                                    {this.state.selectedCategories.length > 0 && (
                                        <p className="filter-clear-txt" onClick={() => { this.setState({ selectedCategories: [] }, () => { this.getOneData(); }) }}> <i className="fa fa-times-circle" /> Clear Filter</p>
                                    )}
                                    <Modal
                                        isOpen={this.state.openCategoryPopup}
                                        ariaHideApp={false}
                                        style={customStyles}
                                        contentLabel="Category Modal"
                                    >
                                        <div className="category-block">
                                            {this.state.categories.map((store) => {
                                                return (
                                                    <div className="form-group-flex" key={store._id}>
                                                        <input type="checkbox" value={store._id} defaultChecked={this.state.selectedCategories.indexOf(store._id) > -1 ? true : false} className="form-control check-box-width-custom" name="pas" noValidate onClick={() => this.categorySelection(store._id)} /> &nbsp; {store.name}
                                                    </div>
                                                );
                                            })}
                                            <button className="btn btn-info btn-brown float-right" type="button" onClick={() => { this.setState({ openCategoryPopup: false }) }}>
                                                Close
                                        </button>
                                        </div>


                                    </Modal> */}

                                    {/* <FormControl type="text"
                                        componentClass="select"
                                        inputRef={(ref) => { this.category = ref }}
                                        onChange={() => this.setState({ category: this.category.value }, () => { this.getOneData() })}
                                    >
                                        <option value="">Category</option>
                                        {this.state.categories.map((category) => {
                                            return (
                                                <option value={category._id} key={category._id}>{category.name}</option>
                                            )
                                        })}
                                    </FormControl> */}
                                </FormGroup>
                            </Col>
                            <Col md={2}>
                                <FormGroup>
                                    <label>Choose Status</label>

                                    <FormControl
                                        type="text"
                                        componentClass="select"
                                        inputRef={(ref) => {
                                            this._curr_bill_status = ref;
                                        }}
                                        onChange={() => this.setState({ currBillStatus: this._curr_bill_status.value }, () => { this.getOneData() })}
                                    >
                                        <option value="">Status</option>
                                        <option value="1">Pending</option>
                                        <option value="2">Completed</option>
                                    </FormControl>
                                </FormGroup>
                            </Col>

                            <Col md={2} className="mar-t-25px">
                                <button id="printInvoice" className="btn btn-info" onClick={() => this.openPrintPopUpModalForOneOrder()}><i className="fa fa-print"></i> Print Preview</button>
                            </Col>
                        </Row>

                        {this.state.oneBillOrder.length > 0 && (
                            <Table responsive bordered hover ref={el => (this.componentRefPending = el)}>
                                <thead>
                                    <tr>
                                        <td colSpan={11}>
                                            Bill no: {this.state.oneBillOrder[0]._id}
                                        </td>
                                    </tr>
                                    <tr>
                                        <th>#</th>
                                        <th>Products</th>
                                        <th>Qty Ordered</th>
                                        <th>Unit price</th>
                                        <th>Total price</th>
                                        <th>Sending Qty</th>
                                        <th>Unit price</th>
                                        <th>Sending Total</th>
                                        <th>Ordered Date</th>
                                        <th>Delivery Date</th>
                                        <th>Branch</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {this.state.oneBillOrder[0].pastries.length > 0 && (
                                        this.state.oneBillOrder[0].pastries.map((oneItem, key) => {
                                            const pastry = oneItem.data;
                                            return (<tr key={key + 1}>
                                                <td>{key + 1}</td>
                                                <td>{this.getProductName(pastry, this.state.oneBillOrder[0].pastryDetails)}</td>
                                                <td>{pastry.qty}</td>
                                                <td>₹ {pastry.price} {this.getUnitName(pastry, this.state.oneBillOrder[0].pastryDetails)}</td>
                                                <td>₹ {pastry.total}</td>
                                                <td className={pastry.status == '1' ? "bill-incomplete" : "bill-complete"}>
                                                    {pastry.status == '1' && (<div>
                                                        <input type="number" defaultValue={pastry.sendQty} onChange={(ele) => this.changePastryQty(pastry._id, ele.target.value, this.state.oneBillOrder, oneItem.orderId.id)} />
                                                        <button onClick={() => this.updateSendQty(pastry._id, oneItem.orderId.id, pastry.sendQty, 'yes')}><i className="fa fa-check"></i></button>
                                                    </div>)}
                                                    {pastry.status == '2' && (<div>
                                                        {/* {pastry.sendQty}<i className="fa fa-check"></i> */}
                                                        <input type="number" defaultValue={pastry.sendQty} onChange={(ele) => this.changePastryQty(pastry._id, ele.target.value, this.state.oneBillOrder, oneItem.orderId.id)} />
                                                        <button onClick={() => this.updateSendQty(pastry._id, oneItem.orderId.id, pastry.sendQty, 'yes')}><i className="fa fa-check-square-o"></i></button>

                                                    </div>)}

                                                </td>
                                                <td>₹ {pastry.price}  {this.getUnitName(pastry, this.state.oneBillOrder[0].pastryDetails)}</td>
                                                <td>₹ {pastry.price * pastry.sendQty}</td>
                                                <td>{moment(oneItem.orderId.date).format('DD/MM/YYYY')}</td>

                                                <td>{moment(pastry.delivery_date).format('DD/MM/YYYY') + ' @ ' + moment(pastry.delivery_time).format('hh:mm a')}</td>
                                                <td>{this.state.oneBillOrder[0].employees ? this.state.oneBillOrder[0].employees.firstname : '-'}</td>
                                            </tr>)
                                        })
                                    )}
                                    <tr className="text-dark-row">
                                        <td colSpan={2}>Total</td>
                                        <td>{this.getTotalOrderedItemorders(this.state.oneBillOrder[0].pastry)}</td>
                                        <td></td>
                                        <td>₹ {this.getTotalAmountOrdered(this.state.oneBillOrder[0].pastry)}</td>
                                        <td>{this.getTotalSendItemorders(this.state.oneBillOrder[0].pastry)}</td>
                                        <td></td>
                                        <td>₹ {this.getTotalAmount(this.state.oneBillOrder[0].pastry)}</td>
                                        <td></td>
                                        <td></td>
                                        <td></td>
                                    </tr>
                                    {
                                        this.state.stockOrderPayment && (
                                            <>
                                                {(this.state.stockOrderPayment.invoiceBreakUp && this.state.stockOrderPayment.invoiceBreakUp.length > 0) && (
                                                    this.state.stockOrderPayment.invoiceBreakUp.map(item => {
                                                        return <tr className="text-dark-row" key={item._id}>
                                                            <td colSpan={7}>Paid on {moment(item.created_at).format('DD/MM/YYYY')}</td>
                                                            <td>₹ {item.paid}	</td>
                                                        </tr>
                                                    })
                                                )}
                                                <tr className="text-dark-row">
                                                    <td colSpan={7}>Balance</td>
                                                    <td>₹ {this.state.stockOrderPayment.balance >= 0 ? this.state.stockOrderPayment.balance : 'Refund ' + Math.abs(this.state.stockOrderPayment.balance)}	</td>
                                                </tr>
                                            </>
                                        )
                                    }
                                </tbody>
                            </Table>
                        )}


                        {this.state.stockOrderPayment && (
                            <div className="balance-frm-wrap">
                                ₹<input type="number" onChange={(e) => this.setState({ balanceAmt: e.target.value })} placeholder="Pay balance amount" />
                                <input type="checkbox"
                                    defaultChecked={this.state.stockOrderPayment.status === '2' ? true : false}
                                    onClick={() => {
                                        this.setState({
                                            payment_status: !this.state.payment_status
                                        })
                                    }
                                    }
                                    name="payment_status" /> <span>Close Payment</span>
                                <button className="btn btn-default" onClick={() => this.updateBalance(this.state.oneBillOrder[0]._id)}>Update</button>
                            </div>
                        )}
                    </div>
                )}

            </div>
        )
    }
}
export default StockOrdersList;
