import React, { Component } from "react";
import "../../assets/css/custom.css";
import "bootstrap/dist/css/bootstrap.min.css";
import { Col, Table, Modal } from "react-bootstrap";
import Button from "components/CustomButton/CustomButton.jsx";
import axios from "axios";
import ReactPaginate from "react-paginate";
import "../../assets/css/custom.css";
import { authHeader } from "../../configs/helpers";
import { apiUrls } from "../../configs/configs";
import * as moment from "moment";
import ReactToPrint from "react-to-print";
import InfiniteScroll from "react-infinite-scroll-component";

const _ = require("lodash");

export class SalesOrders extends Component {
  constructor(props, context) {
    super(props, context);
    this.handleClose = this.handleClose.bind(this);
    this.state = {
      show: false,
      allSalesOrders: [],
      totalSalesQtyArray: [],
      totalPages: 0,
      contentPerPage: 10,
      currentPage: 0,
      currentViewItem: null,
      billno: "",
      orderFromDate: '',
      loading: false,
      orderToDate: '',
      cashiers: [],
      salesMans: [],
      terminals: [],
      cashier: '', salesman: '', terminal: ''
    };
  }

  componentDidMount() {
    this.getCashierList();
    this.getTerminalList();
    this.getSalesList()
    this.getList();
  }

  getCashierList() {
    axios({
      method: "GET",
      url: apiUrls.SALESORDERS.cashiers,
      headers: {
        Authorization: authHeader(),
      },
    })
      .then((result) => {
        if (result.status === 200) {
          this.setState({
            cashiers: result.data.data,
          });
        }
      })
      .catch((err) => {
        this.setState({
          cashiers: [],
        });
      });
  }

  getTerminalList() {
    axios({
      method: "GET",
      url: apiUrls.SALESORDERS.terminals,
      headers: {
        Authorization: authHeader(),
      },
    })
      .then((result) => {
        if (result.status === 200) {
          this.setState({
            terminals: result.data.data,
          });
        }
      })
      .catch((err) => {
        this.setState({
          terminals: [],
        });
      });
  }

  getSalesList() {
    axios({
      method: "GET",
      url: apiUrls.SALESORDERS.salesman,
      headers: {
        Authorization: authHeader(),
      },
    })
      .then((result) => {
        if (result.status === 200) {
          this.setState({
            salesMans: result.data.data,
          });
        }
      })
      .catch((err) => {
        this.setState({
          salesMans: [],
        });
      });
  }

  getList() {
    var params = {
      page: this.state.currentPage,
    };
    if (this.state.billno) {
      params.billNo = this.state.billno;
    }
    if (this.state.orderFromDate) {
      params.orderFromDate = this.state.orderFromDate;
    }
    if (this.state.orderToDate) {
      params.orderToDate = this.state.orderToDate;
    }

    if (this.state.cashier) {
      params.cashier = this.state.cashier;
    }
    if (this.state.salesman) {
      params.salesman = this.state.salesman;
    }
    if (this.state.terminal) {
      params.terminal = this.state.terminal;
    }
    this.setState({
      loading: true,
    });

    axios({
      method: "POST",
      url: apiUrls.SALESORDERS.salesOrders,
      headers: {
        Authorization: authHeader(),
      },
      params: params,
    })
      .then((result) => {
        if (result.status === 200) {
          var temp = this.state.allSalesOrders;
          temp = temp.concat(result.data.data);

          this.setState({
            allSalesOrders: temp,
            totalPages: Math.floor(result.data.total / this.state.contentPerPage),
          });
        }
        this.setState({
          loading: false,
        });

      })
      .catch((err) => {
        this.setState({
          loading: false,
        });
      });
  }

  searchCallBill = (billNo) => {
    this.setState({ currentPage: 0, billno: billNo, allSalesOrders: [] }, () => {
      this.getList();
    });
  };

  processPagination(index) {
    this.setState(
      {
        currentPage: index,
      },
      () => {
        this.getList();
      } // console.log(items)
    );
  }

  handleClose() {
    this.setState({ show: false, currentViewItem: null });
  }

  handleShow(data) {
    this.setState({ show: true, currentViewItem: data });
  }

  calculateQty(items) {
    let totalQtyOfItems = 0;
    for (let i = 0; i < items.length; i++) {
      totalQtyOfItems += parseFloat(items[i].qty);
    }
    return totalQtyOfItems;
  }

  searchCallFromDate = (dt) => {
    this.setState({ currentPage: 0, orderFromDate: dt, allSalesOrders: [] }, () => {
      this.getList();
    });
  };
  searchCallToDate = (dt) => {
    this.setState({ currentPage: 0, orderToDate: dt, allSalesOrders: [] }, () => {
      this.getList();
    });
  };




  fetchMoreData = () => {
    this.setState({
      currentPage: this.state.currentPage + 1
    }, () => {
      this.getList();
    }
    );
  };


  searchByCashier = (val) => {
    this.setState({ currentPage: 0, cashier: val, allSalesOrders: [] }, () => {
      this.getList();
    });
  };

  searchBySalesman = (val) => {
    this.setState({ currentPage: 0, salesman: val, allSalesOrders: [] }, () => {
      this.getList();
    });
  };

  searchByTerminal = (val) => {
    this.setState({ currentPage: 0, terminal: val, allSalesOrders: [] }, () => {
      this.getList();
    });
  };

  getSalesManName = (id) => {
    let name = '';
    this.state.salesMans.forEach(item => {
      if (item._id == id) {
        name = item.firstname;
      }
    })
    return name;
  }

  render() {
    return (
      <div className="box">
        <div className="header">
          <div className="container" id="container">
            <div className="row-container">
              <input
                id="input-container"
                type="date"
                onChange={(e) => this.searchCallFromDate(e.target.value)}

                style={{
                  background: "#6670c9",
                  border: "none",
                  color: "#e5e6f3",
                  height: "40px",
                  borderRadius: "0.05rem",
                  padding: "0.25rem",
                  width: "100%",
                }}
              />
              <input
                id="input-container"
                type="date"
                onChange={(e) => this.searchCallToDate(e.target.value)}

                style={{
                  background: "#6670c9",
                  border: "none",
                  color: "#e5e6f3",
                  height: "40px",
                  borderRadius: "0.05rem",
                  padding: "0.25rem",
                  width: "100%",
                }}
              />
            </div>
            <div className="row-container">
              <select
                id="input-container"
                style={{
                  background: "#6670c9",
                  border: "none",
                  color: "#e5e6f3",
                  height: "40px",
                  borderRadius: "0.05rem",
                  padding: "0.25rem",
                  width: "100%",
                }}
                onChange={(e) => this.searchByCashier(e.target.value)}

              >
                <option value="">All Cashier</option>
                {this.state.cashiers.map(item => {
                  return <option key={item._id} value={item._id}>{item.firstname}({item.empcode})</option>
                })}
              </select>
              <select
                id="input-container"
                style={{
                  background: "#6670c9",
                  border: "none",
                  color: "#e5e6f3",
                  height: "40px",
                  borderRadius: "0.05rem",
                  padding: "0.25rem",
                  width: "100%",
                }}
                onChange={(e) => this.searchBySalesman(e.target.value)}

              >
                <option value="">All SalesMan</option>
                {this.state.salesMans.map(item => {
                  return <option key={item._id} value={item._id}>{item.firstname}({item.empcode})</option>
                })}
              </select>
            </div>
            <div className="row-container">
              <select
                id="input-container"
                style={{
                  background: "#6670c9",
                  border: "none",
                  color: "#e5e6f3",
                  height: "40px",
                  borderRadius: "0.05rem",
                  padding: "0.25rem",
                  width: "100%",
                }}
                onChange={(e) => this.searchByTerminal(e.target.value)}

              >

                <option value="">All Terminals</option>
                {this.state.terminals.map(item => {
                  return <option key={item._id} value={item._id}>{item.firstname}({item.empcode})</option>
                })}
              </select>
              <div className="inputWithIcon" id="input-container">
                <input
                  style={{
                    background: "none",
                    border: "none",
                    height: "40px",
                    borderRadius: "5rem",
                    padding: "0.25rem",
                    width: "100%",
                    outline: "none",
                    padding: "0.80rem",
                  }}
                  onChange={(e) => this.searchCallBill(e.target.value)}
                  type="text"
                  placeholder="Search.."
                />
                <span data-notify="icon" className="pe-7s-search" />
              </div>
            </div>
          </div>

        </div>
        <div className="table">
          <InfiniteScroll
            dataLength={this.state.allSalesOrders.length}
            hasMore={true}
            // loader={<h4>Loading...</h4>}
            next={this.fetchMoreData}
          >
            <Table responsive className="content-table">
              <thead>
                <tr>
                  <th>Sno</th>
                  <th>Ref</th>
                  <th>Date</th>
                  <th>Time</th>
                  <th>Items</th>
                  <th>Cost</th>
                  <th>Mode</th>
                  <th>Status</th>
                  <th></th>
                </tr>
              </thead>
              {this.state.allSalesOrders.map((result, index) => {
                return (
                  <tbody key={`sale-${index}`}>
                    <tr>
                      <td>{index + 1}</td>
                      <td>{result.billNo}</td>
                      <td>{moment(result.orderDate).format("DD/MM/YYYY")}</td>
                      <td>{result.orderBillTime}</td>
                      <td>{result.items.length}</td>
                      <td>₹{result.totalProductSellingPrice}</td>
                      <td>
                        {result.isActive == true
                          ? "Ordered"
                          : "Cancelled"}
                      </td>
                      <td>
                        {result.paymentType == 1
                          ? "Cash"
                          : result.paymentType == 2
                            ? "Card"
                            : "Upi / Gpay."}
                      </td>
                      <td>
                        <button
                          className="file-icon"
                          onClick={() => this.handleShow(result)}
                        >
                          <span data-notify="icon" className="pe-7s-file" />
                        </button>
                      </td>
                    </tr>
                  </tbody>
                );
              })}
            </Table>
          </InfiniteScroll>
          {/* {this.state.allSalesOrders.length > 0 &&
            this.state.totalPages > 0 && (
              <ReactPaginate
                previousLabel={"previous"}
                initialPage={this.state.currentPage}
                nextLabel={"next"}
                breakLabel={"..."}
                breakClassName={"break-me"}
                pageCount={this.state.totalPages}
                marginPagesDisplayed={2}
                pageRangeDisplayed={5}
                onPageChange={(index) => this.processPagination(index.selected)}
                containerClassName={"pagination"}
                subContainerClassName={"pages pagination"}
                activeClassName={"active"}
              />
            )} */}
        </div>
        {this.state.currentViewItem && (
          <Modal show={this.state.show} onHide={this.handleClose}>
            <Modal.Header closeButton>
              <Modal.Title>
                <center>
                  <br />
                  <small className="model-brand">BLACKFOREST CAKES SALES</small>
                  <br />
                  <small className="brand-address">Sales man - {this.getSalesManName(this.state.currentViewItem.waiter)}</small>
                  {/* <small className="brand-address">ETTAYAPURAM ROAD</small>
                  <br />
                  <small className="brand-address-sm">
                    THOOTHUKUDI
                    <br />
                    PH: 9597104066
                  </small>
                  <br /> */}
                </center>
              </Modal.Title>
            </Modal.Header>
            <Modal.Body ref={(el) => (this.componentRefPrint = el)} >
              <p style={{ textAlign: "center", color: "#9a9a9a" }}>
                Bill No: {this.state.currentViewItem.billNo}
              </p>
              <br />
              <div className="current-time">
                <Col>
                  <p>
                    {moment(this.state.currentViewItem.orderDate).format(
                      "DD/MM/YYYY"
                    )}
                  </p>
                </Col>
                <Col>
                  <p>{this.state.currentViewItem.orderBillTime}</p>
                </Col>
              </div>
              <br />

              <Table responsive size="sm" className="model-table">
                <thead>
                  <tr style={{ borderBottom: "2px dashed #9a9a9a" }}>
                    <th>S.No</th>
                    <th>Name</th>
                    <th>Rate</th>
                    <th>Qty</th>
                    <th style={{ float: "right" }}>Amount</th>
                  </tr>
                </thead>
                <tbody>
                  {this.state.currentViewItem.items.map((result, index) => {
                    return (
                      <tr key={`s-v-${index}`} style={{ color: "#9a9a9a" }}>
                        <td>1</td>
                        <td>{result.name}</td>
                        <td>{result.sellingPrice}</td>
                        <td>{result.qty}</td>
                        <td style={{ float: "right" }}>{result.totalCost}</td>
                      </tr>
                    );
                  })}

                  <tr
                    style={{
                      borderTop: "2px dashed #9a9a9a",
                    }}
                  >
                    <td style={{ color: "#9a9a9a" }} colSpan={4}>
                      Qty:{" "}
                      {this.calculateQty(this.state.currentViewItem.items)}
                    </td>
                    <td
                      style={{
                        borderBottom: "2px dashed #9a9a9a",
                        textAlign: "right",
                        color: "#9a9a9a",
                      }}
                    >
                      {this.state.currentViewItem.totalProductSellingPrice}
                    </td>
                  </tr>
                </tbody>
              </Table>

              <center>
                <p style={{ fontWeight: "bold", color: "#9a9a9a" }}>
                  Rs. {this.state.currentViewItem.totalProductSellingPrice}
                </p>
              </center>
            </Modal.Body>
            <Modal.Footer>
              <Button
                style={{ background: "#757373", color: "#ffffff" }}
                onClick={this.handleClose}
              >
                Close
              </Button>
              <ReactToPrint
                documentTitle={"Black-forest-sales"}
                trigger={() => {
                  return (
                    <button
                      id="printInvoices"
                      style={{
                        background: "#337ab7", border: "none",
                        color: "#ffffff"
                      }}
                    >
                      <i className="fa fa-print"></i> Print
                    </button>
                  );
                }}
                content={() => this.componentRefPrint}
              />
              {/* <Button
                  style={{ background: "#337ab7", color: "#ffffff" }}
                  bsStyle="primary"
                >
                  Print
                </Button> */}
            </Modal.Footer>
          </Modal>

        )}
      </div>
    );
  }
}
