
import React, { Component } from "react";
import { Grid, Row, Col } from "react-bootstrap";
import NotificationSystem from "react-notification-system";
import axios from 'axios';
import { style } from "../../variables/Variables.jsx";
import '../../assets/css/custom.css';
import { authHeader } from '../../configs/helpers';
import { ApiUrlHost, apiUrls } from '../../configs/configs';
import * as moment from 'moment';
import Card from "components/Card/Card.jsx";
import { Link } from "react-router-dom";

class ViewDetailOrder extends Component {
  constructor(props) {
    super(props);
    this.state = {
      status: null,
      details: null,
      orderId: this.props.match.params.id,
      balance: null,
      deliveryPersons: [],
      preparingUsers: [],
      preparingUser: null,
      deliveryUser: null,
      addonItems: [],
      lastOrderPageData: this.props.location.state
    }
  }

  componentDidMount() {
    this.getOrderDetails();
    this.getEmployesList();
  }

  getEmployesList = () => {
    axios({
      method: 'GET',
      url: apiUrls.EMPLOYEE_BY_CHEF_DELV,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      const cEmps = [];
      const dEmps = [];

      result.data.data.map((emp) => {
        if (emp.emptype == '2') {
          cEmps.push(emp);
        } else {
          dEmps.push(emp);
        }
      })
      this.setState({
        deliveryPersons: dEmps,
        preparingUsers: cEmps
      })
    }).catch(e => {
      this.setState({
        details: null
      });
    });
  }

  UNSAFE_componentWillReceiveProps(nextProps) {
    if (nextProps.match.params && nextProps.match.params.id) {
      this.setState({ orderId: nextProps.match.params.id }, () => {
        this.getOrderDetails();
      })
    }
  }

  getOrderDetails() {
    axios({
      method: 'GET',
      url: apiUrls.ORDERS.getOne + this.state.orderId,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200 && result.data.data) {
        this.setState({
          details: result.data.data[0],
          status: result.data.data[0].status ? result.data.data[0].status : '',
          preparingUser: result.data.data[0].prepared_by ? result.data.data[0].prepared_by : null,
          deliveryUser: result.data.data[0].delivery_man ? result.data.data[0].delivery_man : null
        });
        if (result.data.data[0].addonDetails && result.data.data[0].addonDetails.length > 0) {
          const addOns = [];
          result.data.data[0].addonDetails.forEach(addon => {
            addOns.push(addon.name)
          });
          this.setState({
            addonItems: addOns
          });
        }
      } else {
        this.setState({
          details: null
        });
      }
    }).catch(e => {
      this.setState({
        details: null
      });
    });
  }

  updateStatus = () => {
    if (this.state.status) {

      this.setState({ _notificationSystem: this.refs.notificationSystem, isFormSubmit: true });
      var _notificationSystem = this.refs.notificationSystem;

      var bodyFormData = { 'status': this.state.status };

      axios({
        method: 'POST',
        url: apiUrls.ORDERS.getOne + this.state.orderId,
        data: bodyFormData,
        headers: {
          'Content-Type': 'application/json',
          Authorization: authHeader()
        }
      }).then(result => {
        if (result.status === 200) {
          this.getOrderDetails();
          _notificationSystem.addNotification({
            title: <span data-notify="icon" className="pe-7s-check" />,
            message: (
              <div>
                Status updated.
              </div>
            ),
            level: 'success',
            position: "tr",
            autoDismiss: 15
          });

        }
      }).catch(e => {
        console.log(e)
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
              {(e.response) ? e.response.data.message : 'Something went wrong!'}
            </div>
          ),
          level: 'error',
          position: "tr",
          autoDismiss: 15
        });
      });
    }
  }

  updateBalance = () => {
    if (this.state.balance) {

      this.setState({ _notificationSystem: this.refs.notificationSystem, isFormSubmit: true });
      var _notificationSystem = this.refs.notificationSystem;

      var bodyFormData = { 'balance': this.state.balance };

      axios({
        method: 'POST',
        url: apiUrls.ORDERS.updateBalance + this.state.orderId,
        data: bodyFormData,
        headers: {
          'Content-Type': 'application/json',
          Authorization: authHeader()
        }
      }).then(result => {
        console.log(result)
        if (result.status === 200) {
          this.getOrderDetails();
          _notificationSystem.addNotification({
            title: <span data-notify="icon" className="pe-7s-check" />,
            message: (
              <div>
                Balance updated.
              </div>
            ),
            level: 'success',
            position: "tr",
            autoDismiss: 15
          });

        }
      }).catch(e => {
        console.log(e)
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
              {(e.response) ? e.response.data.message : 'Something went wrong!'}
            </div>
          ),
          level: 'error',
          position: "tr",
          autoDismiss: 15
        });
      });
    }
  }

  changeStatus = (event) => {
    if (event.target.value) {
      this.setState({ status: event.target.value })
    }
  }

  changePrepUsers = (event) => {
    if (event.target.value) {
      this.setState({ preparingUser: event.target.value })
    }
  }

  changeDeliveryUsers = (event) => {
    if (event.target.value) {
      this.setState({ deliveryUser: event.target.value })
    }
  }

  setBalance = (event) => {
    const { name, value } = event.target;
    this.setState({ [name]: value });
  }


  updatePreparingUser = () => {
    if (this.state.preparingUser) {

      this.setState({ _notificationSystem: this.refs.notificationSystem, isFormSubmit: true });
      var _notificationSystem = this.refs.notificationSystem;

      var bodyFormData = { 'user': this.state.preparingUser };

      axios({
        method: 'POST',
        url: apiUrls.ORDERS.updatePrepareUser + this.state.orderId,
        data: bodyFormData,
        headers: {
          'Content-Type': 'application/json',
          Authorization: authHeader()
        }
      }).then(result => {
        if (result.status === 200) {
          this.getOrderDetails();
          _notificationSystem.addNotification({
            title: <span data-notify="icon" className="pe-7s-check" />,
            message: (
              <div>
                Order details updated.
              </div>
            ),
            level: 'success',
            position: "tr",
            autoDismiss: 15
          });

        }
      }).catch(e => {
        console.log(e)
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
              {(e.response) ? e.response.data.message : 'Something went wrong!'}
            </div>
          ),
          level: 'error',
          position: "tr",
          autoDismiss: 15
        });
      });
    }
  }



  updateDeliveryUser = () => {
    if (this.state.deliveryUser) {

      this.setState({ _notificationSystem: this.refs.notificationSystem, isFormSubmit: true });
      var _notificationSystem = this.refs.notificationSystem;

      var bodyFormData = { 'user': this.state.deliveryUser };

      axios({
        method: 'POST',
        url: apiUrls.ORDERS.updateDeliveryUser + this.state.orderId,
        data: bodyFormData,
        headers: {
          'Content-Type': 'application/json',
          Authorization: authHeader()
        }
      }).then(result => {
        if (result.status === 200) {
          this.getOrderDetails();
          _notificationSystem.addNotification({
            title: <span data-notify="icon" className="pe-7s-check" />,
            message: (
              <div>
                Order details updated.
              </div>
            ),
            level: 'success',
            position: "tr",
            autoDismiss: 15
          });

        }
      }).catch(e => {
        console.log(e)
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
              {(e.response) ? e.response.data.message : 'Something went wrong!'}
            </div>
          ),
          level: 'error',
          position: "tr",
          autoDismiss: 15
        });
      });
    }
  }

  render() {

    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />
        <Grid fluid>

          <Row>
            <Col>
              {this.state.details && (<div className="order-view-bg">
              <Link className="mgr-5 btn btn-default  pull-right" to={
                    {
                      pathname: "/admin/orders",
                      state: this.state.lastOrderPageData
                    }
                  } type="button" >
                     Back to orders
                  </Link>
                <h2 className="text-capitalize">
                  {(this.state.details.productDetails) ? this.state.details.productDetails.name : (this.state.details.pastryDetails) ? this.state.details.pastryDetails.name : 'Photo Cake'}</h2>
                <p className="text-capitalize">
                  

                  {(this.state.details.productCategory[0]) ? this.state.details.productCategory[0].name : (this.state.details.pastryDetails) ? 'Pastries' : 'Photo cake order'}</p>
                <Row>

                  <Col md={4}>
                    <div className="card-bock">
                      <h3 className="text-head">Order Detail</h3>
                      <div className="content-block">
                        <p className="cotent-text">Form No: <span>{(this.state.details.form_no) ? this.state.details.form_no : '-'}</span></p>
                        <p className="cotent-text">Branch: <span>{(this.state.details.branchDetails) ? this.state.details.branchDetails.branch : '-'}</span></p>

                        <p className="cotent-text">Order Created: <span>{(this.state.details.created_at) ? moment(this.state.details.created_at).format('DD-MM-YYYY') : '-'}</span></p>
                        <p className="cotent-text">Delivery Date: <span>{(this.state.details.delivery_date) ? moment(this.state.details.delivery_date).format('DD-MM-YYYY') : '-'}</span></p>
                        <p className="cotent-text">Delivery Time: <span>{(this.state.details.delivery_time) ? moment(this.state.details.delivery_time).format('hh:mm a') : '-'}</span></p>
                        <p className="cotent-text">Birthday Date: <span>{(this.state.details.birthday_date) ? moment(this.state.details.birthday_date).format('DD-MM-YYYY') : '-'}</span></p>
                        <p className="cotent-text">Wordings: <span>{(this.state.details.wordings) ? this.state.details.wordings : '-'}</span></p>
                        <p className="cotent-text">Cake Model: <span>{(this.state.details.cake_model) ? this.state.details.cake_model : '-'}</span></p>
                        <p className="cotent-text">Cake type: <span>{(this.state.details.type) ? this.state.details.type : '-'}</span></p>
                        <p className="cotent-text">Flavour: <span>{(this.state.details.flavour) ? this.state.details.flavour : '-'}</span></p>
                        <p className="cotent-text">Alteration: <span>{(this.state.details.alteration) ? this.state.details.alteration : '-'}</span></p>
                        <p className="cotent-text">Special care: <span>{(this.state.details.special_care) ? this.state.details.special_care : '-'}</span></p>
                        <p className="cotent-text">Sales man: <span>{(this.state.details.employees[0]) ? this.state.details.employees[0].firstname : '-'}</span></p>
                        <p className="cotent-text">Status: <span>{(this.state.details.status == 1) ? 'Pending' : (this.state.details.status == 2) ? 'Cancelled' : (this.state.details.status == 3) ? 'Completed' : (this.state.details.status == 4) ? 'Preparing' : (this.state.details.status == 5) ? 'Ready' : '-'}</span></p>

                        {this.state.details.rating && (<p className="cotent-text">Rating: <span>{this.state.details.rating}/5</span></p>)}
                        {this.state.addonItems.length > 0 && (
                          <p className="cotent-text">Addons: <span>{this.state.addonItems.toString()}</span></p>
                        )}
                        {this.state.details.order_doc && <a href={ApiUrlHost + '/orders/' + this.state.details.order_doc} target="_blank">Download order Document</a>}
                      </div>
                    </div>
                  </Col>
                  <Col md={4}>
                    <div className="card-bock">
                      <h3 className="text-head">Customer Detail</h3>
                      <p className="cotent-text">Customer name: <span>{(this.state.details.customer_name) ? this.state.details.customer_name : '-'}</span></p>
                      <p className="cotent-text">Customer email: <span>{(this.state.details.customer_email) ? this.state.details.customer_email : '-'}</span></p>
                      <p className="cotent-text">Address: <span>{(this.state.details.address) ? this.state.details.address : '-'}</span></p>
                      <p className="cotent-text">Phone: <span>{(this.state.details.customer_phone) ? this.state.details.customer_phone : '-'}</span></p>
                    </div>
                    <div className="card-bock">
                      <h3 className="text-head">Update status</h3>
                      <select className="status-list" onChange={this.changeStatus} value={(this.state.status) ? this.state.status : ''}>
                        <option value="">Choose status</option>
                        <option value="1">Pending</option>
                        <option value="2">Cancelled</option>
                        <option value="4">Preparing</option>
                        <option value="5">Ready</option>
                        <option value="6">Picked</option>
                        <option value="7">Delivered</option>
                        <option value="8">Not Delivered</option>
                        <option value="3">Completed</option>
                      </select>
                      <button className="status-btn" onClick={this.updateStatus}>Update status</button>
                    </div>
                    <div className="card-bock">
                      <h3 className="text-head">Update Balance Amount</h3>
                      <input type="number" min="0" className="form-control mr-b10px" name="balance" placeholder="Fill amount paid" onChange={this.setBalance} noValidate />
                      <button className="status-btn" onClick={this.updateBalance}>Update</button>
                    </div>
                  </Col>
                  <Col md={4}>
                    <div className="card-bock">
                      <h3 className="text-head">Price Detail</h3>
                      {this.state.details && this.state.details.isPastryItem && (
                        <p className="cotent-text">Qty: <span>{(this.state.details.pastry) ? this.state.details.pastry.qty : '-'}</span></p>
                      )}
                      {this.state.details && !this.state.details.isPastryItem && (
                        <p className="cotent-text">Qty: <span>{(this.state.details.product) ? this.state.details.product.qty : '-'}</span></p>
                      )}
                      <p className="cotent-text">Price: <span>{(this.state.details.amount) ? this.state.details.amount : '-'}</span></p>
                      <p className="cotent-text">Advance: <span>{(this.state.details.advance) ? this.state.details.advance : '-'}</span></p>
                      <p className="cotent-text">Balance: <span>{(this.state.details.balance) ? this.state.details.balance : (this.state.details.amount - this.state.details.advance)}</span></p>

                    </div>

                  </Col>
                  <Col md={4}>
                    <div className="card-bock">
                      <h3 className="text-head">Preparing Person</h3>
                      <select className="status-list" onChange={this.changePrepUsers} value={(this.state.preparingUser) ? this.state.preparingUser : ''}>
                        <option value="">Choose</option>
                        {
                          this.state.preparingUsers.map((item, key) => {
                            return (
                              <option value={item._id} key={key}>{item.firstname}</option>
                            )
                          })
                        }
                      </select>
                      <button className="status-btn" onClick={this.updatePreparingUser}>Change</button>
                    </div>

                  </Col>
                  <Col md={4}>
                    <div className="card-bock">
                      <h3 className="text-head">Delivery Person</h3>
                      <select className="status-list" onChange={this.changeDeliveryUsers} value={(this.state.deliveryUser) ? this.state.deliveryUser : ''}>
                        <option value="">Choose</option>
                        {
                          this.state.deliveryPersons.map((item, key) => {
                            return (
                              <option value={item._id} key={key}>{item.firstname}</option>
                            )
                          })
                        }
                      </select>
                      <button className="status-btn" onClick={this.updateDeliveryUser}>Change</button>

                    </div>

                  </Col>
                </Row>

              </div>)}
            </Col>
            {
              (this.state.details && this.state.details.productDetails && this.state.details.productDetails.image.length > 0) && (
                <Col>
                  <Card
                    title="Product Images"
                    content={
                      <Row className="gallery-scroll">
                        {
                          this.state.details.productDetails.image.map((item, key) => {
                            return (

                              <Col xs={4} md={4} className="mb-btm" key={key}>
                                <div className="card card-user">
                                  <img src={ApiUrlHost + '/' + item} height="250" width="100%" alt="product" />
                                </div>
                              </Col>
                            )
                          })
                        }
                      </Row>
                    }
                  />
                </Col>
              )
            }

            {
              (this.state.details && this.state.details.pastryDetails && this.state.details.pastryDetails.image) && (
                <Col>
                  <Card
                    title="Product Images"
                    content={
                      <Row className="gallery-scroll">
                        <Col xs={4} md={4} className="mb-btm" >
                          <div className="card card-user">
                            <img src={ApiUrlHost + '/' + this.state.details.pastryDetails.image} height="250" width="100%" alt="product" />
                          </div>
                        </Col>
                      </Row>
                    }
                  />
                </Col>
              )
            }
          </Row>
        </Grid>
      </div>
    );
  }
}

export default ViewDetailOrder;
