import React, { Component } from "react";
import { FormGroup, FormControl, Row, Grid, Col, Table } from "react-bootstrap";
import axios from "axios";
import NotificationSystem from "react-notification-system";
import ReactPaginate from "react-paginate";
import * as moment from "moment";

import { style } from "../../variables/Variables.jsx";
import "../../assets/css/custom.css";
import { authHeader } from "../../configs/helpers";
import { apiUrls } from "../../configs/configs";

class ReturnOrders extends Component {
  constructor(props) {
    super(props);
    this.state = {
      searchbranch: "",
      returnDateFrom: "",
      returnDateTo: "",
      currentPage: 0,
      branches: [],
      searchLoad: false,
      searchRecords: [],
      totalSearchRec: 0,
      viewOne: false,
      oneItem: null,
      returnInputRef: [],
    };
  }

  componentWillMount() {
    this.getAllBranchEmployees();
    this.getAllRecords();
  }

  getAllBranchEmployees() {
    axios({
      method: "GET",
      url: apiUrls.BRANCH_EMPLOYEE_LIST,
      headers: {
        Authorization: authHeader(),
      },
    })
      .then((result) => {
        if (result.status === 200 && result.data.data) {
          this.setState({
            branches: result.data.data,
          });
        } else {
          this.setState({
            branches: [],
          });
        }
      })
      .catch((e) => {
        this.setState({
          branches: [],
        });
      });
  }
  getPaginateRec(index) {
    this.setState(
      {
        currentPage: index,
      },
      () => {
        this.getAllRecords();
      }
    );
  }

  getAllRecords() {
    this.setState({
      searchLoad: true,
    });

    var params = {
      page: this.state.currentPage,
    };

    if (this.state.searchbranch) {
      params.branch = this.state.searchbranch;
    }
    if (this.state.returnDateFrom) {
      params.returnDateFrom = this.state.returnDateFrom;
    }

    if (this.state.returnDateTo) {
      params.returnDateTo = this.state.returnDateTo;
    }

    axios({
      method: "GET",
      url: apiUrls.REPORTS.returnOrder,
      headers: {
        Authorization: authHeader(),
      },
      params: params,
    })
      .then((result) => {
        if (result.status === 200 && result.data.data && result.data.data[0]) {
          if (this.state.oneItem) {
            const _tempData = result.data.data[0].paginatedResults;
            _tempData.forEach((_n) => {
              if (_n._id == this.state.oneItem._id) {
                this.setState({
                  oneItem: _n,
                });
              }
            });
          }
          this.setState({
            searchRecords: result.data.data[0].paginatedResults,
            searchLoad: false,
            totalSearchRec: result.data.data[0].totalCount[0].count,
          });
        } else {
          this.setState({
            searchRecords: [],
            searchLoad: false,
          });
        }
      })
      .catch((e) => {
        this.setState({
          searchRecords: [],
          searchLoad: false,
        });
      });
  }

  setCreateData(e) {
    this.setState(
      {
        returnDateFrom: e.target.value,
      },
      () => {
        this.getAllRecords();
      }
    );
  }

  setCreateDataTo(e) {
    this.setState(
      {
        returnDateTo: e.target.value,
      },
      () => {
        this.getAllRecords();
      }
    );
  }

  getTotalItems(item) {
    let total = 0;
    item.pastry.forEach((element) => {
      element.qty.forEach((one) => {
        total = parseFloat(total) + parseFloat(one.items);
      });
    });
    return total;
  }

  viewOneItem(item) {
    this.setState({
      inputRef: [],
      viewOne: true,
      oneItem: item,
    });
  }

  getQtyStatus(item) {
    let className = "return-bill-complete";
    item.qty.forEach((one) => {
      if (one.confirmed === false) {
        className = "bill-incomplete";
      }
    });
    return className;
  }

  getQtyTotal(item) {
    let total = 0;
    item.qty.forEach((one) => {
      total = parseFloat(total) + parseFloat(one.items);
    });
    return total;
  }

  confirmReturn(returnId, pastryId, item, _qty) {
    var _notificationSystem = this.refs.notificationSystem;
    const sendData = {
      pastry: pastryId,
      qty: _qty.value,
    };

    axios({
      method: "POST",
      url: apiUrls.REPORTS.returnOrder + "/" + returnId,
      data: sendData,
      headers: {
        "Content-Type": "application/json",
        Authorization: authHeader(),
      },
    })
      .then((result) => {
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-check" />,
          message: <div>updated</div>,
          level: "success",
          position: "tr",
          autoDismiss: 15,
        });
        this.getAllRecords();
      })
      .catch((e) => {
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
              {e.response ? e.response.data.message : "Something went wrong!"}
            </div>
          ),
          level: "error",
          position: "tr",
          autoDismiss: 15,
        });
      });
  }

  render() {
    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />

        <Grid fluid>
          <Row>
            <Col md={2}>
              <FormGroup>
                <label>Choose Branch</label>

                <FormControl
                  type="text"
                  componentClass="select"
                  inputRef={(ref) => {
                    this._sbranch = ref;
                  }}
                  onChange={() =>
                    this.setState({ searchbranch: this._sbranch.value }, () => {
                      this.getAllRecords();
                    })
                  }
                >
                  <option value="">Branch</option>
                  {this.state.branches.map((store) => {
                    return (
                      <option value={store._id} key={store._id}>
                        {store.firstname}
                      </option>
                    );
                  })}
                </FormControl>
              </FormGroup>
            </Col>

            <Col md={2}>
              <FormGroup>
                <label>
                  Return Date From
                  {this.createDate && this.createDate.value && (
                    <span
                      style={{ color: "tomato", fontSize: 8 }}
                      onClick={() => {
                        this.createDate.value = "";
                        this.setState(
                          { returnDateFrom: this.createDate.value },
                          () => {
                            this.getAllRecords();
                          }
                        );
                      }}
                    >
                      {" "}
                      <i className="fa fa-times-circle fa-2x" />
                    </span>
                  )}
                </label>
                <FormControl
                  type="date"
                  inputRef={(ref) => {
                    this.createDate = ref;
                  }}
                  onChange={(e) => this.setCreateData(e)}
                ></FormControl>
              </FormGroup>
            </Col>
            <Col md={2}>
              <FormGroup>
                <label>
                  Return Date To
                  {this.createDateTo && this.createDateTo.value && (
                    <span
                      style={{ color: "tomato", fontSize: 8 }}
                      onClick={() => {
                        this.createDateTo.value = "";
                        this.setState(
                          { returnDateTo: this.createDateTo.value },
                          () => {
                            this.getAllRecords();
                          }
                        );
                      }}
                    >
                      {" "}
                      <i className="fa fa-times-circle fa-2x" />
                    </span>
                  )}
                </label>
                <FormControl
                  type="date"
                  inputRef={(ref) => {
                    this.createDateTo = ref;
                  }}
                  onChange={(e) => this.setCreateDataTo(e)}
                ></FormControl>
              </FormGroup>
            </Col>
          </Row>
          <Table
            responsive
            bordered
            hover
            ref={(el) => (this.componentRefPending = el)}
          >
            <thead>
              <tr>
                <th>S.NO</th>
                <th>Branch</th>
                <th>Return Date</th>
                <th>Total Return items</th>
                <th>View Items</th>
              </tr>
            </thead>
            <tbody>
              {this.state.searchLoad === true && (
                <tr>
                  <td colSpan={5}>Loading...</td>
                </tr>
              )}
              {this.state.searchRecords.length > 0 &&
                this.state.searchLoad === false &&
                this.state.searchRecords.map((returnItems, key) => {
                  return (
                    <tr key={(key + 1) * 123}>
                      <td>{key + 1}</td>
                      <td>
                        {returnItems.employees
                          ? returnItems.employees.firstname
                          : "-"}
                      </td>
                      <td>
                        {moment(returnItems.return_date).format("DD/MM/YYYY")}
                      </td>
                      <td>
                        {returnItems.pastry
                          ? this.getTotalItems(returnItems)
                          : 0}
                      </td>
                      <td style={{ textAlign: "center" }}>
                        <i
                          className="fa fa-eye"
                          onClick={() => this.viewOneItem(returnItems)}
                        ></i>
                      </td>
                    </tr>
                  );
                })}

              {this.state.searchRecords.length === 0 &&
                this.state.searchLoad === false && (
                  <tr>
                    <td colSpan={5}>No orders found</td>
                  </tr>
                )}
            </tbody>
          </Table>
          <div className="footer text-center">
            <ReactPaginate
              previousLabel={"previous"}
              nextLabel={"next"}
              breakLabel={"..."}
              breakClassName={"break-me"}
              pageCount={Math.ceil(this.state.totalSearchRec / 5)}
              marginPagesDisplayed={2}
              pageRangeDisplayed={5}
              onPageChange={(index) => this.getPaginateRec(index.selected)}
              containerClassName={"pagination"}
              subContainerClassName={"pages pagination"}
              activeClassName={"active"}
            />
          </div>
          {this.state.viewOne === true && (
            <div>
              <p>
                Return items from{" "}
                {this.state.oneItem && this.state.oneItem.employees
                  ? this.state.oneItem.employees.firstname
                  : "-"}{" "}
                branch on{" "}
                {this.state.oneItem && this.state.oneItem.return_date
                  ? moment(this.state.oneItem.return_date).format("DD/MM/YYYY")
                  : "-"}
              </p>
              <Table responsive bordered hover>
                <thead>
                  <tr>
                    <th>#</th>
                    <th>Products</th>
                    <th>Unit price</th>
                    <th>Return Qty</th>
                  </tr>
                </thead>
                <tbody>
                  {this.state.oneItem &&
                    this.state.oneItem.pastry.length > 0 &&
                    this.state.oneItem.pastry.map((item, key) => {
                      return (
                        <tr key={item._id}>
                          <td>{key + 1}</td>
                          <td>
                            {item.pastryDetails
                              ? item.pastryDetails[0].name
                              : "-"}
                          </td>
                          <td>
                            ₹{" "}
                            {item.pastryDetails
                              ? item.pastryDetails[0].price
                              : "-"}
                          </td>
                          <td className={this.getQtyStatus(item)}>
                            <div>
                              <input
                                type="number"
                                defaultValue={this.getQtyTotal(item)}
                                ref={(el) =>
                                  (this.state.returnInputRef[key] = el)
                                }
                              />
                              <button
                                onClick={() =>
                                  this.confirmReturn(
                                    this.state.oneItem._id,
                                    item.p_id,
                                    item.qty,
                                    this.state.returnInputRef[key]
                                  )
                                }
                              >
                                <i className="fa fa-check"></i> Update
                              </button>
                              {item.qty.length > 1 &&
                                item.qty.map((oneQ, key) => {
                                  if (key > 0) {
                                    return (
                                      <span
                                        style={{ color: "#fff" }}
                                        key={oneQ._id}
                                      >
                                        (<i className="fa fa-arrow-up"></i>{" "}
                                        {oneQ.items})
                                      </span>
                                    );
                                  }
                                })}
                            </div>
                          </td>
                        </tr>
                      );
                    })}
                </tbody>
              </Table>
            </div>
          )}
        </Grid>
      </div>
    );
  }
}

export default ReturnOrders;
