import React, { Component } from "react";
import { Grid, Row, Col, Table } from "react-bootstrap";
import { Link } from "react-router-dom";
import axios from "axios";
import NotificationSystem from "react-notification-system";

import { style } from "../../variables/Variables.jsx";
import Card from "components/Card/Card.jsx";
import Button from "components/CustomButton/CustomButton.jsx";
import "../../assets/css/custom.css";
import { authHeader } from "../../configs/helpers";
import { apiUrls } from "../../configs/configs";
import InfiniteScroll from "react-infinite-scroll-component";

const mgr2 = {
  marginRight: 2,
};

class StoreList extends Component {
  constructor(props) {
    super(props);
    this.state = {
      stores: [],
      currentPage: 0,
      loading: true,
      totalRec: 0,
      isLoadingContent: false
    };
    this.paginationCall = this.paginationCall.bind(this);
    this.prevRecords = this.prevRecords.bind(this);
    this.nextRecords = this.nextRecords.bind(this);
    this.searchCall = this.searchCall.bind(this);
  }

  componentWillMount() {
    this.getAllStore(null);
  }

  getAllStore(search) {
    var _notificationSystem;

    var params = {
      page: this.state.currentPage,
    };

    if (search) {
      params.branch = search;
    }
    this.setState({
      loading: true,
    })

    this.setState({ _notificationSystem: this.refs.notificationSystem }, () => {
      _notificationSystem = this.refs.notificationSystem;
    });

    axios({
      method: "GET",
      url: apiUrls.STORE.getAll,
      headers: {
        Authorization: authHeader(),
      },
      params: params,
    })
      .then((result) => {
        // console.log(result,'GetALL');
        if (result.status === 200 && result.data.data[0]) {
          var temp = this.state.stores;
          temp = temp.concat(result.data.data[0].paginatedResults);

          this.setState({
            isLoadingContent: false,
            stores: temp,
            totalRec: result.data.data[0].totalCount[0]
              ? result.data.data[0].totalCount[0].count
              : 0,
            loading: false,
          });
        } else {
          this.setState({
            stores: [],
            loading: false,
          });
        }
      })
      .catch((e) => {
        this.setState({
          stores: [],
          loading: false,
        });

        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
              {e.response ? e.response.data.message : "Something went wrong!"}
            </div>
          ),
          level: "error",
          position: "tr",
          autoDismiss: 15,
        });
      });
  }

  paginationCall(index) {
    this.setState(
      {
        currentPage: index,
      },
      () => {
        this.getAllStore(null);
      }
    );
  }

  prevRecords() {
    if (this.state.currentPage > 0) {
      var c = this.state.currentPage;
      this.setState(
        {
          currentPage: c - 1,
        },
        () => {
          this.getAllStore(null);
        }
      );
    }
  }

  nextRecords() {
    var c = this.state.currentPage;
    var totalPage = Math.ceil(this.state.totalRec / 5);
    if (c < totalPage - 1) {
      this.setState(
        {
          currentPage: c + 1,
        },
        () => {
          this.getAllStore(null);
        }
      );
    }
  }

  searchCall(val) {

    this.setState(
      {
        currentPage: 0,
        stores: []
      },
      () => {
        this.getAllStore(val);
      }
    );
  }

  deleteStoreById(storeId) {
    if (window.confirm("Are sure to delete this store!")) {
      var _notificationSystem;

      this.setState(
        { _notificationSystem: this.refs.notificationSystem },
        () => {
          _notificationSystem = this.refs.notificationSystem;
        }
      );

      axios({
        method: "DELETE",
        url: apiUrls.STORE.delete + storeId,
        headers: {
          Authorization: authHeader(),
        },
      })
        .then((result) => {
          if (result.status === 200) {
            // console.log(result, "del")
            // if (
            //   this.state.currentPage !== 0 &&
            //   this.state.stores.length === 1
            // ) {
            //   this.setState({
            //     currentPage: this.state.currentPage - 1,
            //   });
            // }
            // this.getAllStore(null);

            const temp = this.state.stores.filter(i => {
              return i._id != storeId
            });
            this.setState({
              stores: temp
            })

            _notificationSystem.addNotification({
              title: <span data-notify="icon" className="pe-7s-check" />,
              message: <div>Store deleted!.</div>,
              level: "success",
              position: "tr",
              autoDismiss: 15,
            });
          }
        })
        .catch((e) => {
          console.log(e)
          _notificationSystem.addNotification({
            title: <span data-notify="icon" className="pe-7s-close-circle" />,
            message: (
              <div>
                {e.response ? e.response.data.message : "Something went wrong!"}
              </div>
            ),
            level: "error",
            position: "tr",
            autoDismiss: 15,
          });
        });
    }
  }

  fetchMoreData = () => {
    this.setState({
      isLoadingContent: true,
      currentPage: this.state.currentPage + 1
    }, () => {
      this.getAllStore(null);
    }
    );
  };

  render() {
    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />
        <Grid fluid>
          <Row>
            <Col md={12}>
              <Card
                title="Stores"
                search={true}
                searchplaceholder="Search by branch"
                ctTableFullWidth
                ctTableResponsive
                pagination={this.state.stores.length > 0 ? true : false}
                processPagination={this.paginationCall}
                prev={this.prevRecords}
                next={this.nextRecords}
                searchCall={this.searchCall}
                currentPage={this.state.currentPage}
                totalPages={Math.ceil(this.state.totalRec / 5)}
                createLink="/admin/store/create"
                content={
                  <InfiniteScroll
                    dataLength={this.state.stores.length}
                    hasMore={true}
                    // loader={this.state.loading === true && <h4>Loading...</h4>}
                    next={this.fetchMoreData}
                  >
                    <Table striped hover>
                      <thead>
                        <tr>
                          <th>Id</th>
                          <th>Branch</th>
                          <th>Total Employees</th>
                          <th>Phone</th>
                          <th>Actions</th>
                        </tr>
                      </thead>
                      <tbody>
                        {this.state.loading == false &&
                          this.state.stores.length > 0 &&
                          this.state.stores.map((element, index) => {
                            return (
                              <tr key={index}>
                                <td>{index + 1}</td>
                                <td>{element.branch}</td>
                                <td>{element.empl}</td>
                                <td>{element.phone}</td>
                                <td>
                                  <Link
                                    className="mgr-5 btn btn-default"
                                    to={
                                      "/admin/store/" + element._id + "/update"
                                    }
                                    type="button"
                                  >
                                    Edit
                                  </Link>

                                  <Button
                                    bsStyle="danger"
                                    onClick={() =>
                                      this.deleteStoreById(element._id)
                                    }
                                    type="button"
                                    style={mgr2}
                                  >
                                    Delete
                                  </Button>
                                </td>
                              </tr>
                            );
                          })}

                        {this.state.loading == false &&
                          this.state.stores.length == 0 && (
                            <tr>
                              <td colSpan={5} className="text-center">
                                No Stores Records Found
                              </td>
                            </tr>
                          )}
                      </tbody>
                    </Table>
                  </InfiniteScroll>
                }
              />
            </Col>
          </Row>
        </Grid>
      </div>
    );
  }
}

export default StoreList;
