
import React, { Component } from "react";
import ChartistGraph from "react-chartist";
import { Grid, Row, Col, Table } from "react-bootstrap";
import axios from 'axios';
import * as moment from 'moment';

import { Card } from "components/Card/Card.jsx";
import { StatsCard } from "components/StatsCard/StatsCard.jsx";
import {
  optionsSales,
  responsiveSales
} from "variables/Variables.jsx";
import { authHeader, getOrderStatusText } from '../configs/helpers';
import { apiUrls } from '../configs/configs';

const dataSales = {
  labels: [
    "Jan",
    "Feb",
    "Mar",
    "Apr",
    "May",
    "Jun",
    "Jul",
    "Aug",
    "Sep",
    "Oct",
    "Nov",
    "Dec"
  ],
  series: [
    [287, 385, 490, 492, 554, 586, 698, 695],
  ]
};
class Dashboard extends Component {
  constructor(props) {
    super(props);
    this.state = {
      shops: 0,
      orders: 0,
      emps: 0,
      pendings: 0,
      dataOrder: null,
      upcomingItems: []
    };
  }
  createLegend(json) {
    var legend = [];
    for (var i = 0; i < json["names"].length; i++) {
      var type = "fa fa-circle text-" + json["types"][i];
      legend.push(<i className={type} key={i} />);
      legend.push(" ");
      legend.push(json["names"][i]);
    }
    return legend;
  }

  componentDidMount() {
    this.getShopCount();
    this.getEmployeeCount();
    this.getOrderCount();
    this.getPendingOrderCount();
    this.getChartData();
    this.getTodayDeliveryItems()
  }

  getTodayDeliveryItems = () => {
    axios({
      method: 'GET',
      url: apiUrls.DASHBOARD.todayDeliveryItem,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200 && result.data.data  && result.data.data.length > 0) {
        this.setState({
          upcomingItems: result.data.data
        });
      }
    }).catch(e => {
    
      
    });
  }

  getShopCount = () => {
    axios({
      method: 'GET',
      url: apiUrls.DASHBOARD.branches,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200 && result.data) {
        this.setState({
          shops: result.data.count
        });
      }
    }).catch(e => {
      this.setState({
        shops: 0
      });
    });
  }
  
  getEmployeeCount = () => {
    axios({
      method: 'GET',
      url: apiUrls.DASHBOARD.emp,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200 && result.data) {
        this.setState({
          emps: result.data.count
        });
      }
    }).catch(e => {
      this.setState({
        emps: 0
      });
    });
  }

  getOrderCount = () => {
    axios({
      method: 'GET',
      url: apiUrls.DASHBOARD.order,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200 && result.data) {
        this.setState({
          orders: result.data.count
        });
      }
    }).catch(e => {
      this.setState({
        orders: 0
      });
    });
  }

  getPendingOrderCount = () => {
    axios({
      method: 'GET',
      url: apiUrls.DASHBOARD.orderPending,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {

      if (result.status === 200 && result.data) {
        this.setState({
          pendings: result.data.count
        });
      }
    }).catch(e => {
      this.setState({
        pendings: 0
      });
    });
  }

  getChartData = () => {
    axios({
      method: 'GET',
      url: apiUrls.DASHBOARD.chart,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200 && result.data) {
        var labels = [];
        var chartData = [];
        var resData = result.data.data;
        resData.forEach(element => {
          var formattedMonth = moment(element._id.month, 'MM').format('MMM');
          labels.push(formattedMonth)
          chartData.push(element.count)
        });

        this.setState({
          dataOrder: {
            labels: labels,
            series: [
              chartData
            ]
          }
        });
      }
    }).catch(e => {
      console.log(e)
      this.setState({
        dataOrder: null
      });
    });
  }

  goToOrder(id){
    this.props.history.push("/admin/order/" + id);
  }

  render() {
    console.log(this.state.dataOrder, dataSales)
    return (
      <div className="content">
        <Grid fluid>
          <Row>
            <Col lg={3} sm={6}>
              <StatsCard
                bigIcon={<i className="pe-7s-culture text-warning" />}
                statsText="Shops"
                statsValue={this.state.shops}
              />
            </Col>
            <Col lg={3} sm={6}>
              <StatsCard
                bigIcon={<i className="pe-7s-id text-success" />}
                statsText="Employees"
                statsValue={this.state.emps}
              />
            </Col>
            <Col lg={3} sm={6}>
              <StatsCard
                bigIcon={<i className="pe-7s-cash text-danger" />}
                statsText="Orders"
                statsValue={this.state.orders}
              />
            </Col>
            <Col lg={3} sm={6}>
              <StatsCard
                bigIcon={<i className="pe-7s-hourglass text-info" />}
                statsText="Pending Orders"
                statsValue={this.state.pendings}
              />
            </Col>
          </Row>
          {this.state.upcomingItems.length > 0 && (<Row>
            <Col md={6}>
            <Card
                id="chartHours"
                title="Upcoming Orders"
                category="For the next days"
                content={
                  <div className="upcoming-orders-wrap">
                <div>
                  <Table striped hover>
                    <thead>
                      <tr>
                        <th>Order Id</th>
                        <th>Status</th>
                        <th>Delivery Date</th>
                        <th></th>
                      </tr>
                    </thead>
                    <tbody>
                      {this.state.upcomingItems.map((item) => {
                        return ( <tr key={Math.random()}>
                          <td>{item.form_no}</td>
                          <td>{getOrderStatusText(item.status)}</td>
                          <td>{moment(item.delivery_date).calendar()}</td>
                          <td><button className="btn-orders-v" onClick={() => this.goToOrder(item._id)}>View</button></td>
                        </tr>)
                      })}
                     
 
                    </tbody>
                  </Table>
                </div>
              </div>
                }

              />
              
            </Col>
          </Row>)}
          
          <Row>
            <Col md={12}>
              {this.state.dataOrder && (<Card
                id="chartHours"
                title="Orders"
                category="Monthly Performance"
                content={
                  <div className="ct-chart">
                    <ChartistGraph
                      data={this.state.dataOrder}
                      type="Line"
                      options={optionsSales}
                      responsiveOptions={responsiveSales}
                    />
                  </div>
                }

              />)}

            </Col>
          </Row>
          
        </Grid>
      </div>
    );
  }
}

export default Dashboard;
