
import React, { Component } from "react";
import { Grid, Row, Col } from "react-bootstrap";
import { Link } from "react-router-dom";
import NotificationSystem from "react-notification-system";
import axios from 'axios';
import ImageCompressor from 'image-compressor.js';

import { style } from "../../variables/Variables.jsx";
import { Card } from "components/Card/Card.jsx";
import Button from "components/CustomButton/CustomButton.jsx";
import '../../assets/css/custom.css';
import { validateForm, authHeader, fileMaxLimit } from '../../configs/helpers';
import { ApiUrlHost, apiUrls, EmployeeTypes } from '../../configs/configs';

class EmployeeUpdate extends Component {
  constructor(props) {
    super(props);
    this.state = {
      empId: this.props.match.params.id,
      isFormSubmit: false,
      stores: [],
      firstname: '',
      lastname: '',
      phone: '',
      address: '',
      email: '',
      branch: '',
      username: '',
      password: '',
      type: '',
      image: '',
      isOtpAccess: true,
      errors: {
        firstname: '',
        lastname: '',
        phone: '',
        email: '',
        address: '',
        branch: '',
        username: '',
        type: '',
        image: ''
      }
    }
  }

  componentWillMount() {
    this.getEmployeeData();

    // get all branch list
    axios({
      method: 'GET',
      url: apiUrls.STORE.allStore,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        this.setState({
          stores: result.data.data,
        }, () => {
          this.getEmployeeData()
        });
      } else {
        this.setState({
          stores: []
        });
      }
    }).catch(e => {
      this.setState({
        stores: []
      });
    });
  }


  getEmployeeData() {
    axios({
      method: 'GET',
      url: apiUrls.EMPLOYEE + '/' + this.state.empId,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        var storeData = result.data.data;
        this.setState({
          branch: (storeData.branch) ? storeData.branch : null,
          address: (storeData.address) ? storeData.address : '',
          existImg: storeData.image,
          firstname: (storeData.firstname) ? storeData.firstname : '',
          lastname: (storeData.lastname) ? storeData.lastname : '',
          phone: (storeData.phone) ? storeData.phone : '',
          email: (storeData.email) ? storeData.email : '',
          username: (storeData.username) ? storeData.username : '',
          type: storeData.emptype,
          empcode: storeData.empcode,
          isOtpAccess: (storeData.isOTPLogin) ? true : false
        })
      }
    }).catch(e => {
      console.log(e);
    });
  }

  handleChange = (event) => {
    event.preventDefault();
    const { name, value } = event.target;
    let errors = this.state.errors;

    switch (name) {
      case 'firstname':
        errors.firstname =
          value.length <= 0
            ? 'Firstname is required'
            : '';
        break;

      case 'lastname':
        errors.lastname =
          value.length <= 0
            ? 'Lastname is required'
            : '';
        break;
      case 'phone':
        errors.phone =
          value.length <= 0
            ? 'Lastname is required'
            : '';
        break;

      // case 'branch': 
      //   errors.branch = 
      //     value.length <= 0
      //       ? 'Branch name is required'
      //       : '';
      //   break;
      case 'type':
        errors.type =
          value.length <= 0
            ? 'Employee type is required'
            : '';
        break;
      case 'address':
        errors.address =
          value.length <= 0
            ? 'Address is required'
            : '';
        break;
      default:
        break;
    }

    this.setState({ errors, [name]: value });
  }

  handleSubmit = (event) => {
    this.setState({ _notificationSystem: this.refs.notificationSystem, isFormSubmit: true });
    var _notificationSystem = this.refs.notificationSystem;
    event.preventDefault();

    if (this.state.isOtpAccess && !this.state.phone) {
      _notificationSystem.addNotification({
        title: <span data-notify="icon" className="pe-7s-close-circle" />,
        message: (
          <div>
            Phone number required for OTP access
          </div>
        ),
        level: 'error',
        position: "tr",
        autoDismiss: 15
      });
    } else if (validateForm(this.state.errors)) {
      var bodyFormData = new FormData();
      bodyFormData.set('firstname', this.state.firstname);
      bodyFormData.set('lastname', this.state.lastname);
      bodyFormData.set('phone', this.state.phone);
      bodyFormData.set('address', this.state.address);
      // bodyFormData.set('empcode', this.state.empcode);

      if (this.state.branch)
        bodyFormData.set('branch', this.state.branch);

      bodyFormData.set('type', this.state.type);
      bodyFormData.append('image', this.state.image)
      bodyFormData.append('password', this.state.password)
      bodyFormData.set('isOTPLogin', this.state.isOtpAccess);

      axios({
        method: 'PUT',
        url: apiUrls.EMPLOYEE + '/' + this.state.empId,
        data: bodyFormData,
        headers: {
          'Content-Type': 'multipart/form-data',
          Authorization: authHeader()
        }
      }).then(result => {
        if (result.status === 200) {
          this.getEmployeeData();

          _notificationSystem.addNotification({
            title: <span data-notify="icon" className="pe-7s-check" />,
            message: (
              <div>
                Employee details updated.
              </div>
            ),
            level: 'success',
            position: "tr",
            autoDismiss: 15
          });

        }
      }).catch(e => {
        console.log(e)
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
          message: (
            <div>
              {(e.response) ? e.response.data.message : 'Something went wrong!'}
            </div>
          ),
          level: 'error',
          position: "tr",
          autoDismiss: 15
        });
      });
    }
  }

  fileChangedHandler = (event) => {
    let errors = this.state.errors;
    let curr = this;

    if (event.target.files[0]) {
      if (fileMaxLimit(event)) {
        errors.image = '';
        new ImageCompressor(event.target.files[0], {
          quality: 0.6,
          success(result) {
            var file = new File([result], result.name, { type: result.type });
            curr.setState({ image: file, errors });
          },
          error(e) {
            console.log(e.message);
          },
        });
      } else {
        errors.image = 'File size should be maximum 5MB';
        this.setState({ errors });
      }
    } else {
      errors.image = '';
      this.setState({ image: '', errors });
    }
  };

  handleCheck = () => {
    this.setState({ isOtpAccess: !this.state.isOtpAccess });
  };

  render() {
    const { errors, isFormSubmit } = this.state;
    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />
        <Grid fluid>
          <Row>
            <Col md={8}>
              <Card
                title="Update employee"
                content={
                  <form onSubmit={this.handleSubmit} noValidate>
                    <div className="form-group">
                      <label>Firstname</label>
                      <input type="text" className="form-control" name="firstname" value={this.state.firstname} placeholder="Enter firstname" onChange={this.handleChange} noValidate />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.firstname}</p>
                        )
                      }
                    </div>

                    <div className="form-group">
                      <label>Lastname</label>
                      <input type="text" className="form-control" name="lastname" value={this.state.lastname} placeholder="Enter lastname" onChange={this.handleChange} noValidate />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.lastname}</p>
                        )
                      }
                    </div>
                    <div className="form-group">
                      <label>Emp Code</label>
                      <input type="text" className="form-control" name="empcode" value={this.state.empcode} placeholder="Enter empcode" disabled noValidate />

                    </div>

                    <div className="form-group">
                      <label>Phone</label>
                      <input type="text" maxLength="10" className="form-control" value={this.state.phone} name="phone" placeholder="Enter phone" onChange={this.handleChange} noValidate />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.phone}</p>
                        )
                      }
                    </div>

                    <div className="form-group">
                      <label>Address</label>
                      <textarea className="form-control" name="address" value={this.state.address} placeholder="Address of the employee" onChange={this.handleChange}></textarea>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.address}</p>
                        )
                      }
                    </div>

                    <div className="form-group">
                      <label>Email</label>
                      <input type="text" disabled className="form-control" name="email" value={this.state.email} placeholder="Enter email" onChange={this.handleChange} noValidate />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.email}</p>
                        )
                      }
                    </div>

                    <div className="form-group">
                      <label>Branch</label>
                      <select name="branch" className="form-control" value={this.state.branch} onChange={this.handleChange}>
                        <option value="">Select Branch</option>

                        {this.state.stores.length > 0 && this.state.stores.map((type) => {
                          return (
                            <option value={type._id} key={type._id}>{type.branch}</option>
                          )
                        })}
                      </select>                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.branch}</p>
                        )
                      }
                    </div>

                    <div className="form-group">
                      <label>Username</label>
                      <input type="text" disabled className="form-control" value={this.state.username} name="username" placeholder="Enter username" onChange={this.handleChange} noValidate />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.username}</p>
                        )
                      }
                    </div>

                    <div className="form-group">
                      <label>Password</label>
                      <input type="password" className="form-control" value={this.state.password} name="password" placeholder="Enter password if you wish to change" onChange={this.handleChange} noValidate />
                    </div>

                    <div className="form-group">
                      <label>Employee Type</label>
                      <select name="type" className="form-control" value={this.state.type} onChange={this.handleChange}>
                        <option value="">Select Employee Type</option>
                        {EmployeeTypes.map((type) => {
                          return (
                            <option value={type.id} key={type.id} >{type.name}</option>
                          )
                        })}
                      </select>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.type}</p>
                        )
                      }
                    </div>


                    <div className="form-group checkbox-access">
                      <label>OTP Login Access</label>
                      <input type="checkbox" className="form-control" onChange={this.handleCheck} checked={this.state.isOtpAccess} />
                    </div>


                    <div className="form-group">
                      <label>Photo</label>
                      <input type="file" className="form-control" name="image" onChange={this.fileChangedHandler} />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.image}</p>
                        )
                      }
                    </div>


                    <Link className="mgr-5 btn btn-default" to="/admin/employees">Cancel</Link>

                    <Button bsStyle="info" type="submit">
                      Update
                    </Button>

                    <div className="clearfix" />
                  </form>
                }
              />
            </Col>
            {this.state.existImg && (
              <Col md={3}>
                <div className="card card-user">
                  <img src={ApiUrlHost + '/' + this.state.existImg} className="store-image" alt="employee" />
                </div>
              </Col>
            )}
          </Row>
        </Grid>
      </div>
    );
  }
}

export default EmployeeUpdate;
