import React, { Component } from "react";
import Modal from "react-modal";
import axios from "axios";
import { apiUrls } from "../../configs/configs";
import { authHeader } from "../../configs/helpers";
import "./stocks.css";

const customStyles = {
    content: {
        top: "50%",
        left: "50%",
        right: "auto",
        bottom: "auto",
        // marginRight: '-50%',
        transform: "translate(-50%, -50%)",
        height: "600px", // <-- This sets the height
        overlfow: "scroll", // <-- This tells the modal to scrol
        minWidth: "70%",
    },
};

class StockManageAssignBill extends Component {
    constructor(props) {
        super(props);
        this.state = {
            isAll: 1,
            openPopup: false,
            selectedCategory: '',
            selectedBranch: '',
            errMsg: '',
            selectedProducts: [],
            defaultStkValue: '',
            applyAllBranch: false
        };
    }

    UNSAFE_componentWillReceiveProps(_nprops) {
        if (_nprops.open === true) {
            this.setState({
                openPopup: true,
                selectedCategory: _nprops.category,
                selectedBranch: _nprops.branch,
            });
            this.getBranchesByCategory(_nprops.branch, _nprops.category)
        }
    }

    getBranchesByCategory(branch, category) {
        axios({
            method: "GET",
            url: `${apiUrls.STOCKS.getAllBranchProducts}?branch=${branch}&category=${category}`,
            headers: {
                Authorization: authHeader(),
            }
        })
            .then((result) => {
                let items = [];

                if (result.status === 200) {
                    if (result.data && result.data.data && result.data.data.length > 0) {
                        items = result.data.data;
                    }
                }
                this.getProductsDropdown(category, items);

            })
            .catch((e) => {
                this.setState({
                    selectedCategories: []
                });
            });
    }


    getProductsDropdown(category, selected) {
        axios({
            method: "POST",
            url: `${apiUrls.STORE.productDropDown}?category=${category}`,
            headers: {
                Authorization: authHeader(),
            }
        })
            .then((result) => {
                if (result.status === 200) {
                    const items = result.data.data;
                    items.forEach((i) => {
                        i.isSelected = false;
                        i.qty = '';
                        selected.forEach((s) => {
                            if (s.product == i._id) {
                                i.isSelected = s.isEnable;
                                i.isAddedAlready = true;
                                i.qty = s.qty;
                            }
                        })
                    });

                    this.setState({
                        selectedProducts: items
                    });
                }
            })
            .catch((e) => {
            });
    }

    closePopUp(isRefresh = false) {
        this.setState({
            openPopup: false,
            selectedCategory: '',
            selectedBranch: '',
            selectedProducts: [],
            defaultStkValue: '',
            isAll: 1,
            applyAllBranch: false
        });

        this.props.closePopup(isRefresh);
    }

    handleChange = (e, field) => {
        this.setState({
            [field]: Number(e.target.value),
        });
    };

    handleInput = () => {
        this.setState({
            applyAllBranch: !this.state.applyAllBranch,
        });
    };

    setError(errMsg) {
        this.setState({ errMsg })

        setTimeout(() => {
            this.setState({ errMsg: '' })
        }, 3000);
    }

    saveItems() {
        if (!this.state.selectedBranch) {
            this.setError("Choose your branch");
            return;
        }

        if (!this.state.selectedCategory) {
            this.setError("Choose your category");
            return;
        }
        const temp = [];

        this.state.selectedProducts.forEach(i => {
            if (this.state.isAll === 1) {
                i.isSelected = true;
            }
            temp.push(i);
        })

        const sendBody = {
            applyToAll: this.state.isAll,
            applyAllBranch: this.state.applyAllBranch,
            defaultStock: this.state.defaultStkValue,
            selectedCategory: this.state.selectedCategory,
            selectedBranch: this.state.selectedBranch,
            products: this.state.isAll == 2 ? this.state.selectedProducts.filter(i => { return (i.isSelected == true || i.isAddedAlready == true) }) : temp,
        };

        if (this.state.isAll == 2 && sendBody.products.length == 0) {
            this.setError("Choose atleast one item");
            return;
        }


        axios({
            method: "POST",
            data: sendBody,
            url: `${apiUrls.STOCKS.create}`,
            headers: {
                Authorization: authHeader(),
            }
        })
            .then((result) => {
                this.closePopUp(true);
            })
            .catch((e) => {
            });
    }

    handleQty(id, e) {
        const items = this.state.selectedProducts;
        items.forEach((i) => {
            if (i._id == id) {
                i.qty = e.target.value ? Number(e.target.value) : ''
            }
        });

        this.setState({
            selectedProducts: items
        })
    }

    handleCheck(id) {
        const items = this.state.selectedProducts;
        items.forEach((i) => {
            if (i._id == id) {
                i.isSelected = !i.isSelected
            }
        });

        this.setState({
            selectedProducts: items
        })
    }

    render() {
        return (
            <Modal
                isOpen={this.state.openPopup}
                ariaHideApp={false}
                style={customStyles}
                contentLabel="Stock Modal"
            >
                {this.state.errMsg && <p className="error-wrap">{this.state.errMsg}</p>}
                <div className="modal-header">
                    <p>Enable Product Category</p>
                    {!this.state.errMsg && <p className="close-modal" onClick={() => this.closePopUp()}>
                        <i className="fa fa-times"></i>
                    </p>}
                </div>
                <div className="modal-body">
                    <p>Do you want to enable all products</p>
                    <label>
                        <input type="radio" name="type" value={1} onChange={(e) => this.handleChange(e, 'isAll')}
                        />&nbsp;Yes&nbsp;&nbsp;
                        <input type="radio" name="type" value={2} onChange={(e) => this.handleChange(e, 'isAll')} />&nbsp;No
                    </label>
                    {this.state.isAll == 1 && (
                        <>
                            <p>Enter default stock of all product</p>
                            <input type="number" className="form-control" onChange={(e) => this.handleChange(e, 'defaultStkValue')} />
                        </>
                    )}
                    <p className="note">* Empty Qty considered as Unlimited</p>
                    <label>
                        <input type="checkbox" name="apply" onClick={() => this.handleInput()} />&nbsp;Apply to all branch&nbsp;&nbsp;
                    </label>
                    {this.state.isAll == 2 && (
                        <>
                            <p>Product List</p>
                            <div className="pro-list">
                                {this.state.selectedProducts.map((i, k) => {
                                    return (<label key={`pro-stk-by-cat${k}`}>
                                        <input type="checkbox" name="pro" onChange={() => this.handleCheck(i._id)} checked={i.isSelected} />
                                        <span>&nbsp;{i.name} &nbsp;</span>
                                        <input type="number" className="form-control" placeholder="Qty" value={i.qty} onChange={(e) => this.handleQty(i._id, e)} />
                                    </label>)
                                })}

                            </div>
                        </>
                    )}
                </div>
                <div className="modal-footer">
                    <button className="btn" onClick={() => this.saveItems()}>Save</button>
                </div>

            </Modal>
        );
    }
}

export default StockManageAssignBill;
