
import React, { Component } from "react";
import { Grid, Row, Col } from "react-bootstrap";
import {  Link } from "react-router-dom";
import NotificationSystem from "react-notification-system";
import axios from 'axios';

import { style } from "../../variables/Variables.jsx";
import { Card } from "components/Card/Card.jsx";
import Button from "components/CustomButton/CustomButton.jsx";
import '../../assets/css/custom.css';
import {validateForm, authHeader } from '../../configs/helpers';
import { apiUrls} from '../../configs/configs';


class ProductUpdate extends Component {
  constructor(props){
    super(props);
    this.state = {
      pId: this.props.match.params.id,
      isFormSubmit: false,
      name: '',
      category: '',
      album: '',
      description: '',
      directuse: '',
      footnote: '',
      ingredients: '',
      pricesData: [],
      albumCol: [],
      categoryCol: [],
      productUnits: [],
      errors: {
        name: '',
        category: '',
        album: '',
        description: '',
        directuse: '',
        footnote: '',
        ingredients: '',
      }
    }
  }

  componentWillMount(){
    this.getAlbumList();
    this.getCategoryList();
    this.getProductData();
    this.getProductUnitList();

  }


  getProductUnitList(){
    axios({
      method: 'GET',
      url: apiUrls.PRODUCTUNITS,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        this.setState({
          productUnits: result.data.data[0].paginatedResults,
        });
      }else{
        this.setState({
          productUnits : []
        });
      }
    }).catch(e => {
      this.setState({
        productUnits : []
      });
    });
  }


  getProductData(){
    axios({
      method: 'GET',
      url: apiUrls.PRODUCT.create + '/' + this.state.pId,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
       var pData = result.data.data;
       let priceData = [];
       if(pData.price && pData.price.length > 0){
        pData.price.map((p, key) => {
            priceData.push({
                id: (key + 1), price: p.price, qty: p.qty, offerPercent: p.offerPercent,sellingPrice: p.sellingPrice,
                costPrice: p.costPrice,unit: p.unit, type: p.type
            })
        })
       }
       this.setState({
        name: pData.name,
        category: pData.category._id,
        album: pData.album,
        description: pData.description,
        directuse: pData.directuse,
        footnote: pData.footnote,
        ingredients: (pData.ingredients) ? pData.ingredients : '',
        pricesData: priceData
       })
      }
    }).catch(e => {
      console.log(e);
    });
  }

  getAlbumList(){
    axios({
      method: 'GET',
      url: apiUrls.PRODUCT.getAllAlbum,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        this.setState({
          albumCol: result.data.data,
        });
      }else{
        this.setState({
          albumCol : []
        });
      }
    }).catch(e => {
      this.setState({
        albumCol : []
      });
    });
  }

  getCategoryList(){
    axios({
      method: 'GET',
      url: apiUrls.PRODUCT.getAllCategory,
      headers: {
        Authorization: authHeader()
      }
    }).then(result => {
      if (result.status === 200) {
        this.setState({
          categoryCol: result.data.data,
        });
      }else{
        this.setState({
          categoryCol : []
        });
      }
    }).catch(e => {
      this.setState({
        categoryCol : []
      });
    });
  }

  handleChange = (event) => {
    event.preventDefault();
    const { name, value } = event.target;
    let errors = this.state.errors;

    switch (name) {
      case 'name': 
        errors.name = 
          value.length <= 0
            ? 'Product name is required'
            : '';
        break;

      case 'category': 
        errors.category = 
          value.length <= 0
            ? 'Product category is required'
            : '';
        break;  

      case 'album': 
        errors.album = 
          value.length <= 0
            ? 'Product album is required'
            : '';
          break;  
      
      // case 'description': 
      // errors.description = 
      //   value.length <= 0
      //     ? 'Description is required'
      //     : '';
      //     break;  

      // case 'footnote': 
      //     errors.footnote = 
      //       value.length <= 0
      //         ? 'Footnote is required'
      //         : '';
      //       break;  
      
      // case 'ingredients': 
      //         errors.ingredients = 
      //           value.length <= 0
      //             ? 'Ingredients is required'
      //             : '';              
      //     break;  
      // case 'directuse': 
      //     errors.directuse = 
      //       value.length <= 0
      //         ? 'Direction to use is required'
      //         : '';              
      // break;  
      default:
        break;
    }

    this.setState({errors, [name]: value});
  }


  handleSubmit = (event) => {
    this.setState({ _notificationSystem: this.refs.notificationSystem, isFormSubmit: true });
    var _notificationSystem = this.refs.notificationSystem;
    var havePrice = true;

    event.preventDefault();

    if(this.state.pricesData.length > 0){
      this.state.pricesData.map((price) => {
        if(price.qty && price.price){

        }else{
          havePrice = false;
        }
      });
    } else{
        havePrice = false;
    }

    if(validateForm(this.state.errors) && havePrice) {
      var bodyFormData = {};
      bodyFormData.name = this.state.name;
      bodyFormData.category = this.state.category;
      bodyFormData.album = this.state.album;
      bodyFormData.price = this.state.pricesData;

      if(this.state.description){
        bodyFormData.description = this.state.description;
      }

      if(this.state.directuse){
        bodyFormData.directuse = this.state.directuse;
      }

      if(this.state.footnote){
        bodyFormData.footnote = this.state.footnote;
      }
      
      if(this.state.ingredients){
        bodyFormData.ingredients = this.state.ingredients;
      }
      
      axios({
        method: 'PUT',
        url: apiUrls.PRODUCT.create + '/' + this.state.pId,
        data: bodyFormData,
        headers: {
            'Content-Type': 'application/json',
            Authorization: authHeader()
        }
      }).then(result => {
        if (result.status === 200) {

        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-check" />,
            message: (
              <div>
                'Product updated.'
              </div>
            ),
            level: 'success',
            position: "tr",
            autoDismiss: 15
          });

        }
      }).catch(e => {
        console.log(e)
        _notificationSystem.addNotification({
          title: <span data-notify="icon" className="pe-7s-close-circle" />,
            message: (
              <div>
              {(e.response) ? e.response.data.message : 'Something went wrong!'}
              </div>
            ),
            level: 'error',
            position: "tr",
            autoDismiss: 15
          });
      });
    }
  }

  addPriceDetails() {
    let newPrice = {id: (this.state.pricesData.length + 1), price: '', qty: '', offerPercent: ''};
    this.setState({
      pricesData: [...this.state.pricesData, newPrice]
    })
  }

  removePriceDetails(id) {
    let oldData = this.state.pricesData;
    let clearedPrice = oldData.filter((price) => price.id != id);
    this.setState({
      pricesData: clearedPrice
    }) 
   }

   updatePriceDate(id, key, val) {
      let priceCol = this.state.pricesData;
      priceCol.map((price) => {
        if(price.id === id){
          price[key] = val
        }
      })
   }

  render() {
    const { errors, isFormSubmit } = this.state;
    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />
        <Grid fluid>
          <Row>
            <Col md={8}>
            <Card
                title="Update Product"
                content={
                  <form onSubmit={this.handleSubmit} noValidate>
                    
                    <div className="form-group">
                      <label>Name</label>
                      <input type="text" className="form-control" name="name" placeholder="Enter name" value={this.state.name} onChange={this.handleChange} noValidate />
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.name}</p>
                        )
                      }
                    </div>
                    <Col md={6}>
                    <div className="form-group">
                      <label>Category</label>
                      <select name="category" className="form-control" value={this.state.category} onChange={this.handleChange}>
                      <option value="">Select Category</option>
                      {this.state.categoryCol.length > 0 && (
                        this.state.categoryCol.map((e, key) => {
                          return (
                            <option value={e._id} key={key}>{e.name}</option>
                          )
                        })
                      )}
                      </select>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.category}</p>
                        )
                      }
                    </div>
                    </Col>
                    <Col md={6}>

                    <div className="form-group">
                      <label>Album</label>
                      <select name="album" className="form-control" value={this.state.album} onChange={this.handleChange}>
                      <option value="">Select Album</option>
                      {this.state.albumCol.length > 0 && (
                        this.state.albumCol.map((e, key) => {
                          return (
                            <option value={e._id} key={key}>{e.name}</option>
                          )
                        })
                      )}
                      </select>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.album}</p>
                        )
                      }
                    </div>
                    </Col>
                    
                    

                    <div className="form-group">
                      <label>Description</label>
                      <textarea className="form-control" name="description" value={this.state.description} placeholder="Description of product" onChange={this.handleChange}></textarea>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.description}</p>
                        )
                      }
                    </div>

                    <div className="form-group">
                      <label>Direction to use</label>
                      <textarea className="form-control" name="directuse" value={this.state.directuse} placeholder="Direction to use" onChange={this.handleChange}></textarea>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.directuse}</p>
                        )
                      }   
                    </div>
                    <div className="form-group">
                      <label>Footnote</label>
                      <textarea className="form-control" name="footnote" value={this.state.footnote} placeholder="Footnote of product" onChange={this.handleChange}></textarea>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.footnote}</p>
                        )
                      }   
                    </div>

                    <div className="form-group">
                      <label>Ingredients</label>
                      <input type="text" className="form-control" name="ingredients" value={this.state.ingredients} placeholder="Enter ingredients"  onChange={this.handleChange} noValidate />
                      <small className="text-danger">(Every ingredient should seperated by comma.)</small>
                      {
                        isFormSubmit && (
                          <p className="txt-error">{errors.ingredients}</p>
                        )
                      }   
                    </div>                    

                    <div className="form-group">
                      <Button bsStyle="link" onClick={()=>this.addPriceDetails()}>Add price details</Button>
                    </div>

                    {
                      this.state.pricesData.length > 0 && (
                        this.state.pricesData.map((e, k) => {
                          console.log(e)
                          return (
                            <Row className="bg-light-grey" key={k}>
                               <Col md={2}>
                                <div className="form-group">
                                  <label>Price</label>
                                  <input type="number" min={0} className="form-control" defaultValue={(e.price)}  onChange={(ele) => this.updatePriceDate(e.id, 'price', ele.target.value)} noValidate />
                                </div>
                              </Col>
                             
                              <Col md={2}>
                                <div className="form-group">
                                  <label>offer Percent</label>
                                  <input type="number" min={0} max={100}  className="form-control" defaultValue={e.offerPercent}  onChange={(ele) => this.updatePriceDate(e.id, 'offerPercent', ele.target.value)}  noValidate />
                                </div>
                              </Col>
                              <Col md={2}>
                                <div className="form-group">
                                  <label>quantity</label>
                                  <input type="number" min={0} className="form-control" defaultValue={e.qty}  onChange={(ele) => this.updatePriceDate(e.id, 'qty', ele.target.value)} noValidate />
                                </div>
                              </Col>
                              
                              <Col md={2}>
                                <div className="form-group">
                                  <label>Unit</label>
                                  <select name="unit" value={e.unit} className="form-control" onChange={(ele) => this.updatePriceDate(e.id, 'unit', ele.target.value)}>
                                    <option value="">Select</option>
                                    {this.state.productUnits.length > 0 && (
                                      this.state.productUnits.map((e, key) => {
                                        return (
                                          <option value={e._id} key={key}>{e.name}</option>
                                        )
                                      })
                                    )}
                                  </select>
                                </div>
                              </Col>

                              <Col md={2}>
                                <div className="form-group" >
                                  <label>Cake Type</label>
                                  <select name="type" className="form-control" value={e.type} onChange={(ele) => this.updatePriceDate(e.id, 'type', ele.target.value)}>
                                    <option value="">Select</option>
                                    <option value="1">Fresh Cream</option>
                                    <option value="2">Butter Cream</option>
                                  </select>
                                </div>
                              </Col>
                              <Col md={2}>
                                <Button bsStyle="link" className="mr-t25px" onClick={() => this.removePriceDetails(e.id)}>Remove</Button>
                              </Col>
                            </Row>
                          )
                        })
                      )
                    }


                    <Link className="mgr-5 btn btn-default" to="/admin/products">Cancel</Link>

                    <Button bsStyle="info"  type="submit">
                      Update
                    </Button>

                    <div className="clearfix" />
                  </form>
                }
              />
            </Col>
          </Row>
        </Grid>
      </div>
    );
  }
}

export default ProductUpdate;
