import React, { Component } from "react";
import { NavItem, Nav, NavDropdown, MenuItem } from "react-bootstrap";
import { Link, withRouter } from "react-router-dom";
import "../../assets/css/custom.css";
import Pusher from "pusher-js";
import { authHeader } from "../../configs/helpers";
import { apiUrls } from "../../configs/configs";
import axios from "axios";

Pusher.logToConsole = false;

class AdminNavbarLinks extends Component {
  constructor(props) {
    super(props);
    this.state = {
      messages: [],
    };
  }

  clearMessage = (key, id, detail) => {
    axios({
      method: "post",
      url: apiUrls.ORDERS.notification + id,
      headers: {
        Authorization: authHeader(),
      },
    })
      .then((result) => {
        if (result.status === 200) {
          this.getAllNotification();
        }
      })
      .catch((e) => {});
    if (detail.isPastry === true) {
      this.props.history.push("/admin/pastry-order/" + key);
    } else {
      this.props.history.push("/admin/order/" + key);
    }
  };

  componentDidMount() {
    var self = this;
    var pusher = new Pusher("af73232460d1d42cc257", {
      cluster: "ap2",
      forceTLS: true,
    });

    var channel = pusher.subscribe("my-channel");
    channel.bind("my-event", function (data) {
      self.getAllNotification();
    });
    this.getAllNotification();
  }

  getAllNotification = () => {
    axios({
      method: "get",
      url: apiUrls.ORDERS.notifications,
      headers: {
        Authorization: authHeader(),
      },
    })
      .then((result) => {
        if (result.status === 200) {
          const messages = result.data.data;
          this.setState({
            messages: messages,
          });
        }
      })
      .catch((e) => {
        this.setState({
          messages: [],
        });
      });
  };

  render() {
    const notification = (
      <div>
        <i className="fa fa-globe" />
        <b className="caret" />
        {this.state.messages.length > 0 && (
          <span className="notification">{this.state.messages.length}</span>
        )}
        <p className="hidden-lg hidden-md">Notification</p>
      </div>
    );

    return (
      <div>
        <Nav>
          <NavDropdown
            eventKey={2}
            title={notification}
            noCaret
            id="basic-nav-dropdown"
            // onToggle={(ex)=> ex === false ? this.clearMessage() : null}
          >
            {this.state.messages.length > 0 &&
              this.state.messages.map((m, k) => {
                return (
                  <MenuItem
                    onClick={() => this.clearMessage(m.order_id, m._id, m)}
                    eventKey={k}
                    key={k}
                  >
                    {m.title ? m.title : "you have new order"}
                  </MenuItem>
                );
              })}

            {this.state.messages.length === 0 && (
              <MenuItem>You have no notifications</MenuItem>
            )}
          </NavDropdown>
        </Nav>

        <Nav pullRight>
          <NavItem componentClass="div" eventKey={3} href="#">
            <Link className="logout-btn" to="/">
              Logout
            </Link>
          </NavItem>
        </Nav>
      </div>
    );
  }
}

export default withRouter(AdminNavbarLinks);
