import React, { Component } from "react";
import { Grid, Row, Col } from "react-bootstrap";
import { Link } from "react-router-dom";
import NotificationSystem from "react-notification-system";
import axios from "axios";
import ImageCompressor from "image-compressor.js";

import { style } from "../../variables/Variables.jsx";
import { Card } from "components/Card/Card.jsx";
import Button from "components/CustomButton/CustomButton.jsx";
import "../../assets/css/custom.css";
import { validateForm, authHeader, fileMaxLimit } from "../../configs/helpers";
import { apiUrls } from "../../configs/configs";

class StoreCreate extends Component {
  constructor(props) {
    super(props);
    this.state = {
      isFormSubmit: false,
      branch: null,
      address: null,
      phone: null,
      image: null,
      errors: {
        branch: "Branch name is required",
        address: "Address is required",
        phone: 'Phone number is required',
        image: "",
      },
    };
  }

  handleChange = (event) => {
    // console.log(event)
    event.preventDefault();
    const { name, value } = event.target;
    let errors = this.state.errors;

    switch (name) {
      case "branch":
        errors.branch = value.length <= 0 ? "Branch name is required" : "";
        break;
      case "address":
        errors.address = value.length <= 0 ? "Address is required" : "";
        break;
      case "phone":
        errors.phone = value.length <= 0 ? "Phone number is required" : "";
        break;
      default:
        break;
    }

    this.setState({ errors, [name]: value });
  };

  handleSubmit = (event) => {
    this.setState({
      _notificationSystem: this.refs.notificationSystem,
      isFormSubmit: true,
    });
    var _notificationSystem = this.refs.notificationSystem;
    event.preventDefault();

    if (validateForm(this.state.errors)) {
      var bodyFormData = new FormData();
      bodyFormData.set("branch", this.state.branch);
      bodyFormData.set("address", this.state.address);
      bodyFormData.set("phone", this.state.phone);
      bodyFormData.append("image", this.state.image);

      axios({
        method: "POST",
        url: apiUrls.STORE.create,
        data: bodyFormData,
        headers: {
          "Content-Type": "multipart/form-data",
          Authorization: authHeader(),
        },
      })
        .then((result) => {
          if (result.status === 201) {
            _notificationSystem.addNotification({
              title: <span data-notify="icon" className="pe-7s-check" />,
              message: <div>'Store created.'</div>,
              level: "success",
              position: "tr",
              autoDismiss: 15,
            });
          }
        })
        .catch((e) => {
          console.log(e);
          _notificationSystem.addNotification({
            title: <span data-notify="icon" className="pe-7s-close-circle" />,
            message: (
              <div>
                {e.response ? e.response.data.message : "Something went wrong!"}
              </div>
            ),
            level: "error",
            position: "tr",
            autoDismiss: 15,
          });
        });
    }
  };

  fileChangedHandler = (event) => {
    let errors = this.state.errors;
    let curr = this;

    if (event.target.files[0]) {
      if (fileMaxLimit(event)) {
        errors.image = "";
        new ImageCompressor(event.target.files[0], {
          quality: 0.6,
          success(result) {
            var file = new File([result], result.name, { type: result.type });
            curr.setState({ image: file, errors });
          },
          error(e) {
            console.log(e.message);
          },
        });
      } else {
        errors.image = "File size should be maximum 5MB";
        this.setState({ errors });
      }
    } else {
      errors.image = "";
      this.setState({ image: "", errors });
    }
  };

  render() {
    const { errors, isFormSubmit } = this.state;

    return (
      <div className="content">
        <NotificationSystem ref="notificationSystem" style={style} />
        <Grid fluid>
          <Row>
            <Col md={8}>
              <Card
                title="Create a new store"
                content={
                  <form onSubmit={this.handleSubmit} noValidate>
                    <div className="form-group">
                      <label>Branch</label>
                      <input
                        type="text"
                        className="form-control"
                        name="branch"
                        placeholder="Enter branch"
                        onChange={this.handleChange}
                        noValidate
                      />
                      {isFormSubmit && (
                        <p className="txt-error">{errors.branch}</p>
                      )}
                    </div>

                    <div className="form-group">
                      <label>Address</label>
                      <textarea
                        className="form-control"
                        name="address"
                        placeholder="Address of the branch"
                        onChange={this.handleChange}
                      ></textarea>
                      {isFormSubmit && (
                        <p className="txt-error">{errors.address}</p>
                      )}
                    </div>

                    <div className="form-group">
                      <label>Phone</label>
                      <input
                        type="number"
                        className="form-control"
                        name="phone"
                        placeholder="Enter phone number"
                        onChange={this.handleChange}
                        noValidate
                      />
                      {isFormSubmit && (
                        <p className="txt-error">{errors.phone}</p>
                      )}
                    </div>

                    <div className="form-group">
                      <label>Photo</label>
                      <input
                        type="file"
                        className="form-control"
                        name="image"
                        onChange={this.fileChangedHandler}
                      />
                      {isFormSubmit && (
                        <p className="txt-error">{errors.image}</p>
                      )}
                    </div>

                    <Link className="mgr-5 btn btn-default" to="/admin/stores">
                      Cancel
                    </Link>

                    <Button bsStyle="info" type="submit">
                      Create
                    </Button>

                    <div className="clearfix" />
                  </form>
                }
              />
            </Col>
          </Row>
        </Grid>
      </div>
    );
  }
}

export default StoreCreate;
